window.BUILTIN_BANK = [{"id":"P5-001","part":"5","difficulty":"400","category":"介系詞","prompt":"All expense reports must be submitted _____ Friday to receive reimbursement this month.","choices":["on","by","with","during"],"answer":1,"explanation":"by 表示「不晚於某時間」，適合截止期限。","translation":"所有費用報告必須在星期五以前提交，才能於本月收到報銷。","passage":"","audioText":"","tags":["deadline","preposition"]},{"id":"P5-002","part":"5","difficulty":"400","category":"固定搭配","prompt":"Ms. Huang is responsible _____ training newly hired employees.","choices":["of","with","for","to"],"answer":2,"explanation":"be responsible for 是「負責……」的固定搭配。","translation":"黃小姐負責訓練新進員工。","passage":"","audioText":"","tags":["be-adj-prep"]},{"id":"P5-003","part":"5","difficulty":"400","category":"固定搭配","prompt":"Many customers are interested _____ the company's new membership program.","choices":["at","in","for","on"],"answer":1,"explanation":"be interested in 是固定搭配。","translation":"許多顧客對公司的新會員方案有興趣。","passage":"","audioText":"","tags":["be-adj-prep"]},{"id":"P5-004","part":"5","difficulty":"600","category":"動名詞","prompt":"The new software is capable of _____ large amounts of data.","choices":["process","processed","processing","to process"],"answer":2,"explanation":"介系詞 of 後接名詞或 V-ing，因此選 processing。","translation":"這套新軟體能處理大量資料。","passage":"","audioText":"","tags":["gerund","be-adj-prep"]},{"id":"P5-005","part":"5","difficulty":"600","category":"時態","prompt":"Ms. Patel _____ director of operations since last January.","choices":["is","was","has been","will be"],"answer":2,"explanation":"since + 過去時間點常搭配現在完成式。","translation":"Patel 女士自去年一月起一直擔任營運主管。","passage":"","audioText":"","tags":["present-perfect"]},{"id":"P5-006","part":"5","difficulty":"400","category":"原因片語","prompt":"The outdoor event was canceled _____ heavy rain.","choices":["because","because of","although","despite"],"answer":1,"explanation":"because of 後接名詞片語；because 後面要接完整子句。","translation":"戶外活動因大雨而取消。","passage":"","audioText":"","tags":["because-of"]},{"id":"P5-007","part":"5","difficulty":"600","category":"連接詞","prompt":"The downtown branch will remain open, _____ the airport branch will close early.","choices":["whereas","unless","because","therefore"],"answer":0,"explanation":"whereas 用來對比兩個子句。","translation":"市中心分店會維持營業，相對地機場分店將提早關閉。","passage":"","audioText":"","tags":["contrast"]},{"id":"P5-008","part":"5","difficulty":"400","category":"副詞","prompt":"The consultant was _____ recommended by several former clients.","choices":["high","higher","highly","height"],"answer":2,"explanation":"修飾過去分詞 recommended 應使用副詞 highly。","translation":"這位顧問受到多名前客戶的高度推薦。","passage":"","audioText":"","tags":["adverb"]},{"id":"P5-009","part":"5","difficulty":"400","category":"動詞原形","prompt":"The company expects online sales to _____ significantly next quarter.","choices":["increase","increased","increasing","increases"],"answer":0,"explanation":"expect + O + to V；to 後接原形動詞。","translation":"公司預期下一季網路銷售將大幅增加。","passage":"","audioText":"","tags":["to-infinitive"]},{"id":"P5-010","part":"5","difficulty":"600","category":"關係代名詞","prompt":"Applicants _____ have at least three years of experience will be given priority.","choices":["who","whom","whose","which"],"answer":0,"explanation":"先行詞 applicants 是人，且關係代名詞在子句中作主詞，用 who。","translation":"具備至少三年經驗的申請者將優先錄取。","passage":"","audioText":"","tags":["relative-clause"]},{"id":"P5-011","part":"5","difficulty":"600","category":"條件句","prompt":"The shipment will arrive on time _____ the weather becomes severe.","choices":["if","unless","because","despite"],"answer":1,"explanation":"unless = if not，語意為「除非天氣惡化」。","translation":"除非天候轉差，貨物將準時抵達。","passage":"","audioText":"","tags":["unless"]},{"id":"P5-012","part":"5","difficulty":"600","category":"讓步","prompt":"_____ several delays, the construction project was completed within budget.","choices":["Although","Despite","Because","Unless"],"answer":1,"explanation":"Despite 後接名詞片語 several delays。","translation":"儘管多次延誤，工程仍在預算內完成。","passage":"","audioText":"","tags":["despite"]},{"id":"P5-013","part":"5","difficulty":"400","category":"詞性","prompt":"Final _____ from the finance department is required before the purchase can be made.","choices":["approve","approved","approval","approving"],"answer":2,"explanation":"形容詞 final 後需接名詞 approval。","translation":"完成採購前，需要財務部門的最終核准。","passage":"","audioText":"","tags":["word-form"]},{"id":"P5-014","part":"5","difficulty":"400","category":"副詞","prompt":"The new filing system allows employees to locate documents more _____.","choices":["efficient","efficiency","efficiently","efficiencies"],"answer":2,"explanation":"修飾動詞 locate 應用副詞 efficiently。","translation":"新的歸檔系統讓員工能更有效率地找到文件。","passage":"","audioText":"","tags":["word-form"]},{"id":"P5-015","part":"5","difficulty":"400","category":"固定句型","prompt":"The orientation session is scheduled _____ at 9:30 A.M.","choices":["begin","began","to begin","beginning"],"answer":2,"explanation":"be scheduled to V 表示「預定做……」。","translation":"新生訓練預定上午九點半開始。","passage":"","audioText":"","tags":["scheduled-to"]},{"id":"P5-016","part":"5","difficulty":"600","category":"相關連接詞","prompt":"Either the sales manager or her assistants _____ attending the trade show.","choices":["is","are","was","has"],"answer":1,"explanation":"either A or B 的動詞通常與較近主詞 assistants 一致，用 are。","translation":"銷售經理或她的助理們將出席商展。","passage":"","audioText":"","tags":["subject-verb"]},{"id":"P5-017","part":"5","difficulty":"600","category":"相關連接詞","prompt":"Neither the printer nor the copy machines _____ functioning properly.","choices":["is","are","has","was"],"answer":1,"explanation":"較近主詞 copy machines 為複數，因此用 are。","translation":"印表機與影印機目前都無法正常運作。","passage":"","audioText":"","tags":["subject-verb"]},{"id":"P5-018","part":"5","difficulty":"600","category":"平行結構","prompt":"The seminar will cover not only customer service but also _____ management.","choices":["time","timely","timing","timed"],"answer":0,"explanation":"not only A but also B 要平行；customer service 與 time management 都是名詞片語。","translation":"研討會不只涵蓋客服，也會談時間管理。","passage":"","audioText":"","tags":["parallelism"]},{"id":"P5-019","part":"5","difficulty":"400","category":"be動詞","prompt":"Additional information _____ available on the company's website.","choices":["are","were","is","have"],"answer":2,"explanation":"information 是不可數名詞，視為單數。","translation":"更多資訊可在公司網站取得。","passage":"","audioText":"","tags":["uncountable"]},{"id":"P5-020","part":"5","difficulty":"800","category":"過去完成式","prompt":"By the time the manager arrived, the interview panel _____ the final candidate.","choices":["already selected","has already selected","had already selected","will select"],"answer":2,"explanation":"較早發生的過去動作使用過去完成式。","translation":"經理抵達時，面試小組早已選定最後一位候選人。","passage":"","audioText":"","tags":["past-perfect"]},{"id":"P5-021","part":"5","difficulty":"400","category":"不定詞","prompt":"The company installed energy-efficient lighting _____ electricity costs.","choices":["reduce","reduced","reducing","to reduce"],"answer":3,"explanation":"不定詞可表示目的：「為了降低」。","translation":"公司安裝節能照明以降低電費。","passage":"","audioText":"","tags":["purpose"]},{"id":"P5-022","part":"5","difficulty":"800","category":"分詞構句","prompt":"_____ the quarterly report, Mr. Diaz sent it to the board members.","choices":["Completed","Completing","Having completed","To completing"],"answer":2,"explanation":"先完成報告再寄出，用 having + p.p. 表示先發生。","translation":"完成季度報告後，Diaz 先生將它寄給董事會成員。","passage":"","audioText":"","tags":["participle-clause"]},{"id":"P5-023","part":"5","difficulty":"600","category":"關係代名詞","prompt":"The updated policy, _____ was announced yesterday, takes effect immediately.","choices":["who","which","where","what"],"answer":1,"explanation":"先行詞 policy 是物，非限定關係子句用 which。","translation":"昨天公布的更新政策立即生效。","passage":"","audioText":"","tags":["relative-clause"]},{"id":"P5-024","part":"5","difficulty":"600","category":"whose","prompt":"Customers _____ orders were damaged will receive replacements at no charge.","choices":["who","whose","which","whom"],"answer":1,"explanation":"whose 表示所有關係：「顧客的訂單」。","translation":"訂單受損的顧客將免費收到替換品。","passage":"","audioText":"","tags":["whose"]},{"id":"P5-025","part":"5","difficulty":"800","category":"介系詞關係代名詞","prompt":"The annual meeting, at _____ shareholders vote on major proposals, will be held in June.","choices":["that","where","which","what"],"answer":2,"explanation":"at which = at the meeting，正式書面用法。","translation":"股東將對重大提案投票的年度會議將於六月舉行。","passage":"","audioText":"","tags":["prep-relative"]},{"id":"P5-026","part":"5","difficulty":"800","category":"假設語氣","prompt":"If I _____ in charge of the project, I would revise the schedule.","choices":["am","was","were","had been"],"answer":2,"explanation":"與現在事實相反的假設，be 動詞正式用 were。","translation":"如果我是專案負責人，我會修改時程。","passage":"","audioText":"","tags":["subjunctive"]},{"id":"P5-027","part":"5","difficulty":"800","category":"倒裝假設","prompt":"_____ we known about the road closure, we would have taken another route.","choices":["If","Were","Had","Should"],"answer":2,"explanation":"Had we known = If we had known。","translation":"如果早知道道路封閉，我們就會走另一條路。","passage":"","audioText":"","tags":["inversion"]},{"id":"P5-028","part":"5","difficulty":"600","category":"被動語態","prompt":"All applications must _____ electronically through the company portal.","choices":["submit","be submitted","submitted","be submitting"],"answer":1,"explanation":"申請文件是被提交，因此用 must be submitted。","translation":"所有申請必須透過公司入口網站以電子方式提交。","passage":"","audioText":"","tags":["passive"]},{"id":"P5-029","part":"5","difficulty":"600","category":"最高級","prompt":"Of the three candidates interviewed, Ms. Walker was the _____ qualified.","choices":["more","most","much","very"],"answer":1,"explanation":"三者以上比較使用最高級 most qualified。","translation":"三名受訪候選人中，Walker 女士最符合資格。","passage":"","audioText":"","tags":["superlative"]},{"id":"P5-030","part":"5","difficulty":"400","category":"數量詞","prompt":"The new procedure requires _____ steps than the previous one.","choices":["few","fewer","less","little"],"answer":1,"explanation":"steps 是可數複數，使用 fewer。","translation":"新流程比舊流程需要更少步驟。","passage":"","audioText":"","tags":["quantifier"]},{"id":"P5-031","part":"5","difficulty":"400","category":"數量詞","prompt":"There is very _____ time left before the registration deadline.","choices":["few","fewer","little","many"],"answer":2,"explanation":"time 是不可數名詞，使用 little。","translation":"距離報名截止時間只剩很少時間。","passage":"","audioText":"","tags":["quantifier"]},{"id":"P5-032","part":"5","difficulty":"400","category":"限定詞","prompt":"The first printer is out of order, so please use _____ one.","choices":["other","another","others","the others"],"answer":1,"explanation":"another + 單數名詞，表示「另一個」。","translation":"第一台印表機故障，請使用另一台。","passage":"","audioText":"","tags":["determiner"]},{"id":"P5-033","part":"5","difficulty":"600","category":"主動詞一致","prompt":"Each of the conference participants _____ a name badge.","choices":["receive","receives","receiving","have received"],"answer":1,"explanation":"each 作主詞時視為單數。","translation":"每位與會者都會收到名牌。","passage":"","audioText":"","tags":["each"]},{"id":"P5-034","part":"5","difficulty":"400","category":"數量詞","prompt":"The survey received _____ responses from overseas customers.","choices":["much","many","a little","less"],"answer":1,"explanation":"responses 為可數複數，用 many。","translation":"這項調查收到許多海外顧客的回覆。","passage":"","audioText":"","tags":["countable"]},{"id":"P5-035","part":"5","difficulty":"400","category":"時間介系詞","prompt":"No personal calls are permitted _____ working hours.","choices":["while","during","since","until"],"answer":1,"explanation":"during + 名詞片語 working hours。","translation":"工作時間內禁止私人通話。","passage":"","audioText":"","tags":["during"]},{"id":"P5-036","part":"5","difficulty":"400","category":"時間介系詞","prompt":"Please return the signed agreement _____ ten business days.","choices":["within","between","among","through"],"answer":0,"explanation":"within 表示「在某段期間之內」。","translation":"請在十個工作天內交回已簽署的協議。","passage":"","audioText":"","tags":["within"]},{"id":"P5-037","part":"5","difficulty":"400","category":"片語介系詞","prompt":"_____ the weather forecast, the storm should pass by noon.","choices":["According to","Because","In spite","Meanwhile"],"answer":0,"explanation":"according to 表示「根據……」。","translation":"根據天氣預報，暴風雨應在中午前通過。","passage":"","audioText":"","tags":["according-to"]},{"id":"P5-038","part":"5","difficulty":"600","category":"片語介系詞","prompt":"_____ the base salary, employees receive transportation allowances.","choices":["In addition to","Instead","Although","Except"],"answer":0,"explanation":"in addition to + 名詞，表示「除了……之外還有」。","translation":"除基本薪資外，員工也會收到交通津貼。","passage":"","audioText":"","tags":["addition"]},{"id":"P5-039","part":"5","difficulty":"600","category":"片語介系詞","prompt":"The company revised its policy _____ customer feedback.","choices":["in response to","in charge of","in favor of","in case of"],"answer":0,"explanation":"in response to 表示「回應、因應」。","translation":"公司因應顧客回饋修改政策。","passage":"","audioText":"","tags":["response"]},{"id":"P5-040","part":"5","difficulty":"400","category":"片語介系詞","prompt":"Ms. Reed accepted the award _____ the entire design team.","choices":["on behalf of","in spite of","with regard to","apart from"],"answer":0,"explanation":"on behalf of 表示「代表……」。","translation":"Reed 女士代表整個設計團隊領獎。","passage":"","audioText":"","tags":["behalf"]},{"id":"P5-041","part":"5","difficulty":"400","category":"固定搭配","prompt":"Full-time employees are eligible _____ health insurance benefits.","choices":["at","to","for","with"],"answer":2,"explanation":"be eligible for 是「有資格獲得……」。","translation":"全職員工有資格享有健康保險福利。","passage":"","audioText":"","tags":["be-adj-prep"]},{"id":"P5-042","part":"5","difficulty":"400","category":"固定搭配","prompt":"Are you familiar _____ the updated reservation system?","choices":["for","to","with","of"],"answer":2,"explanation":"人 be familiar with 物，表示熟悉某物。","translation":"你熟悉更新後的預約系統嗎？","passage":"","audioText":"","tags":["be-adj-prep"]},{"id":"P5-043","part":"5","difficulty":"400","category":"固定搭配","prompt":"This model is similar _____ the one released last year.","choices":["with","to","for","as"],"answer":1,"explanation":"be similar to 是固定搭配。","translation":"這款型號與去年推出的款式相似。","passage":"","audioText":"","tags":["be-adj-prep"]},{"id":"P5-044","part":"5","difficulty":"400","category":"固定搭配","prompt":"Management is aware _____ the technical issue and is working on a solution.","choices":["about","of","with","from"],"answer":1,"explanation":"be aware of 是固定搭配。","translation":"管理層已知悉技術問題，正著手解決。","passage":"","audioText":"","tags":["be-adj-prep"]},{"id":"P5-045","part":"5","difficulty":"400","category":"固定搭配","prompt":"Most clients were satisfied _____ the revised proposal.","choices":["with","at","to","of"],"answer":0,"explanation":"be satisfied with 是固定搭配。","translation":"大多數客戶對修訂後的提案感到滿意。","passage":"","audioText":"","tags":["be-adj-prep"]},{"id":"P5-046","part":"5","difficulty":"400","category":"固定搭配","prompt":"The delay was due _____ an unexpected equipment failure.","choices":["for","from","to","of"],"answer":2,"explanation":"be due to 表示「由於」。","translation":"延誤是由突發設備故障造成。","passage":"","audioText":"","tags":["due-to"]},{"id":"P5-047","part":"5","difficulty":"600","category":"片語介系詞","prompt":"The store will remain open _____ the renovation work.","choices":["regardless of","because","unless","whereas"],"answer":0,"explanation":"regardless of 表示「不論、不受……影響」。","translation":"商店不受裝修工程影響，仍會營業。","passage":"","audioText":"","tags":["regardless"]},{"id":"P5-048","part":"5","difficulty":"600","category":"片語介系詞","prompt":"All visitors must register at the front desk prior _____ entering the laboratory.","choices":["of","to","for","with"],"answer":1,"explanation":"prior to + N/V-ing，表示「在……之前」。","translation":"所有訪客進入實驗室前都必須在櫃台登記。","passage":"","audioText":"","tags":["prior-to"]},{"id":"P5-049","part":"5","difficulty":"600","category":"名詞子句","prompt":"The committee has not decided _____ the event will be held indoors or outdoors.","choices":["that","whether","what","which"],"answer":1,"explanation":"whether...or... 表示「是否……或……」。","translation":"委員會尚未決定活動要在室內或室外舉行。","passage":"","audioText":"","tags":["whether"]},{"id":"P5-050","part":"5","difficulty":"600","category":"目的子句","prompt":"The instructions were rewritten _____ new users could understand them more easily.","choices":["so that","because of","even though","in case of"],"answer":0,"explanation":"so that + 子句，表示目的。","translation":"說明已重新撰寫，以便新使用者更容易理解。","passage":"","audioText":"","tags":["so-that"]},{"id":"P5-051","part":"5","difficulty":"400","category":"商務字彙","prompt":"The purchasing manager will _____ with several suppliers before signing a contract.","choices":["negotiate","decorate","hesitate","celebrate"],"answer":0,"explanation":"negotiate with 表示「與……協商」。","translation":"採購經理會先與數家供應商協商，再簽訂合約。","passage":"","audioText":"","tags":["business-verb"]},{"id":"P5-052","part":"5","difficulty":"400","category":"商務字彙","prompt":"Because the speaker became ill, the seminar had to be _____.","choices":["postponed","promoted","produced","permitted"],"answer":0,"explanation":"postpone 表示延期；被延期用 be postponed。","translation":"由於講者生病，研討會必須延期。","passage":"","audioText":"","tags":["business-verb"]},{"id":"P5-053","part":"5","difficulty":"400","category":"商務字彙","prompt":"The warehouse manager checks the _____ every Friday to prevent shortages.","choices":["inventory","itinerary","interview","invoice"],"answer":0,"explanation":"inventory 指庫存。","translation":"倉庫經理每週五檢查庫存，以避免短缺。","passage":"","audioText":"","tags":["vocabulary"]},{"id":"P5-054","part":"5","difficulty":"400","category":"商務字彙","prompt":"Employees should attach receipts when requesting travel _____.","choices":["reimbursement","advertisement","achievement","employment"],"answer":0,"explanation":"travel reimbursement 指差旅費報銷。","translation":"員工申請差旅費報銷時應附上收據。","passage":"","audioText":"","tags":["vocabulary"]},{"id":"P5-055","part":"5","difficulty":"400","category":"商務字彙","prompt":"The laptop comes with a two-year _____ covering parts and labor.","choices":["warranty","salary","vacancy","facility"],"answer":0,"explanation":"warranty 指產品保固。","translation":"這台筆電附兩年零件與人工保固。","passage":"","audioText":"","tags":["vocabulary"]},{"id":"P5-056","part":"5","difficulty":"400","category":"商務字彙","prompt":"The customer called to ask when her _____ would arrive.","choices":["shipment","leadership","membership","internship"],"answer":0,"explanation":"shipment 指一批運送中的貨物。","translation":"顧客來電詢問她的貨物何時送達。","passage":"","audioText":"","tags":["vocabulary"]},{"id":"P5-057","part":"5","difficulty":"600","category":"商務字彙","prompt":"The technology firm plans to _____ a smaller competitor.","choices":["acquire","require","inquire","retire"],"answer":0,"explanation":"acquire a company 表示收購公司。","translation":"這家科技公司計畫收購一家規模較小的競爭者。","passage":"","audioText":"","tags":["vocabulary"]},{"id":"P5-058","part":"5","difficulty":"600","category":"商務字彙","prompt":"The company's annual _____ increased by twelve percent.","choices":["revenue","review","renewal","reservation"],"answer":0,"explanation":"revenue 指公司營收。","translation":"公司的年度營收增加了百分之十二。","passage":"","audioText":"","tags":["vocabulary"]},{"id":"P5-059","part":"5","difficulty":"400","category":"商務字彙","prompt":"Each _____ must submit a résumé and two references.","choices":["applicant","appliance","appointment","application"],"answer":0,"explanation":"applicant 指申請者、應徵者。","translation":"每位應徵者都必須提交履歷與兩封推薦資料。","passage":"","audioText":"","tags":["vocabulary"]},{"id":"P5-060","part":"5","difficulty":"400","category":"商務字彙","prompt":"Visitors can pick up a product _____ at the information desk.","choices":["brochure","branch","bargain","budget"],"answer":0,"explanation":"brochure 指介紹產品或服務的小冊子。","translation":"訪客可在服務台索取產品簡介。","passage":"","audioText":"","tags":["vocabulary"]},{"id":"P2-001","part":"2","difficulty":"400","category":"應答","prompt":"Choose the best response.","choices":["Ms. Park from the sales department.","It starts at ten.","In the main auditorium."],"answer":0,"explanation":"問 Who，應回答人。","translation":"誰將負責這場簡報？","passage":"","audioText":"Who will lead the presentation?","tags":["listening","response"],"audioTranslation":"誰將負責這場簡報？","answerTranslation":"銷售部的 Park 女士。"},{"id":"P2-002","part":"2","difficulty":"400","category":"應答","prompt":"Choose the best response.","choices":["On the top shelf beside the printer.","Yes, I signed them.","About twenty pages."],"answer":0,"explanation":"問 Where，應回答地點。","translation":"你把已簽署的合約放在哪裡？","passage":"","audioText":"Where did you put the signed contracts?","tags":["listening","response"],"audioTranslation":"你把已簽署的合約放在哪裡？","answerTranslation":"放在印表機旁邊的最上層架子上。"},{"id":"P2-003","part":"2","difficulty":"400","category":"應答","prompt":"Choose the best response.","choices":["Sometime before noon.","They repaired the elevator.","At the loading dock."],"answer":0,"explanation":"問 When，應回答時間。","translation":"維修人員預計何時抵達？","passage":"","audioText":"When is the maintenance crew expected to arrive?","tags":["listening","response"],"audioTranslation":"維修人員預計何時抵達？","answerTranslation":"中午以前的某個時間。"},{"id":"P2-004","part":"2","difficulty":"400","category":"應答","prompt":"Choose the best response.","choices":["The director's flight was delayed.","In Conference Room B.","For about an hour."],"answer":0,"explanation":"問 Why，應回答原因。","translation":"會議為什麼延期？","passage":"","audioText":"Why was the meeting postponed?","tags":["listening","response"],"audioTranslation":"會議為什麼延期？","answerTranslation":"主管的班機延誤了。"},{"id":"P2-005","part":"2","difficulty":"400","category":"應答","prompt":"Choose the best response.","choices":["Once every three months.","By a certified technician.","The inspection was thorough."],"answer":0,"explanation":"How often 問頻率。","translation":"這套設備多久檢查一次？","passage":"","audioText":"How often is the equipment inspected?","tags":["listening","response"],"audioTranslation":"這套設備多久檢查一次？","answerTranslation":"每三個月一次。"},{"id":"P2-006","part":"2","difficulty":"600","category":"應答","prompt":"Choose the best response.","choices":["Not at all. I'll send it right away.","Yes, the schedule changed.","It was revised yesterday."],"answer":0,"explanation":"Would you mind...? 接受請求可回答 Not at all。","translation":"可以麻煩你把修訂後的時程寄給我嗎？","passage":"","audioText":"Would you mind sending me the revised schedule?","tags":["listening","response"],"audioTranslation":"可以麻煩你把修訂後的時程寄給我嗎？","answerTranslation":"當然不介意，我會立刻寄出。"},{"id":"P2-007","part":"2","difficulty":"600","category":"應答","prompt":"Choose the best response.","choices":["No, the printer stopped working.","They were very expensive.","At the post office."],"answer":0,"explanation":"否定疑問句仍依事實回答；此處說明尚未寄出的原因。","translation":"那些發票還沒寄出去嗎？","passage":"","audioText":"Haven't the invoices been mailed yet?","tags":["listening","response"],"audioTranslation":"那些發票還沒寄出去嗎？","answerTranslation":"還沒，因為印表機故障了。"},{"id":"P2-008","part":"2","difficulty":"400","category":"應答","prompt":"Choose the best response.","choices":["Certainly. What time would you prefer?","The table is made of wood.","Six people attended yesterday."],"answer":0,"explanation":"對請求最自然的回應是答應並確認時間。","translation":"你可以幫今晚六個人訂位嗎？","passage":"","audioText":"Could you reserve a table for six tonight?","tags":["listening","response"],"audioTranslation":"你可以幫今晚六個人訂位嗎？","answerTranslation":"當然，你希望幾點？"},{"id":"P2-009","part":"2","difficulty":"600","category":"應答","prompt":"Choose the best response.","choices":["The expressway is usually faster.","Our flight leaves at seven.","I took a taxi yesterday."],"answer":0,"explanation":"Which route 問路線選擇。","translation":"我們去機場應該走哪條路？","passage":"","audioText":"Which route should we take to the airport?","tags":["listening","response"],"audioTranslation":"我們去機場應該走哪條路？","answerTranslation":"高速公路通常比較快。"},{"id":"P2-010","part":"2","difficulty":"400","category":"應答","prompt":"Choose the best response.","choices":["It closes at eight, so we still have time.","The sandwiches are on the counter.","I opened the window."],"answer":0,"explanation":"回答營業狀態並提供時間。","translation":"你知道員工餐廳是否還在營業嗎？","passage":"","audioText":"Do you know whether the cafeteria is still open?","tags":["listening","response"],"audioTranslation":"你知道員工餐廳是否還在營業嗎？","answerTranslation":"它八點關門，所以我們還有時間。"},{"id":"P2-011","part":"2","difficulty":"600","category":"應答","prompt":"Choose the best response.","choices":["That sounds like a good idea.","The proposal was approved.","Lunch is included."],"answer":0,"explanation":"Why don't we...? 是提議。","translation":"我們何不午餐後再審查提案？","passage":"","audioText":"Why don't we review the proposal after lunch?","tags":["listening","response"],"audioTranslation":"我們何不午餐後再審查提案？","answerTranslation":"聽起來是個好主意。"},{"id":"P2-012","part":"2","difficulty":"400","category":"應答","prompt":"Choose the best response.","choices":["Twenty should be enough.","The copier is downstairs.","I copied it this morning."],"answer":0,"explanation":"How many 問數量。","translation":"這份報告需要幾份副本？","passage":"","audioText":"How many copies of the report do we need?","tags":["listening","response"],"audioTranslation":"這份報告需要幾份副本？","answerTranslation":"二十份應該就夠了。"},{"id":"P2-013","part":"2","difficulty":"600","category":"應答","prompt":"Choose the best response.","choices":["No, he has another appointment.","The trade show was successful.","He works in marketing."],"answer":0,"explanation":"依事實回答否定疑問句。","translation":"Gomez 先生不是要參加商展嗎？","passage":"","audioText":"Isn't Mr. Gomez attending the trade show?","tags":["listening","response"],"audioTranslation":"Gomez 先生不是要參加商展嗎？","answerTranslation":"沒有，他另有約會。"},{"id":"P2-014","part":"2","difficulty":"400","category":"應答","prompt":"Choose the best response.","choices":["I think it belongs to Ms. Lee.","It's raining heavily.","The door is locked."],"answer":0,"explanation":"Whose 問所有人。","translation":"門邊這把雨傘是誰的？","passage":"","audioText":"Whose umbrella is this by the door?","tags":["listening","response"],"audioTranslation":"門邊這把雨傘是誰的？","answerTranslation":"我想它是 Lee 女士的。"},{"id":"P2-015","part":"2","difficulty":"600","category":"應答","prompt":"Choose the best response.","choices":["I'll check what is available.","The flight was canceled.","The aisle is narrow."],"answer":0,"explanation":"服務情境中應確認座位供應狀況。","translation":"可以給我一個走道座位嗎？","passage":"","audioText":"Could I get an aisle seat, please?","tags":["listening","response"],"audioTranslation":"可以給我一個走道座位嗎？","answerTranslation":"我來查看看目前有哪些座位。"},{"id":"P2-016","part":"2","difficulty":"600","category":"應答","prompt":"Choose the best response.","choices":["It's much easier to move around now.","The office moved last month.","On the third floor."],"answer":0,"explanation":"What do you think of...? 問意見。","translation":"你覺得新的辦公室配置如何？","passage":"","audioText":"What do you think of the new office layout?","tags":["listening","response"],"audioTranslation":"你覺得新的辦公室配置如何？","answerTranslation":"現在走動方便多了。"},{"id":"P2-017","part":"2","difficulty":"400","category":"應答","prompt":"Choose the best response.","choices":["It's printed on the last page.","The warranty lasts two years.","I bought it online."],"answer":0,"explanation":"問位置，回答在最後一頁。","translation":"我在哪裡可以找到保固資訊？","passage":"","audioText":"Where can I find the warranty information?","tags":["listening","response"],"audioTranslation":"我在哪裡可以找到保固資訊？","answerTranslation":"它印在最後一頁。"},{"id":"P2-018","part":"2","difficulty":"600","category":"應答","prompt":"Choose the best response.","choices":["Call now, in case the office closes early.","The supplier called yesterday.","Tomorrow is a holiday."],"answer":0,"explanation":"選擇問句應直接給建議。","translation":"我應該現在打給供應商，還是等到明天？","passage":"","audioText":"Should I call the supplier now or wait until tomorrow?","tags":["listening","response"],"audioTranslation":"我應該現在打給供應商，還是等到明天？","answerTranslation":"現在就打，以免辦公室提早關門。"},{"id":"P2-019","part":"2","difficulty":"400","category":"應答","prompt":"Choose the best response.","choices":["It went better than I expected.","At the corporate office.","The interviewer arrived early."],"answer":0,"explanation":"How was...? 問經驗或感受。","translation":"你今天早上的面試如何？","passage":"","audioText":"How was your interview this morning?","tags":["listening","response"],"audioTranslation":"你今天早上的面試如何？","answerTranslation":"比我預期的順利。"},{"id":"P2-020","part":"2","difficulty":"600","category":"應答","prompt":"Choose the best response.","choices":["Not yet, but they expect to finish today.","The budget meeting is upstairs.","Yes, it was very costly."],"answer":0,"explanation":"現在完成式 Yes/No 問句，回答目前狀態。","translation":"財務部已經核准預算了嗎？","passage":"","audioText":"Has the finance department approved the budget?","tags":["listening","response"],"audioTranslation":"財務部已經核准預算了嗎？","answerTranslation":"還沒，不過他們預計今天完成。"},{"id":"P3-011","part":"3","difficulty":"600","category":"會議安排","prompt":"What are the speakers mainly discussing?","choices":["A change to a presentation","A new product price","A hiring decision","A travel reimbursement"],"answer":0,"explanation":"對話重點是簡報時間改動。","translation":"","passage":"","audioText":"W: Hi, Daniel. The client moved tomorrow's product presentation from 10 A.M. to 2 P.M. M: Thanks for letting me know. I'll update the room reservation and notify the design team. W: Great. Please ask them to bring the revised brochures.","tags":["conversation"],"audioTranslation":"女：嗨，Daniel。客戶把明天的產品簡報從上午十點改到下午兩點。男：謝謝你通知我。我會更新會議室預約並通知設計團隊。女：很好。請他們帶上修訂後的宣傳冊。","groupId":"P3-G01"},{"id":"P3-012","part":"3","difficulty":"600","category":"會議安排","prompt":"What will the man do?","choices":["Reserve a room and contact a team","Print employee badges","Meet a supplier at the airport","Cancel a product launch"],"answer":0,"explanation":"男子說會更新會議室預約並通知設計團隊。","translation":"","passage":"","audioText":"W: Hi, Daniel. The client moved tomorrow's product presentation from 10 A.M. to 2 P.M. M: Thanks for letting me know. I'll update the room reservation and notify the design team. W: Great. Please ask them to bring the revised brochures.","tags":["conversation"],"audioTranslation":"女：嗨，Daniel。客戶把明天的產品簡報從上午十點改到下午兩點。男：謝謝你通知我。我會更新會議室預約並通知設計團隊。女：很好。請他們帶上修訂後的宣傳冊。","groupId":"P3-G01"},{"id":"P3-013","part":"3","difficulty":"600","category":"會議安排","prompt":"What does the woman ask the design team to bring?","choices":["Revised brochures","Expense reports","Laptop warranties","Customer surveys"],"answer":0,"explanation":"女子要求攜帶修訂後的小冊子。","translation":"","passage":"","audioText":"W: Hi, Daniel. The client moved tomorrow's product presentation from 10 A.M. to 2 P.M. M: Thanks for letting me know. I'll update the room reservation and notify the design team. W: Great. Please ask them to bring the revised brochures.","tags":["conversation"],"audioTranslation":"女：嗨，Daniel。客戶把明天的產品簡報從上午十點改到下午兩點。男：謝謝你通知我。我會更新會議室預約並通知設計團隊。女：很好。請他們帶上修訂後的宣傳冊。","groupId":"P3-G01"},{"id":"P3-021","part":"3","difficulty":"600","category":"飯店訂房","prompt":"Where most likely does the woman work?","choices":["At a hotel","At a factory","At a bank","At a museum"],"answer":0,"explanation":"提到 reservation、late arrival 與機場接送，最可能是飯店。","translation":"","passage":"","audioText":"M: Good afternoon. I have a reservation under the name Chen, but my flight arrives after midnight. W: That's fine. I'll mark your reservation for late arrival. Would you also like us to arrange airport transportation? M: Yes, please. That would be very helpful.","tags":["conversation"],"audioTranslation":"男：午安。我以 Chen 的名字訂了房，但我的班機會在午夜後才抵達。女：沒問題。我會把你的預約註記為晚到。你也需要我們安排機場接送嗎？男：好的，麻煩了。那會非常有幫助。","groupId":"P3-G02"},{"id":"P3-022","part":"3","difficulty":"600","category":"飯店訂房","prompt":"What concern does the man mention?","choices":["He will arrive very late","His room is too small","His payment was rejected","His luggage is missing"],"answer":0,"explanation":"男子擔心午夜後才抵達。","translation":"","passage":"","audioText":"M: Good afternoon. I have a reservation under the name Chen, but my flight arrives after midnight. W: That's fine. I'll mark your reservation for late arrival. Would you also like us to arrange airport transportation? M: Yes, please. That would be very helpful.","tags":["conversation"],"audioTranslation":"男：午安。我以 Chen 的名字訂了房，但我的班機會在午夜後才抵達。女：沒問題。我會把你的預約註記為晚到。你也需要我們安排機場接送嗎？男：好的，麻煩了。那會非常有幫助。","groupId":"P3-G02"},{"id":"P3-023","part":"3","difficulty":"600","category":"飯店訂房","prompt":"What service does the man request?","choices":["Airport transportation","Laundry repair","Conference catering","Package delivery"],"answer":0,"explanation":"男子接受安排機場交通。","translation":"","passage":"","audioText":"M: Good afternoon. I have a reservation under the name Chen, but my flight arrives after midnight. W: That's fine. I'll mark your reservation for late arrival. Would you also like us to arrange airport transportation? M: Yes, please. That would be very helpful.","tags":["conversation"],"audioTranslation":"男：午安。我以 Chen 的名字訂了房，但我的班機會在午夜後才抵達。女：沒問題。我會把你的預約註記為晚到。你也需要我們安排機場接送嗎？男：好的，麻煩了。那會非常有幫助。","groupId":"P3-G02"},{"id":"P3-031","part":"3","difficulty":"600","category":"物流延誤","prompt":"Why will the delivery be late?","choices":["Because of severe weather","Because payment is missing","Because the order was canceled","Because the warehouse is full"],"answer":0,"explanation":"女子明確說 because of a storm。","translation":"","passage":"","audioText":"W: We received a message from our shipping company. The office chairs won't arrive until Friday because of a storm. M: That's a problem. The new employees start on Thursday. W: We can move some chairs from the training room temporarily.","tags":["conversation"],"audioTranslation":"女：我們收到貨運公司的訊息。因為暴風雨，辦公椅要到星期五才會抵達。男：這是個問題。新員工星期四就要開始上班。女：我們可以暫時從訓練室搬一些椅子過來。","groupId":"P3-G03"},{"id":"P3-032","part":"3","difficulty":"600","category":"物流延誤","prompt":"What will happen on Thursday?","choices":["New employees will begin work","The chairs will be repaired","A storm will reach the city","The training room will close"],"answer":0,"explanation":"男子說新員工星期四開始上班。","translation":"","passage":"","audioText":"W: We received a message from our shipping company. The office chairs won't arrive until Friday because of a storm. M: That's a problem. The new employees start on Thursday. W: We can move some chairs from the training room temporarily.","tags":["conversation"],"audioTranslation":"女：我們收到貨運公司的訊息。因為暴風雨，辦公椅要到星期五才會抵達。男：這是個問題。新員工星期四就要開始上班。女：我們可以暫時從訓練室搬一些椅子過來。","groupId":"P3-G03"},{"id":"P3-033","part":"3","difficulty":"600","category":"物流延誤","prompt":"What does the woman suggest?","choices":["Using chairs from another room","Buying desks online","Postponing employee training","Calling every supplier"],"answer":0,"explanation":"女子建議暫時搬用訓練室的椅子。","translation":"","passage":"","audioText":"W: We received a message from our shipping company. The office chairs won't arrive until Friday because of a storm. M: That's a problem. The new employees start on Thursday. W: We can move some chairs from the training room temporarily.","tags":["conversation"],"audioTranslation":"女：我們收到貨運公司的訊息。因為暴風雨，辦公椅要到星期五才會抵達。男：這是個問題。新員工星期四就要開始上班。女：我們可以暫時從訓練室搬一些椅子過來。","groupId":"P3-G03"},{"id":"P3-041","part":"3","difficulty":"800","category":"求職面試","prompt":"What is the purpose of the conversation?","choices":["To conduct a job interview","To negotiate a sales contract","To revise a travel itinerary","To inspect a branch office"],"answer":0,"explanation":"談論履歷、經驗和下一階段面試。","translation":"","passage":"","audioText":"M: Ms. Owens, your résumé shows extensive experience in international sales. Could you tell me about your work in Singapore? W: Certainly. I managed a team of twelve and helped increase regional revenue by eighteen percent. M: Impressive. The next step is a video interview with our vice president.","tags":["conversation"],"audioTranslation":"男：Owens 女士，你的履歷顯示你有豐富的國際銷售經驗。可以談談你在新加坡的工作嗎？女：當然。我管理一個十二人的團隊，並協助區域營收提高百分之十八。男：很出色。下一步是和我們副總裁進行視訊面試。","groupId":"P3-G04"},{"id":"P3-042","part":"3","difficulty":"800","category":"求職面試","prompt":"What did the woman accomplish in Singapore?","choices":["She increased regional revenue","She opened twelve stores","She designed a new product","She reduced travel costs"],"answer":0,"explanation":"女子說提高區域營收 18%。","translation":"","passage":"","audioText":"M: Ms. Owens, your résumé shows extensive experience in international sales. Could you tell me about your work in Singapore? W: Certainly. I managed a team of twelve and helped increase regional revenue by eighteen percent. M: Impressive. The next step is a video interview with our vice president.","tags":["conversation"],"audioTranslation":"男：Owens 女士，你的履歷顯示你有豐富的國際銷售經驗。可以談談你在新加坡的工作嗎？女：當然。我管理一個十二人的團隊，並協助區域營收提高百分之十八。男：很出色。下一步是和我們副總裁進行視訊面試。","groupId":"P3-G04"},{"id":"P3-043","part":"3","difficulty":"800","category":"求職面試","prompt":"What will the woman most likely do next?","choices":["Have another interview","Submit an expense report","Attend a trade show","Train new employees"],"answer":0,"explanation":"下一步是與副總裁視訊面試。","translation":"","passage":"","audioText":"M: Ms. Owens, your résumé shows extensive experience in international sales. Could you tell me about your work in Singapore? W: Certainly. I managed a team of twelve and helped increase regional revenue by eighteen percent. M: Impressive. The next step is a video interview with our vice president.","tags":["conversation"],"audioTranslation":"男：Owens 女士，你的履歷顯示你有豐富的國際銷售經驗。可以談談你在新加坡的工作嗎？女：當然。我管理一個十二人的團隊，並協助區域營收提高百分之十八。男：很出色。下一步是和我們副總裁進行視訊面試。","groupId":"P3-G04"},{"id":"P3-051","part":"3","difficulty":"600","category":"設備維修","prompt":"What problem is mentioned?","choices":["A machine is leaking","A lounge is overcrowded","A repair bill is missing","A sign was printed incorrectly"],"answer":0,"explanation":"咖啡機漏水。","translation":"","passage":"","audioText":"W: The coffee machine in the employee lounge is leaking again. M: I'll call the repair company, but they may not come until tomorrow. W: In that case, let's put up a sign and move the smaller machine from the second floor.","tags":["conversation"],"audioTranslation":"女：員工休息室的咖啡機又漏水了。男：我會打給維修公司，不過他們可能要明天才會來。女：既然如此，我們貼一張告示，並把二樓那台較小的機器搬過來吧。","groupId":"P3-G05"},{"id":"P3-052","part":"3","difficulty":"600","category":"設備維修","prompt":"What will the man probably do?","choices":["Contact a repair company","Order more coffee","Clean the second floor","Replace an employee"],"answer":0,"explanation":"男子說會打電話給維修公司。","translation":"","passage":"","audioText":"W: The coffee machine in the employee lounge is leaking again. M: I'll call the repair company, but they may not come until tomorrow. W: In that case, let's put up a sign and move the smaller machine from the second floor.","tags":["conversation"],"audioTranslation":"女：員工休息室的咖啡機又漏水了。男：我會打給維修公司，不過他們可能要明天才會來。女：既然如此，我們貼一張告示，並把二樓那台較小的機器搬過來吧。","groupId":"P3-G05"},{"id":"P3-053","part":"3","difficulty":"600","category":"設備維修","prompt":"What does the woman propose?","choices":["Moving another machine","Closing the building","Canceling tomorrow's meeting","Buying a refrigerator"],"answer":0,"explanation":"女子建議搬二樓的小型機器。","translation":"","passage":"","audioText":"W: The coffee machine in the employee lounge is leaking again. M: I'll call the repair company, but they may not come until tomorrow. W: In that case, let's put up a sign and move the smaller machine from the second floor.","tags":["conversation"],"audioTranslation":"女：員工休息室的咖啡機又漏水了。男：我會打給維修公司，不過他們可能要明天才會來。女：既然如此，我們貼一張告示，並把二樓那台較小的機器搬過來吧。","groupId":"P3-G05"},{"id":"P3-061","part":"3","difficulty":"800","category":"行銷活動","prompt":"What are the speakers concerned about?","choices":["A low purchase rate","A delayed advertisement","A lack of website visitors","A shortage of products"],"answer":0,"explanation":"訪客多但完成購買的人少。","translation":"","passage":"","audioText":"M: The online advertisement attracted more visitors than expected, but few of them completed a purchase. W: Perhaps the checkout process is too complicated. We should ask the Web team to review it. M: Agreed. I'll also compare our prices with those of our competitors.","tags":["conversation"],"audioTranslation":"男：網路廣告吸引的訪客比預期多，但很少有人完成購買。女：也許結帳流程太複雜。我們應該請網站團隊檢查。男：同意。我也會把我們的價格和競爭者比較。","groupId":"P3-G06"},{"id":"P3-062","part":"3","difficulty":"800","category":"行銷活動","prompt":"What does the woman suggest?","choices":["Reviewing the checkout process","Hiring more salespeople","Closing the online store","Changing the company logo"],"answer":0,"explanation":"女子建議請網站團隊檢查結帳流程。","translation":"","passage":"","audioText":"M: The online advertisement attracted more visitors than expected, but few of them completed a purchase. W: Perhaps the checkout process is too complicated. We should ask the Web team to review it. M: Agreed. I'll also compare our prices with those of our competitors.","tags":["conversation"],"audioTranslation":"男：網路廣告吸引的訪客比預期多，但很少有人完成購買。女：也許結帳流程太複雜。我們應該請網站團隊檢查。男：同意。我也會把我們的價格和競爭者比較。","groupId":"P3-G06"},{"id":"P3-063","part":"3","difficulty":"800","category":"行銷活動","prompt":"What will the man compare?","choices":["Product prices","Employee schedules","Shipping routes","Advertising images"],"answer":0,"explanation":"男子會比較競爭者價格。","translation":"","passage":"","audioText":"M: The online advertisement attracted more visitors than expected, but few of them completed a purchase. W: Perhaps the checkout process is too complicated. We should ask the Web team to review it. M: Agreed. I'll also compare our prices with those of our competitors.","tags":["conversation"],"audioTranslation":"男：網路廣告吸引的訪客比預期多，但很少有人完成購買。女：也許結帳流程太複雜。我們應該請網站團隊檢查。男：同意。我也會把我們的價格和競爭者比較。","groupId":"P3-G06"},{"id":"P4-011","part":"4","difficulty":"600","category":"交通公告","prompt":"What is the purpose of the announcement?","choices":["To report a train delay","To advertise a new station","To explain a ticket price increase","To recruit maintenance workers"],"answer":0,"explanation":"公告說明列車延誤。","translation":"","passage":"","audioText":"Attention passengers. The 8:15 train to Riverside will depart twenty minutes late because maintenance crews are inspecting the tracks. Passengers may use their current tickets on the 8:30 express train at no additional charge.","tags":["talk"],"audioTranslation":"各位乘客請注意。由於維修人員正在檢查軌道，上午八點十五分前往 Riverside 的列車將延誤二十分鐘。乘客可持原車票免費搭乘八點三十分的快車。","groupId":"P4-G01"},{"id":"P4-012","part":"4","difficulty":"600","category":"交通公告","prompt":"Why is the train delayed?","choices":["The tracks are being inspected","The driver is absent","A ticket machine is broken","Heavy rain flooded the station"],"answer":0,"explanation":"維修人員正在檢查軌道。","translation":"","passage":"","audioText":"Attention passengers. The 8:15 train to Riverside will depart twenty minutes late because maintenance crews are inspecting the tracks. Passengers may use their current tickets on the 8:30 express train at no additional charge.","tags":["talk"],"audioTranslation":"各位乘客請注意。由於維修人員正在檢查軌道，上午八點十五分前往 Riverside 的列車將延誤二十分鐘。乘客可持原車票免費搭乘八點三十分的快車。","groupId":"P4-G01"},{"id":"P4-013","part":"4","difficulty":"600","category":"交通公告","prompt":"What may passengers do?","choices":["Take an express train without paying extra","Request a hotel room","Exchange tickets next week","Board at a different city"],"answer":0,"explanation":"原票可免費搭乘 8:30 快車。","translation":"","passage":"","audioText":"Attention passengers. The 8:15 train to Riverside will depart twenty minutes late because maintenance crews are inspecting the tracks. Passengers may use their current tickets on the 8:30 express train at no additional charge.","tags":["talk"],"audioTranslation":"各位乘客請注意。由於維修人員正在檢查軌道，上午八點十五分前往 Riverside 的列車將延誤二十分鐘。乘客可持原車票免費搭乘八點三十分的快車。","groupId":"P4-G01"},{"id":"P4-021","part":"4","difficulty":"600","category":"語音留言","prompt":"Why is the speaker calling?","choices":["To discuss an order","To schedule an interview","To announce a store opening","To collect a late payment"],"answer":0,"explanation":"來電討論訂單 5842。","translation":"","passage":"","audioText":"Hello, this is Karen from Apex Office Supplies. I'm calling about order 5842. The blue folders are temporarily out of stock, so we can send green ones today or ship the blue folders next Monday. Please call me before 4 P.M. to let me know which option you prefer.","tags":["talk"],"audioTranslation":"您好，我是 Apex 辦公用品公司的 Karen。我來電是關於訂單 5842。藍色資料夾暫時缺貨，因此我們可以今天寄出綠色款，或在下週一寄出藍色款。請在下午四點前回電，告訴我您偏好哪個方案。","groupId":"P4-G02"},{"id":"P4-022","part":"4","difficulty":"600","category":"語音留言","prompt":"What item is unavailable?","choices":["Blue folders","Green chairs","Printer paper","Desk lamps"],"answer":0,"explanation":"藍色資料夾缺貨。","translation":"","passage":"","audioText":"Hello, this is Karen from Apex Office Supplies. I'm calling about order 5842. The blue folders are temporarily out of stock, so we can send green ones today or ship the blue folders next Monday. Please call me before 4 P.M. to let me know which option you prefer.","tags":["talk"],"audioTranslation":"您好，我是 Apex 辦公用品公司的 Karen。我來電是關於訂單 5842。藍色資料夾暫時缺貨，因此我們可以今天寄出綠色款，或在下週一寄出藍色款。請在下午四點前回電，告訴我您偏好哪個方案。","groupId":"P4-G02"},{"id":"P4-023","part":"4","difficulty":"600","category":"語音留言","prompt":"What does the speaker request?","choices":["A decision before 4 P.M.","A new purchase order","A delivery address","A product brochure"],"answer":0,"explanation":"要求四點前回覆選項。","translation":"","passage":"","audioText":"Hello, this is Karen from Apex Office Supplies. I'm calling about order 5842. The blue folders are temporarily out of stock, so we can send green ones today or ship the blue folders next Monday. Please call me before 4 P.M. to let me know which option you prefer.","tags":["talk"],"audioTranslation":"您好，我是 Apex 辦公用品公司的 Karen。我來電是關於訂單 5842。藍色資料夾暫時缺貨，因此我們可以今天寄出綠色款，或在下週一寄出藍色款。請在下午四點前回電，告訴我您偏好哪個方案。","groupId":"P4-G02"},{"id":"P4-031","part":"4","difficulty":"600","category":"場館公告","prompt":"Where is the announcement being made?","choices":["At a museum","At a restaurant","At a factory","At an airport"],"answer":0,"explanation":"內容提及 exhibit、guided tours、galleries。","translation":"","passage":"","audioText":"Welcome to the City Design Museum. The photography exhibit on the second floor opens at 10:30. Guided tours begin every hour in the main lobby. Please note that food and beverages are not permitted inside the galleries.","tags":["talk"],"audioTranslation":"歡迎來到市立設計博物館。二樓的攝影展於十點三十分開放。導覽每小時於主大廳出發。請注意，展廳內禁止攜帶食物與飲料。","groupId":"P4-G03"},{"id":"P4-032","part":"4","difficulty":"600","category":"場館公告","prompt":"When does the photography exhibit open?","choices":["At 10:30","At 9:00","At noon","At 1:30"],"answer":0,"explanation":"公告明確說 10:30。","translation":"","passage":"","audioText":"Welcome to the City Design Museum. The photography exhibit on the second floor opens at 10:30. Guided tours begin every hour in the main lobby. Please note that food and beverages are not permitted inside the galleries.","tags":["talk"],"audioTranslation":"歡迎來到市立設計博物館。二樓的攝影展於十點三十分開放。導覽每小時於主大廳出發。請注意，展廳內禁止攜帶食物與飲料。","groupId":"P4-G03"},{"id":"P4-033","part":"4","difficulty":"600","category":"場館公告","prompt":"What is prohibited in the galleries?","choices":["Food and drinks","Photography","Guided tours","Children"],"answer":0,"explanation":"展廳禁止飲食。","translation":"","passage":"","audioText":"Welcome to the City Design Museum. The photography exhibit on the second floor opens at 10:30. Guided tours begin every hour in the main lobby. Please note that food and beverages are not permitted inside the galleries.","tags":["talk"],"audioTranslation":"歡迎來到市立設計博物館。二樓的攝影展於十點三十分開放。導覽每小時於主大廳出發。請注意，展廳內禁止攜帶食物與飲料。","groupId":"P4-G03"},{"id":"P4-041","part":"4","difficulty":"800","category":"公司安全","prompt":"What will be closed?","choices":["A stairwell","A cafeteria","A loading dock","An elevator"],"answer":0,"explanation":"西側樓梯間將關閉。","translation":"","passage":"","audioText":"This is a reminder that the west stairwell will be closed tomorrow from 9 A.M. until 1 P.M. for safety inspections. During that time, employees should use the elevators near the cafeteria or the east stairwell. Deliveries should enter through the loading dock on Pine Street.","tags":["talk"],"audioTranslation":"提醒各位，西側樓梯間將於明日上午九點至下午一點因安全檢查而關閉。期間員工應使用員工餐廳附近的電梯或東側樓梯間。送貨車輛應由 Pine Street 的裝卸區進入。","groupId":"P4-G04"},{"id":"P4-042","part":"4","difficulty":"800","category":"公司安全","prompt":"What should employees use?","choices":["The elevators or east stairwell","The Pine Street entrance only","The west stairwell","The emergency exit"],"answer":0,"explanation":"公告指定電梯或東側樓梯間。","translation":"","passage":"","audioText":"This is a reminder that the west stairwell will be closed tomorrow from 9 A.M. until 1 P.M. for safety inspections. During that time, employees should use the elevators near the cafeteria or the east stairwell. Deliveries should enter through the loading dock on Pine Street.","tags":["talk"],"audioTranslation":"提醒各位，西側樓梯間將於明日上午九點至下午一點因安全檢查而關閉。期間員工應使用員工餐廳附近的電梯或東側樓梯間。送貨車輛應由 Pine Street 的裝卸區進入。","groupId":"P4-G04"},{"id":"P4-043","part":"4","difficulty":"800","category":"公司安全","prompt":"Where should deliveries enter?","choices":["Through the loading dock","Through the cafeteria","Through the main lobby","Through the west stairwell"],"answer":0,"explanation":"貨運應從 Pine Street 裝卸區進入。","translation":"","passage":"","audioText":"This is a reminder that the west stairwell will be closed tomorrow from 9 A.M. until 1 P.M. for safety inspections. During that time, employees should use the elevators near the cafeteria or the east stairwell. Deliveries should enter through the loading dock on Pine Street.","tags":["talk"],"audioTranslation":"提醒各位，西側樓梯間將於明日上午九點至下午一點因安全檢查而關閉。期間員工應使用員工餐廳附近的電梯或東側樓梯間。送貨車輛應由 Pine Street 的裝卸區進入。","groupId":"P4-G04"},{"id":"P6-001","part":"6","difficulty":"600","category":"電子郵件","prompt":"Choose the best word or phrase for the blank.","choices":["repair","repairs","repaired","repairing"],"answer":2,"explanation":"被動語態 can be repaired。","translation":"","passage":"To: All Staff\nSubject: Parking Area Maintenance\n\nThe north parking area will be closed on Saturday so that the surface can be _____. Employees working that day should use the visitor lot across the street.","audioText":"","tags":["text-completion"],"groupId":"P6-G01"},{"id":"P6-002","part":"6","difficulty":"600","category":"電子郵件","prompt":"Choose the best word or phrase for the blank.","choices":["However","For example","Otherwise","Similarly"],"answer":0,"explanation":"前句說預計四點完成，後句補充可能更早，帶有轉折。","translation":"","passage":"To: All Staff\nSubject: Parking Area Maintenance\n\nThe work is expected to finish by 4 P.M. _____, the area may reopen earlier if weather conditions remain favorable.","audioText":"","tags":["text-completion"],"groupId":"P6-G01"},{"id":"P6-003","part":"6","difficulty":"600","category":"電子郵件","prompt":"Choose the best word or phrase for the blank.","choices":["direct","direction","directly","directed"],"answer":0,"explanation":"will be available to + 原形動詞 direct。","translation":"","passage":"To: All Staff\nSubject: Parking Area Maintenance\n\nSecurity officers will be available to _____ drivers to the temporary parking area.","audioText":"","tags":["text-completion"],"groupId":"P6-G01"},{"id":"P6-004","part":"6","difficulty":"800","category":"電子郵件","prompt":"Choose the best word or phrase for the blank.","choices":["cause","caused","causing","causes"],"answer":0,"explanation":"may 後接原形動詞。","translation":"","passage":"To: All Staff\nSubject: Parking Area Maintenance\n\nWe apologize for any inconvenience this work may _____.","audioText":"","tags":["text-completion"],"groupId":"P6-G01"},{"id":"P6-005","part":"6","difficulty":"600","category":"公司公告","prompt":"Choose the best word or phrase for the blank.","choices":["provide","provided","will provide","have provided"],"answer":2,"explanation":"未來活動，使用 will provide。","translation":"","passage":"The annual employee health fair will take place in the main auditorium on August 12. Representatives from several local clinics _____ free basic screenings.","audioText":"","tags":["text-completion"],"groupId":"P6-G02"},{"id":"P6-006","part":"6","difficulty":"600","category":"公司公告","prompt":"Choose the best word or phrase for the blank.","choices":["by","at","from","among"],"answer":0,"explanation":"截止日期使用 by。","translation":"","passage":"Employees who wish to participate should register online _____ August 8.","audioText":"","tags":["text-completion"],"groupId":"P6-G02"},{"id":"P6-007","part":"6","difficulty":"800","category":"公司公告","prompt":"Choose the best word or phrase for the blank.","choices":["Although","Because of","Despite","Unless"],"answer":0,"explanation":"後面是完整子句 the event is free，用 although。","translation":"","passage":"_____ the event is free, advance registration is required because space is limited.","audioText":"","tags":["text-completion"],"groupId":"P6-G02"},{"id":"P6-008","part":"6","difficulty":"600","category":"公司公告","prompt":"Choose the best word or phrase for the blank.","choices":["register","registering","registered","registration"],"answer":2,"explanation":"registered participants = 已報名的參加者。","translation":"","passage":"A detailed schedule will be sent to all _____ participants.","audioText":"","tags":["text-completion"],"groupId":"P6-G02"},{"id":"P6-009","part":"6","difficulty":"600","category":"顧客通知","prompt":"Choose the best word or phrase for the blank.","choices":["every","each of","all","another"],"answer":0,"explanation":"every + 單數時間單位。","translation":"","passage":"Thank you for purchasing a Bellmont air purifier. To ensure optimal performance, the filter should be replaced _____ six months.","audioText":"","tags":["text-completion"],"groupId":"P6-G03"},{"id":"P6-010","part":"6","difficulty":"600","category":"顧客通知","prompt":"Choose the best word or phrase for the blank.","choices":["authorize","authorized","authority","authorization"],"answer":1,"explanation":"authorized retailer = 授權零售商。","translation":"","passage":"Replacement filters can be ordered through our website or from any _____ retailer.","audioText":"","tags":["text-completion"],"groupId":"P6-G03"},{"id":"P6-011","part":"6","difficulty":"800","category":"顧客通知","prompt":"Choose the best word or phrase for the blank.","choices":["who","whose","whom","which"],"answer":0,"explanation":"先行詞 customers 是人，關係子句缺主詞，用 who。","translation":"","passage":"Customers _____ register their product online will receive maintenance reminders by e-mail.","audioText":"","tags":["text-completion"],"groupId":"P6-G03"},{"id":"P6-012","part":"6","difficulty":"600","category":"顧客通知","prompt":"Choose the best word or phrase for the blank.","choices":["for","to","with","by"],"answer":0,"explanation":"required for + 名詞。","translation":"","passage":"Please keep your receipt, as it may be required _____ warranty service.","audioText":"","tags":["text-completion"],"groupId":"P6-G03"},{"id":"P6-013","part":"6","difficulty":"600","category":"內部備忘錄","prompt":"Choose the best word or phrase for the blank.","choices":["offered","offering","offer","offers"],"answer":0,"explanation":"sessions offered this week = 本週提供的課程，過去分詞修飾。","translation":"","passage":"Beginning next month, expense claims will be processed through the new FinanceTrack system. Employees are encouraged to attend one of the training sessions _____ this week.","audioText":"","tags":["text-completion"],"groupId":"P6-G04"},{"id":"P6-014","part":"6","difficulty":"800","category":"內部備忘錄","prompt":"Choose the best word or phrase for the blank.","choices":["track","tracked","tracking","tracker"],"answer":0,"explanation":"與 upload 平行，使用原形 track。","translation":"","passage":"The sessions will explain how to upload receipts and _____ the status of a claim.","audioText":"","tags":["text-completion"],"groupId":"P6-G04"},{"id":"P6-015","part":"6","difficulty":"600","category":"內部備忘錄","prompt":"Choose the best word or phrase for the blank.","choices":["before","during","until","among"],"answer":0,"explanation":"before + V-ing。","translation":"","passage":"Managers should make sure that all team members have created an account _____ submitting their first claim.","audioText":"","tags":["text-completion"],"groupId":"P6-G04"},{"id":"P6-016","part":"6","difficulty":"800","category":"內部備忘錄","prompt":"Choose the best word or phrase for the blank.","choices":["direct","directing","directed","direction"],"answer":2,"explanation":"問題應被轉交，用被動 be directed to。","translation":"","passage":"Questions regarding the new system should be _____ to the accounting department.","audioText":"","tags":["text-completion"],"groupId":"P6-G04"},{"id":"P7-011","part":"7","difficulty":"600","category":"電子郵件","prompt":"Why was the e-mail sent?","choices":["To announce an elevator inspection","To request rent payments","To advertise office space","To recruit delivery drivers"],"answer":0,"explanation":"主旨是通知電梯檢查。","translation":"","passage":"From: Maria Lopez\nTo: Building Tenants\nSubject: Elevator Inspection\n\nThe two elevators in the east lobby will be inspected on Tuesday, September 14, between 9:00 A.M. and noon. During this period, please use the elevators near the west entrance. Delivery companies should be told to use the loading dock elevator, which will remain in service. We apologize for the temporary inconvenience.","audioText":"","tags":["reading"],"groupId":"P7-R01"},{"id":"P7-012","part":"7","difficulty":"600","category":"電子郵件","prompt":"When will the inspection end?","choices":["At noon","At 9 A.M.","On Monday","At midnight"],"answer":0,"explanation":"between 9:00 A.M. and noon。","translation":"","passage":"From: Maria Lopez\nTo: Building Tenants\nSubject: Elevator Inspection\n\nThe two elevators in the east lobby will be inspected on Tuesday, September 14, between 9:00 A.M. and noon. During this period, please use the elevators near the west entrance. Delivery companies should be told to use the loading dock elevator, which will remain in service. We apologize for the temporary inconvenience.","audioText":"","tags":["reading"],"groupId":"P7-R01"},{"id":"P7-013","part":"7","difficulty":"600","category":"電子郵件","prompt":"What should delivery companies use?","choices":["The loading dock elevator","The east lobby elevators","The stairs near the west entrance","A nearby parking garage"],"answer":0,"explanation":"文中明確指定 loading dock elevator。","translation":"","passage":"From: Maria Lopez\nTo: Building Tenants\nSubject: Elevator Inspection\n\nThe two elevators in the east lobby will be inspected on Tuesday, September 14, between 9:00 A.M. and noon. During this period, please use the elevators near the west entrance. Delivery companies should be told to use the loading dock elevator, which will remain in service. We apologize for the temporary inconvenience.","audioText":"","tags":["reading"],"groupId":"P7-R01"},{"id":"P7-021","part":"7","difficulty":"600","category":"廣告","prompt":"What is being advertised?","choices":["A weekend meeting package","A restaurant opening","An employee training course","A transportation service"],"answer":0,"explanation":"廣告主題是 weekend conference package。","translation":"","passage":"Harbor View Business Hotel\nWeekend Conference Package\n\nReserve a meeting room for Saturday or Sunday and receive:\n• Complimentary wireless Internet\n• Coffee service for up to 20 guests\n• A 15 percent discount on guest rooms\n• Free parking for the event organizer\n\nReservations must be made at least ten days in advance. Call 555-0184 or visit harborviewhotel.example.","audioText":"","tags":["reading"],"groupId":"P7-R02"},{"id":"P7-022","part":"7","difficulty":"600","category":"廣告","prompt":"What is free for the event organizer?","choices":["Parking","Guest rooms","Lunch","Printing"],"answer":0,"explanation":"列點寫 Free parking for the event organizer。","translation":"","passage":"Harbor View Business Hotel\nWeekend Conference Package\n\nReserve a meeting room for Saturday or Sunday and receive:\n• Complimentary wireless Internet\n• Coffee service for up to 20 guests\n• A 15 percent discount on guest rooms\n• Free parking for the event organizer\n\nReservations must be made at least ten days in advance. Call 555-0184 or visit harborviewhotel.example.","audioText":"","tags":["reading"],"groupId":"P7-R02"},{"id":"P7-023","part":"7","difficulty":"600","category":"廣告","prompt":"What is required?","choices":["Booking at least ten days early","Having more than 20 guests","Paying only in cash","Staying for two nights"],"answer":0,"explanation":"Reservations must be made at least ten days in advance。","translation":"","passage":"Harbor View Business Hotel\nWeekend Conference Package\n\nReserve a meeting room for Saturday or Sunday and receive:\n• Complimentary wireless Internet\n• Coffee service for up to 20 guests\n• A 15 percent discount on guest rooms\n• Free parking for the event organizer\n\nReservations must be made at least ten days in advance. Call 555-0184 or visit harborviewhotel.example.","audioText":"","tags":["reading"],"groupId":"P7-R02"},{"id":"P7-031","part":"7","difficulty":"800","category":"公司新聞","prompt":"What did Northstar Electronics announce?","choices":["Plans to open a research center","A product recall","The closure of a factory","A change in leadership"],"answer":0,"explanation":"第一句即說將開設研究中心。","translation":"","passage":"Northstar Electronics announced yesterday that it will open a research center in Taichung early next year. The facility will focus on energy-efficient sensors for household appliances. According to Chief Executive Mina Ross, the location was selected because of its access to engineering talent and nearby manufacturing partners. The company expects to hire approximately 120 employees during the center's first year of operation.","audioText":"","tags":["reading"],"groupId":"P7-R03"},{"id":"P7-032","part":"7","difficulty":"800","category":"公司新聞","prompt":"Why was Taichung selected?","choices":["It offers engineering talent and manufacturing partners","It has the lowest office rent","It is close to the company's headquarters","It provides free transportation"],"answer":0,"explanation":"CEO 提到人才與製造夥伴。","translation":"","passage":"Northstar Electronics announced yesterday that it will open a research center in Taichung early next year. The facility will focus on energy-efficient sensors for household appliances. According to Chief Executive Mina Ross, the location was selected because of its access to engineering talent and nearby manufacturing partners. The company expects to hire approximately 120 employees during the center's first year of operation.","audioText":"","tags":["reading"],"groupId":"P7-R03"},{"id":"P7-033","part":"7","difficulty":"800","category":"公司新聞","prompt":"How many employees may be hired in the first year?","choices":["About 120","About 20","About 1,200","About 12"],"answer":0,"explanation":"文中寫 approximately 120。","translation":"","passage":"Northstar Electronics announced yesterday that it will open a research center in Taichung early next year. The facility will focus on energy-efficient sensors for household appliances. According to Chief Executive Mina Ross, the location was selected because of its access to engineering talent and nearby manufacturing partners. The company expects to hire approximately 120 employees during the center's first year of operation.","audioText":"","tags":["reading"],"groupId":"P7-R03"},{"id":"P7-041","part":"7","difficulty":"600","category":"客訴信","prompt":"Why did Mr. Wu write the letter?","choices":["To report problems with an order","To request a price list","To change a delivery address","To cancel a meeting"],"answer":0,"explanation":"他回報零件受損及缺少說明書。","translation":"","passage":"Dear Customer Service,\n\nI ordered a standing desk from your website on May 3. The desk arrived yesterday, but one of the metal legs was damaged and the assembly instructions were missing. I have attached photographs of the damaged part. Please send a replacement leg and a copy of the instructions as soon as possible. My order number is SD-7741.\n\nSincerely,\nKevin Wu","audioText":"","tags":["reading"],"groupId":"P7-R04"},{"id":"P7-042","part":"7","difficulty":"600","category":"客訴信","prompt":"What was missing?","choices":["Assembly instructions","A desktop surface","A payment receipt","Photographs"],"answer":0,"explanation":"文中說 assembly instructions were missing。","translation":"","passage":"Dear Customer Service,\n\nI ordered a standing desk from your website on May 3. The desk arrived yesterday, but one of the metal legs was damaged and the assembly instructions were missing. I have attached photographs of the damaged part. Please send a replacement leg and a copy of the instructions as soon as possible. My order number is SD-7741.\n\nSincerely,\nKevin Wu","audioText":"","tags":["reading"],"groupId":"P7-R04"},{"id":"P7-043","part":"7","difficulty":"600","category":"客訴信","prompt":"What did Mr. Wu attach?","choices":["Photographs","A warranty card","A new order form","A shipping label"],"answer":0,"explanation":"文中說 attached photographs。","translation":"","passage":"Dear Customer Service,\n\nI ordered a standing desk from your website on May 3. The desk arrived yesterday, but one of the metal legs was damaged and the assembly instructions were missing. I have attached photographs of the damaged part. Please send a replacement leg and a copy of the instructions as soon as possible. My order number is SD-7741.\n\nSincerely,\nKevin Wu","audioText":"","tags":["reading"],"groupId":"P7-R04"},{"id":"P7-051","part":"7","difficulty":"800","category":"活動通知","prompt":"What is the workshop about?","choices":["Reducing waste at work","Preparing financial reports","Improving public speaking","Repairing office equipment"],"answer":0,"explanation":"主題是 reducing office waste。","translation":"","passage":"The Green Workplace Committee invites employees to join a lunchtime workshop on reducing office waste. The workshop will be held in Room 402 on October 6 from 12:15 to 1:00 P.M. Participants will learn how to set up paper-reduction goals and organize reusable supply stations. A light lunch will be provided. Because seating is limited to 35 people, employees should register through the internal portal by October 2.","audioText":"","tags":["reading"],"groupId":"P7-R05"},{"id":"P7-052","part":"7","difficulty":"800","category":"活動通知","prompt":"What will participants receive?","choices":["A light lunch","A travel allowance","A printed certificate","Free office furniture"],"answer":0,"explanation":"文中說 A light lunch will be provided。","translation":"","passage":"The Green Workplace Committee invites employees to join a lunchtime workshop on reducing office waste. The workshop will be held in Room 402 on October 6 from 12:15 to 1:00 P.M. Participants will learn how to set up paper-reduction goals and organize reusable supply stations. A light lunch will be provided. Because seating is limited to 35 people, employees should register through the internal portal by October 2.","audioText":"","tags":["reading"],"groupId":"P7-R05"},{"id":"P7-053","part":"7","difficulty":"800","category":"活動通知","prompt":"Why should employees register early?","choices":["Seating is limited","The fee will increase","Managers must approve attendance","The room may change"],"answer":0,"explanation":"因為只有 35 個座位。","translation":"","passage":"The Green Workplace Committee invites employees to join a lunchtime workshop on reducing office waste. The workshop will be held in Room 402 on October 6 from 12:15 to 1:00 P.M. Participants will learn how to set up paper-reduction goals and organize reusable supply stations. A light lunch will be provided. Because seating is limited to 35 people, employees should register through the internal portal by October 2.","audioText":"","tags":["reading"],"groupId":"P7-R05"},{"id":"P7-061","part":"7","difficulty":"800","category":"雙篇閱讀","prompt":"Why will the library close early?","choices":["To install computer equipment","To hold a private event","To repair the café","To train new librarians"],"answer":0,"explanation":"公告明確說安裝新電腦設備。","translation":"","passage":"NOTICE\nThe Lakeside Library will close at 6 P.M. instead of 9 P.M. on Friday, November 19, so that new computer equipment can be installed. The library will reopen at its usual time on Saturday.\n\nE-MAIL\nFrom: Jordan Kim\nTo: Study Group\nI just saw the library notice. Since we planned to meet Friday at 7, let's use the café across from the library instead. It has a large table in the back, but we should arrive early because it becomes crowded after dinner.","audioText":"","tags":["reading"],"groupId":"P7-R06"},{"id":"P7-062","part":"7","difficulty":"800","category":"雙篇閱讀","prompt":"What does Jordan suggest?","choices":["Meeting at a café","Changing the meeting to Saturday","Using the library in the morning","Canceling the study group"],"answer":0,"explanation":"電子郵件建議改在圖書館對面的咖啡廳。","translation":"","passage":"NOTICE\nThe Lakeside Library will close at 6 P.M. instead of 9 P.M. on Friday, November 19, so that new computer equipment can be installed. The library will reopen at its usual time on Saturday.\n\nE-MAIL\nFrom: Jordan Kim\nTo: Study Group\nI just saw the library notice. Since we planned to meet Friday at 7, let's use the café across from the library instead. It has a large table in the back, but we should arrive early because it becomes crowded after dinner.","audioText":"","tags":["reading"],"groupId":"P7-R06"},{"id":"P7-063","part":"7","difficulty":"800","category":"雙篇閱讀","prompt":"Why should the group arrive early?","choices":["The café gets crowded","The library doors will be locked","The computer installation starts early","The café closes before dinner"],"answer":0,"explanation":"咖啡廳晚餐後會變擁擠。","translation":"","passage":"NOTICE\nThe Lakeside Library will close at 6 P.M. instead of 9 P.M. on Friday, November 19, so that new computer equipment can be installed. The library will reopen at its usual time on Saturday.\n\nE-MAIL\nFrom: Jordan Kim\nTo: Study Group\nI just saw the library notice. Since we planned to meet Friday at 7, let's use the café across from the library instead. It has a large table in the back, but we should arrive early because it becomes crowded after dinner.","audioText":"","tags":["reading"],"groupId":"P7-R06"},{"id":"P7-071","part":"7","difficulty":"800","category":"職缺","prompt":"What is one duty of the position?","choices":["Managing website updates","Repairing computer hardware","Selling insurance policies","Planning international flights"],"answer":0,"explanation":"職務包含 manage website updates。","translation":"","passage":"Digital Content Coordinator\n\nPine & Row Publishing is seeking a detail-oriented coordinator to manage website updates and prepare weekly newsletters. Candidates should have at least two years of experience with content management systems and strong written communication skills. Familiarity with basic HTML is preferred but not required. The position is full-time and includes health insurance, paid leave, and a transportation allowance. Applications received by March 18 will receive priority consideration.","audioText":"","tags":["reading"],"groupId":"P7-R07"},{"id":"P7-072","part":"7","difficulty":"800","category":"職缺","prompt":"What is preferred but not required?","choices":["Basic HTML knowledge","Two years of experience","Writing ability","Availability for full-time work"],"answer":0,"explanation":"Familiarity with basic HTML is preferred but not required。","translation":"","passage":"Digital Content Coordinator\n\nPine & Row Publishing is seeking a detail-oriented coordinator to manage website updates and prepare weekly newsletters. Candidates should have at least two years of experience with content management systems and strong written communication skills. Familiarity with basic HTML is preferred but not required. The position is full-time and includes health insurance, paid leave, and a transportation allowance. Applications received by March 18 will receive priority consideration.","audioText":"","tags":["reading"],"groupId":"P7-R07"},{"id":"P7-073","part":"7","difficulty":"800","category":"職缺","prompt":"How can applicants receive priority?","choices":["Apply by March 18","Provide three references","Accept a lower salary","Visit the office in person"],"answer":0,"explanation":"在 3 月 18 日前申請會優先考量。","translation":"","passage":"Digital Content Coordinator\n\nPine & Row Publishing is seeking a detail-oriented coordinator to manage website updates and prepare weekly newsletters. Candidates should have at least two years of experience with content management systems and strong written communication skills. Familiarity with basic HTML is preferred but not required. The position is full-time and includes health insurance, paid leave, and a transportation allowance. Applications received by March 18 will receive priority consideration.","audioText":"","tags":["reading"],"groupId":"P7-R07"},{"id":"P7-081","part":"7","difficulty":"600","category":"訂單確認","prompt":"How much do the two keyboards cost in total?","choices":["$136","$68","$42","$178"],"answer":0,"explanation":"2 × 68 = 136。","translation":"","passage":"Order Confirmation: #B-19084\n\nItems:\n2 × Ergonomic Keyboard — $68 each\n1 × Wireless Mouse — $42\nStandard delivery — Free\n\nEstimated delivery: June 10–12\nShipping address: 28 Maple Avenue, Suite 5\n\nTo change or cancel this order, contact customer service within 24 hours of purchase. Returns are accepted within 30 days after delivery, provided that the items are unused and in their original packaging.","audioText":"","tags":["reading"],"groupId":"P7-R08"},{"id":"P7-082","part":"7","difficulty":"600","category":"訂單確認","prompt":"What is the delivery charge?","choices":["There is no charge","$42","$24","$30"],"answer":0,"explanation":"Standard delivery — Free。","translation":"","passage":"Order Confirmation: #B-19084\n\nItems:\n2 × Ergonomic Keyboard — $68 each\n1 × Wireless Mouse — $42\nStandard delivery — Free\n\nEstimated delivery: June 10–12\nShipping address: 28 Maple Avenue, Suite 5\n\nTo change or cancel this order, contact customer service within 24 hours of purchase. Returns are accepted within 30 days after delivery, provided that the items are unused and in their original packaging.","audioText":"","tags":["reading"],"groupId":"P7-R08"},{"id":"P7-083","part":"7","difficulty":"600","category":"訂單確認","prompt":"Under what condition may an item be returned?","choices":["It is unused and in its original packaging","It was purchased more than 30 days ago","It has been repaired by the customer","It was delivered to a business address"],"answer":0,"explanation":"退貨條件是未使用且保留原包裝。","translation":"","passage":"Order Confirmation: #B-19084\n\nItems:\n2 × Ergonomic Keyboard — $68 each\n1 × Wireless Mouse — $42\nStandard delivery — Free\n\nEstimated delivery: June 10–12\nShipping address: 28 Maple Avenue, Suite 5\n\nTo change or cancel this order, contact customer service within 24 hours of purchase. Returns are accepted within 30 days after delivery, provided that the items are unused and in their original packaging.","audioText":"","tags":["reading"],"groupId":"P7-R08"},{"id":"P2-021","part":"2","difficulty":"400","category":"應答","prompt":"Choose the best response.","choices":["Early next month.","At the front desk.","It has a blue cover."],"answer":0,"explanation":"When 問時間，應回答下個月初。","translation":"新目錄何時可以取得？","passage":"","audioText":"When will the new catalog be available?","audioTranslation":"新目錄何時可以取得？","answerTranslation":"下個月初。","tags":["listening","response"]},{"id":"P2-022","part":"2","difficulty":"600","category":"應答","prompt":"Choose the best response.","choices":["Yes, that would be helpful.","The copier was repaired.","I paid by credit card."],"answer":0,"explanation":"Would you like me to...? 是主動提供協助，最自然的是接受或婉拒。","translation":"需要我影印一份收據嗎？","passage":"","audioText":"Would you like me to make a copy of the receipt?","audioTranslation":"需要我影印一份收據嗎？","answerTranslation":"好的，那會很有幫助。","tags":["listening","response"]},{"id":"P2-023","part":"2","difficulty":"600","category":"應答","prompt":"Choose the best response.","choices":["No, the replacement hasn't arrived yet.","The part costs thirty dollars.","Yesterday was very busy."],"answer":0,"explanation":"否定疑問句仍依事實回答；此處說明尚未更換的原因。","translation":"技術人員昨天不是已經更換這個零件了嗎？","passage":"","audioText":"Didn't the technician replace this part yesterday?","audioTranslation":"技術人員昨天不是已經更換這個零件了嗎？","answerTranslation":"沒有，替換零件還沒送到。","tags":["listening","response"]},{"id":"P2-024","part":"2","difficulty":"400","category":"應答","prompt":"Choose the best response.","choices":["Someone in the accounting department.","For a three-day trip.","The ticket was refundable."],"answer":0,"explanation":"Who 問聯絡對象。","translation":"關於差旅費報銷，我應該聯絡誰？","passage":"","audioText":"Who should I contact about my travel reimbursement?","audioTranslation":"關於差旅費報銷，我應該聯絡誰？","answerTranslation":"會計部門的人。","tags":["listening","response"]},{"id":"P2-025","part":"2","difficulty":"600","category":"應答","prompt":"Choose the best response.","choices":["That might attract more customers.","The entrance closes at nine.","The display was expensive."],"answer":0,"explanation":"Why don't we...? 是建議，應回應是否同意。","translation":"我們何不把展示架移到入口附近？","passage":"","audioText":"Why don't we move the display closer to the entrance?","audioTranslation":"我們何不把展示架移到入口附近？","answerTranslation":"那可能會吸引更多顧客。","tags":["listening","response"]},{"id":"P2-026","part":"2","difficulty":"400","category":"應答","prompt":"Choose the best response.","choices":["About forty-five minutes.","On every office computer.","The installer is experienced."],"answer":0,"explanation":"How long 問持續時間。","translation":"軟體安裝需要多久？","passage":"","audioText":"How long will the software installation take?","audioTranslation":"軟體安裝需要多久？","answerTranslation":"大約四十五分鐘。","tags":["listening","response"]},{"id":"P2-027","part":"2","difficulty":"600","category":"應答","prompt":"Choose the best response.","choices":["In the auditorium on the first floor.","It begins after lunch.","The new employees attended."],"answer":0,"explanation":"where 問地點。","translation":"你可以告訴我新人說明會在哪裡舉行嗎？","passage":"","audioText":"Could you tell me where the orientation is being held?","audioTranslation":"你可以告訴我新人說明會在哪裡舉行嗎？","answerTranslation":"在一樓的禮堂。","tags":["listening","response"]},{"id":"P2-028","part":"2","difficulty":"600","category":"應答","prompt":"Choose the best response.","choices":["Yes, I'll add it to the supply order.","The holiday lasts three days.","The printer is near my desk."],"answer":0,"explanation":"Shouldn't we...? 帶有建議意味，最自然的是同意並採取行動。","translation":"我們不是應該在假日前多訂一些影印紙嗎？","passage":"","audioText":"Shouldn't we order more printer paper before the holiday?","audioTranslation":"我們不是應該在假日前多訂一些影印紙嗎？","answerTranslation":"是的，我會把它加進用品訂單。","tags":["listening","response"]},{"id":"P2-029","part":"2","difficulty":"400","category":"應答","prompt":"Choose the best response.","choices":["The one who worked in Toronto.","At the interview tomorrow.","About six years ago."],"answer":0,"explanation":"Which candidate 問特定候選人。","translation":"哪位候選人的管理經驗最豐富？","passage":"","audioText":"Which candidate has the most management experience?","audioTranslation":"哪位候選人的管理經驗最豐富？","answerTranslation":"那位曾在多倫多工作的人。","tags":["listening","response"]},{"id":"P2-030","part":"2","difficulty":"600","category":"應答","prompt":"Choose the best response.","choices":["Not yet, so I sent another e-mail.","The delivery truck is outside.","Yes, the package is heavy."],"answer":0,"explanation":"現在完成式問目前是否已完成；回答尚未並說明後續行動。","translation":"顧客已經確認送貨地址了嗎？","passage":"","audioText":"Has the customer confirmed the delivery address?","audioTranslation":"顧客已經確認送貨地址了嗎？","answerTranslation":"還沒，所以我又寄了一封電子郵件。","tags":["listening","response"]},{"id":"P3-071","part":"3","difficulty":"600","category":"訂單修改","prompt":"Why is the woman calling?","choices":["To change an order quantity","To report damaged notebooks","To request a refund","To apply for a job"],"answer":0,"explanation":"女子要把筆記本數量從二十本改成三十本。","translation":"","passage":"","audioText":"W: Hello, I'm calling about order 7615. We need thirty notebooks instead of twenty. M: I can update the quantity, but the delivery date may move from Tuesday to Wednesday. W: Wednesday is fine, as long as the boxes arrive before noon.","audioTranslation":"女：您好，我來電是關於訂單 7615。我們需要三十本筆記本，而不是二十本。男：我可以更新數量，不過送貨日期可能會從星期二改到星期三。女：星期三沒問題，只要箱子能在中午前送達。","tags":["conversation","listening"],"groupId":"P3-G07"},{"id":"P3-072","part":"3","difficulty":"600","category":"訂單修改","prompt":"What may change?","choices":["The delivery date","The product color","The payment method","The shipping address"],"answer":0,"explanation":"男子說交貨日期可能由星期二改到星期三。","translation":"","passage":"","audioText":"W: Hello, I'm calling about order 7615. We need thirty notebooks instead of twenty. M: I can update the quantity, but the delivery date may move from Tuesday to Wednesday. W: Wednesday is fine, as long as the boxes arrive before noon.","audioTranslation":"女：您好，我來電是關於訂單 7615。我們需要三十本筆記本，而不是二十本。男：我可以更新數量，不過送貨日期可能會從星期二改到星期三。女：星期三沒問題，只要箱子能在中午前送達。","tags":["conversation","listening"],"groupId":"P3-G07"},{"id":"P3-073","part":"3","difficulty":"600","category":"訂單修改","prompt":"What does the woman require?","choices":["Delivery before noon","A lower price","Separate invoices","Tuesday delivery"],"answer":0,"explanation":"女子說只要中午以前抵達即可。","translation":"","passage":"","audioText":"W: Hello, I'm calling about order 7615. We need thirty notebooks instead of twenty. M: I can update the quantity, but the delivery date may move from Tuesday to Wednesday. W: Wednesday is fine, as long as the boxes arrive before noon.","audioTranslation":"女：您好，我來電是關於訂單 7615。我們需要三十本筆記本，而不是二十本。男：我可以更新數量，不過送貨日期可能會從星期二改到星期三。女：星期三沒問題，只要箱子能在中午前送達。","tags":["conversation","listening"],"groupId":"P3-G07"},{"id":"P3-081","part":"3","difficulty":"800","category":"簡報設備","prompt":"What problem does the man mention?","choices":["A projector image is too dark","A presentation file is missing","A conference room is locked","Several attendees are late"],"answer":0,"explanation":"男子說投影畫面太暗。","translation":"","passage":"","audioText":"M: I tested the projector in Conference Room C, but the image is still too dark. W: The larger projector is available in Room A. We could move the presentation there. M: Good idea. I'll tell the attendees about the room change.","audioTranslation":"男：我測試了 C 會議室的投影機，但畫面仍然太暗。女：A 會議室有一台較大的投影機可用。我們可以把簡報移到那裡。男：好主意。我會通知與會者更換會議室。","tags":["conversation","listening"],"groupId":"P3-G08"},{"id":"P3-082","part":"3","difficulty":"800","category":"簡報設備","prompt":"What does the woman suggest?","choices":["Using another room","Buying a new computer","Printing the slides","Postponing the meeting"],"answer":0,"explanation":"女子建議移到有較大投影機的 A 會議室。","translation":"","passage":"","audioText":"M: I tested the projector in Conference Room C, but the image is still too dark. W: The larger projector is available in Room A. We could move the presentation there. M: Good idea. I'll tell the attendees about the room change.","audioTranslation":"男：我測試了 C 會議室的投影機，但畫面仍然太暗。女：A 會議室有一台較大的投影機可用。我們可以把簡報移到那裡。男：好主意。我會通知與會者更換會議室。","tags":["conversation","listening"],"groupId":"P3-G08"},{"id":"P3-083","part":"3","difficulty":"800","category":"簡報設備","prompt":"What will the man do?","choices":["Notify the attendees","Repair the projector","Reserve a restaurant","Cancel the presentation"],"answer":0,"explanation":"男子會通知與會者更換房間。","translation":"","passage":"","audioText":"M: I tested the projector in Conference Room C, but the image is still too dark. W: The larger projector is available in Room A. We could move the presentation there. M: Good idea. I'll tell the attendees about the room change.","audioTranslation":"男：我測試了 C 會議室的投影機，但畫面仍然太暗。女：A 會議室有一台較大的投影機可用。我們可以把簡報移到那裡。男：好主意。我會通知與會者更換會議室。","tags":["conversation","listening"],"groupId":"P3-G08"},{"id":"P4-051","part":"4","difficulty":"600","category":"商店公告","prompt":"What has changed?","choices":["A department has moved","The store has closed","Parking fees have increased","A product has been recalled"],"answer":0,"explanation":"家電部門移到二樓。","translation":"","passage":"","audioText":"Good morning, shoppers. Beginning today, the home appliance department has moved from the third floor to the newly renovated second floor. To celebrate, all small kitchen appliances are fifteen percent off through Sunday. Please ask a sales associate for assistance.","audioTranslation":"各位顧客早安。從今天開始，家電部門已從三樓搬到新整修完成的二樓。為了慶祝，所有小型廚房家電到星期日為止一律九折五。需要協助請洽銷售人員。","tags":["talk","listening"],"groupId":"P4-G05"},{"id":"P4-052","part":"4","difficulty":"600","category":"商店公告","prompt":"What is discounted?","choices":["Small kitchen appliances","All furniture","Delivery services","Restaurant meals"],"answer":0,"explanation":"小型廚房家電打八五折。","translation":"","passage":"","audioText":"Good morning, shoppers. Beginning today, the home appliance department has moved from the third floor to the newly renovated second floor. To celebrate, all small kitchen appliances are fifteen percent off through Sunday. Please ask a sales associate for assistance.","audioTranslation":"各位顧客早安。從今天開始，家電部門已從三樓搬到新整修完成的二樓。為了慶祝，所有小型廚房家電到星期日為止一律九折五。需要協助請洽銷售人員。","tags":["talk","listening"],"groupId":"P4-G05"},{"id":"P4-053","part":"4","difficulty":"600","category":"商店公告","prompt":"Until when is the discount offered?","choices":["Through Sunday","Until noon today","For one month","Through Friday"],"answer":0,"explanation":"公告明確說 through Sunday。","translation":"","passage":"","audioText":"Good morning, shoppers. Beginning today, the home appliance department has moved from the third floor to the newly renovated second floor. To celebrate, all small kitchen appliances are fifteen percent off through Sunday. Please ask a sales associate for assistance.","audioTranslation":"各位顧客早安。從今天開始，家電部門已從三樓搬到新整修完成的二樓。為了慶祝，所有小型廚房家電到星期日為止一律九折五。需要協助請洽銷售人員。","tags":["talk","listening"],"groupId":"P4-G05"},{"id":"P4-061","part":"4","difficulty":"800","category":"會議開場","prompt":"What should listeners do first?","choices":["Sign an attendance sheet","Go to the cafeteria","Put on safety equipment","Watch an outdoor demonstration"],"answer":0,"explanation":"開始前先簽到並領手冊。","translation":"","passage":"","audioText":"Before we begin today's safety workshop, please sign the attendance sheet near the entrance and collect a training booklet. The morning session will end at eleven forty-five, followed by lunch in the cafeteria. The afternoon demonstration will take place outdoors, so please bring your identification badge.","audioTranslation":"在今天的安全工作坊開始前，請在入口附近的簽到表簽名，並領取訓練手冊。上午課程將於十一點四十五分結束，之後在員工餐廳用餐。下午的示範將在戶外舉行，因此請攜帶識別證。","tags":["talk","listening"],"groupId":"P4-G06"},{"id":"P4-062","part":"4","difficulty":"800","category":"會議開場","prompt":"What happens after the morning session?","choices":["Lunch is served","A test is given","The workshop ends","A bus departs"],"answer":0,"explanation":"上午課程後在餐廳用餐。","translation":"","passage":"","audioText":"Before we begin today's safety workshop, please sign the attendance sheet near the entrance and collect a training booklet. The morning session will end at eleven forty-five, followed by lunch in the cafeteria. The afternoon demonstration will take place outdoors, so please bring your identification badge.","audioTranslation":"在今天的安全工作坊開始前，請在入口附近的簽到表簽名，並領取訓練手冊。上午課程將於十一點四十五分結束，之後在員工餐廳用餐。下午的示範將在戶外舉行，因此請攜帶識別證。","tags":["talk","listening"],"groupId":"P4-G06"},{"id":"P4-063","part":"4","difficulty":"800","category":"會議開場","prompt":"Why should listeners bring an identification badge?","choices":["The afternoon activity is outdoors","They need to borrow a booklet","The cafeteria requires payment","The entrance is being repaired"],"answer":0,"explanation":"下午示範在戶外，需攜帶識別證。","translation":"","passage":"","audioText":"Before we begin today's safety workshop, please sign the attendance sheet near the entrance and collect a training booklet. The morning session will end at eleven forty-five, followed by lunch in the cafeteria. The afternoon demonstration will take place outdoors, so please bring your identification badge.","audioTranslation":"在今天的安全工作坊開始前，請在入口附近的簽到表簽名，並領取訓練手冊。上午課程將於十一點四十五分結束，之後在員工餐廳用餐。下午的示範將在戶外舉行，因此請攜帶識別證。","tags":["talk","listening"],"groupId":"P4-G06"},{"id":"P5-061","part":"5","difficulty":"400","category":"固定搭配","prompt":"Employees are encouraged to become familiar _____ the new safety procedures.","choices":["to","with","for","of"],"answer":1,"explanation":"become/be familiar with 是「熟悉……」。","translation":"員工被鼓勵熟悉新的安全程序。","passage":"","audioText":"","tags":["reading","grammar"]},{"id":"P5-062","part":"5","difficulty":"600","category":"動名詞","prompt":"The committee is committed to _____ energy consumption by ten percent.","choices":["reduce","reduced","reducing","reduction"],"answer":2,"explanation":"be committed to 中的 to 是介系詞，後接 V-ing。","translation":"委員會致力於將能源消耗降低百分之十。","passage":"","audioText":"","tags":["reading","grammar"]},{"id":"P5-063","part":"5","difficulty":"600","category":"動名詞","prompt":"Ms. Flores is accustomed to _____ with international clients.","choices":["work","worked","working","be worked"],"answer":2,"explanation":"be accustomed to 的 to 是介系詞，後接 V-ing。","translation":"Flores 女士習慣與國際客戶合作。","passage":"","audioText":"","tags":["reading","grammar"]},{"id":"P5-064","part":"5","difficulty":"400","category":"不定詞","prompt":"All visitors are required _____ a temporary identification badge.","choices":["wear","wearing","to wear","wore"],"answer":2,"explanation":"be required to V。","translation":"所有訪客都必須佩戴臨時識別證。","passage":"","audioText":"","tags":["reading","grammar"]},{"id":"P5-065","part":"5","difficulty":"600","category":"不定詞","prompt":"Demand for the new service is likely _____ during the holiday season.","choices":["increase","to increase","increasing","increased"],"answer":1,"explanation":"be likely to V 表示「很可能……」。","translation":"新服務的需求很可能在假期期間增加。","passage":"","audioText":"","tags":["reading","grammar"]},{"id":"P5-066","part":"5","difficulty":"400","category":"介系詞","prompt":"The revised contract is different _____ the version we reviewed last week.","choices":["with","than","from","to"],"answer":2,"explanation":"be different from 是標準固定搭配。","translation":"修訂後的合約與上週審查的版本不同。","passage":"","audioText":"","tags":["reading","grammar"]},{"id":"P5-067","part":"5","difficulty":"600","category":"介系詞","prompt":"The conference fee is inclusive _____ lunch and printed materials.","choices":["of","for","to","with"],"answer":0,"explanation":"be inclusive of 表示「包含……」。","translation":"會議費用包含午餐與印刷資料。","passage":"","audioText":"","tags":["reading","grammar"]},{"id":"P5-068","part":"5","difficulty":"600","category":"副詞","prompt":"Please read the installation instructions _____ before operating the equipment.","choices":["careful","carefully","carefulness","more careful"],"answer":1,"explanation":"修飾動詞 read，使用副詞 carefully。","translation":"操作設備前請仔細閱讀安裝說明。","passage":"","audioText":"","tags":["reading","grammar"]},{"id":"P5-069","part":"5","difficulty":"400","category":"詞性","prompt":"The manager praised the team for its _____ response to the customer complaint.","choices":["prompt","promptly","promptness","prompted"],"answer":0,"explanation":"修飾名詞 response，用形容詞 prompt。","translation":"經理稱讚團隊迅速回應顧客投訴。","passage":"","audioText":"","tags":["reading","grammar"]},{"id":"P5-070","part":"5","difficulty":"600","category":"主詞動詞一致","prompt":"A list of approved vendors _____ available from the purchasing department.","choices":["are","were","is","have"],"answer":2,"explanation":"主詞中心字為單數 list，不受 vendors 影響。","translation":"核准供應商名單可向採購部門索取。","passage":"","audioText":"","tags":["reading","grammar"]},{"id":"P5-071","part":"5","difficulty":"600","category":"關係副詞","prompt":"The factory _____ the components are assembled operates around the clock.","choices":["which","where","who","when"],"answer":1,"explanation":"先行詞 factory 是地點，子句缺地點副詞，用 where。","translation":"組裝零件的工廠全天候運作。","passage":"","audioText":"","tags":["reading","grammar"]},{"id":"P5-072","part":"5","difficulty":"800","category":"關係子句","prompt":"The consultant to _____ we sent the financial records will arrive tomorrow.","choices":["who","whom","whose","which"],"answer":1,"explanation":"介系詞 to 後指人，正式用 whom。","translation":"我們寄送財務紀錄給他的那位顧問將於明天抵達。","passage":"","audioText":"","tags":["reading","grammar"]},{"id":"P5-073","part":"5","difficulty":"800","category":"倒裝","prompt":"Not until the final inspection _____ the building open to the public.","choices":["did","was","was it","it was"],"answer":2,"explanation":"Not until 置於句首時主句倒裝：was the building open。","translation":"直到最終檢查完成後，建築才對外開放。","passage":"","audioText":"","tags":["reading","grammar"]},{"id":"P5-074","part":"5","difficulty":"800","category":"分詞","prompt":"_____ near the main entrance, the information desk is easy to find.","choices":["Located","Locating","To locate","Having located"],"answer":0,"explanation":"information desk 與 locate 為被動關係，用過去分詞 located。","translation":"服務台位於正門附近，很容易找到。","passage":"","audioText":"","tags":["reading","grammar"]},{"id":"P5-075","part":"5","difficulty":"600","category":"完成式","prompt":"The company _____ three new branches so far this year.","choices":["opens","opened","has opened","will open"],"answer":2,"explanation":"so far this year 常搭配現在完成式。","translation":"公司今年到目前為止已開設三家新分店。","passage":"","audioText":"","tags":["reading","grammar"]},{"id":"P5-076","part":"5","difficulty":"800","category":"未來完成式","prompt":"By the end of June, the construction crew _____ the roof repairs.","choices":["completes","completed","will complete","will have completed"],"answer":3,"explanation":"by + 未來時間點，強調屆時完成，用未來完成式。","translation":"到六月底，施工團隊將已完成屋頂修繕。","passage":"","audioText":"","tags":["reading","grammar"]},{"id":"P5-077","part":"5","difficulty":"600","category":"比較級","prompt":"The new delivery system is considerably _____ than the previous one.","choices":["reliable","more reliable","most reliable","reliably"],"answer":1,"explanation":"than 前使用比較級 more reliable。","translation":"新的配送系統比先前的可靠得多。","passage":"","audioText":"","tags":["reading","grammar"]},{"id":"P5-078","part":"5","difficulty":"400","category":"代名詞","prompt":"Employees may choose the training session that best fits _____ schedule.","choices":["they","them","their","theirs"],"answer":2,"explanation":"名詞 schedule 前用所有格形容詞 their。","translation":"員工可以選擇最符合自己行程的訓練課程。","passage":"","audioText":"","tags":["reading","grammar"]},{"id":"P5-079","part":"5","difficulty":"600","category":"連接副詞","prompt":"The product received excellent reviews; _____, sales remained below expectations.","choices":["therefore","however","in addition","for example"],"answer":1,"explanation":"前後語意轉折，使用 however。","translation":"產品獲得極佳評價；然而銷售仍低於預期。","passage":"","audioText":"","tags":["reading","grammar"]},{"id":"P5-080","part":"5","difficulty":"600","category":"商務字彙","prompt":"The board decided to _____ additional funds to employee training.","choices":["allocate","locate","calculate","translate"],"answer":0,"explanation":"allocate funds to 表示將資金分配給某用途。","translation":"董事會決定撥出額外資金用於員工訓練。","passage":"","audioText":"","tags":["reading","grammar"]},{"id":"P6-017","part":"6","difficulty":"600","category":"活動通知","prompt":"Choose the best word or phrase for the blank.","choices":["prompt","promptly","promptness","prompted"],"answer":1,"explanation":"修飾 begin，使用副詞 promptly。","translation":"","passage":"The Riverside Business Association will host a networking breakfast on April 22. Guests are asked to arrive by 8:15 so that the program can begin _____.","audioText":"","tags":["text-completion"],"groupId":"P6-G05"},{"id":"P6-018","part":"6","difficulty":"600","category":"活動通知","prompt":"Choose the best word or phrase for the blank.","choices":["give","gave","given","giving"],"answer":0,"explanation":"to 後接原形動詞 give。","translation":"","passage":"The Riverside Business Association will host a networking breakfast on April 22. Each participant will have an opportunity to _____ a brief introduction.","audioText":"","tags":["text-completion"],"groupId":"P6-G05"},{"id":"P6-019","part":"6","difficulty":"800","category":"活動通知","prompt":"Choose the best word or phrase for the blank.","choices":["Because","Despite","During","Unless"],"answer":0,"explanation":"後接完整子句 attendance is limited，使用 Because。","translation":"","passage":"The Riverside Business Association will host a networking breakfast on April 22. _____ attendance is limited, reservations are strongly recommended.","audioText":"","tags":["text-completion"],"groupId":"P6-G05"},{"id":"P6-020","part":"6","difficulty":"600","category":"活動通知","prompt":"Choose the best word or phrase for the blank.","choices":["once","during","despite","meanwhile"],"answer":0,"explanation":"once + 子句，表示「一旦……」。","translation":"","passage":"The Riverside Business Association will host a networking breakfast on April 22. Confirmation e-mails will be sent _____ registration is completed.","audioText":"","tags":["text-completion"],"groupId":"P6-G05"},{"id":"P6-021","part":"6","difficulty":"600","category":"服務公告","prompt":"Choose the best word or phrase for the blank.","choices":["perform","performed","performing","performance"],"answer":1,"explanation":"更新是被執行，用被動 are performed。","translation":"","passage":"Our online banking service will be temporarily unavailable from midnight to 3 A.M. on Sunday while system updates are _____.","audioText":"","tags":["text-completion"],"groupId":"P6-G06"},{"id":"P6-022","part":"6","difficulty":"600","category":"服務公告","prompt":"Choose the best word or phrase for the blank.","choices":["before","among","through","unless"],"answer":0,"explanation":"在維護開始前完成，用 before。","translation":"","passage":"Our online banking service will be temporarily unavailable from midnight to 3 A.M. on Sunday. Customers are advised to complete urgent transactions _____ the maintenance period begins.","audioText":"","tags":["text-completion"],"groupId":"P6-G06"},{"id":"P6-023","part":"6","difficulty":"800","category":"服務公告","prompt":"Choose the best word or phrase for the blank.","choices":["unless","because","although","therefore"],"answer":0,"explanation":"unless = 除非。","translation":"","passage":"Our online banking service will be temporarily unavailable from midnight to 3 A.M. on Sunday. We expect all services to resume normally, _____ unexpected technical problems occur.","audioText":"","tags":["text-completion"],"groupId":"P6-G06"},{"id":"P6-024","part":"6","difficulty":"600","category":"服務公告","prompt":"Choose the best word or phrase for the blank.","choices":["patient","patience","patiently","patients"],"answer":1,"explanation":"your 後接名詞 patience。","translation":"","passage":"Our online banking service will be temporarily unavailable from midnight to 3 A.M. on Sunday. We appreciate your _____ during this scheduled maintenance.","audioText":"","tags":["text-completion"],"groupId":"P6-G06"},{"id":"P7-091","part":"7","difficulty":"600","category":"電子郵件","prompt":"What is changing next month?","choices":["How supply requests are submitted","Where employees receive deliveries","The price of office furniture","The date of the monthly meeting"],"answer":0,"explanation":"下個月開始必須透過新的採購入口提交用品需求。","translation":"","passage":"From: Olivia Grant\nTo: All Department Assistants\nSubject: Monthly Supply Orders\n\nBeginning next month, office supply requests must be submitted through the new purchasing portal. Requests received by the twentieth will be included in that month's order. A short online tutorial is available on the employee website. Please contact Purchasing if your department needs an item that is not listed in the portal.","audioText":"","tags":["reading"],"groupId":"P7-R09"},{"id":"P7-092","part":"7","difficulty":"600","category":"電子郵件","prompt":"What should an employee do if an item is not listed?","choices":["Contact the purchasing department","Order it from a personal account","Wait until the following year","Ask the delivery driver"],"answer":0,"explanation":"文末要求聯絡 Purchasing。","translation":"","passage":"From: Olivia Grant\nTo: All Department Assistants\nSubject: Monthly Supply Orders\n\nBeginning next month, office supply requests must be submitted through the new purchasing portal. Requests received by the twentieth will be included in that month's order. A short online tutorial is available on the employee website. Please contact Purchasing if your department needs an item that is not listed in the portal.","audioText":"","tags":["reading"],"groupId":"P7-R09"},{"id":"P7-101","part":"7","difficulty":"600","category":"廣告","prompt":"How long is the course?","choices":["Four weeks","Four days","Two months","One year"],"answer":0,"explanation":"廣告說 in four weeks。","translation":"","passage":"BrightPath Language Center\nSummer Business English Intensive\n\nImprove presentation, negotiation, and e-mail writing skills in four weeks. Classes meet Monday through Thursday from 6:30 to 8:30 P.M. All course materials are included. Register by May 20 to receive a ten percent early-registration discount. A free placement interview is required before the first class.","audioText":"","tags":["reading"],"groupId":"P7-R10"},{"id":"P7-102","part":"7","difficulty":"600","category":"廣告","prompt":"How can a student receive a discount?","choices":["Register by May 20","Attend every evening","Bring personal materials","Skip the placement interview"],"answer":0,"explanation":"五月二十日前報名可享早鳥優惠。","translation":"","passage":"BrightPath Language Center\nSummer Business English Intensive\n\nImprove presentation, negotiation, and e-mail writing skills in four weeks. Classes meet Monday through Thursday from 6:30 to 8:30 P.M. All course materials are included. Register by May 20 to receive a ten percent early-registration discount. A free placement interview is required before the first class.","audioText":"","tags":["reading"],"groupId":"P7-R10"},{"id":"P7-111","part":"7","difficulty":"800","category":"備忘錄","prompt":"Which transaction now requires special approval?","choices":["A refund over $300","Every product exchange","A purchase made online","A return made on Friday"],"answer":0,"explanation":"超過 300 美元的退款需區域經理核准。","translation":"","passage":"To: Regional Store Managers\nFrom: Elaine Ford, Operations Director\nSubject: Revised Return Procedure\n\nEffective immediately, refunds for purchases over $300 require approval from a regional manager. Store employees should continue to process exchanges according to the existing policy. A revised return form has been uploaded to the company intranet. Please destroy any unused copies of the previous form by Friday.","audioText":"","tags":["reading"],"groupId":"P7-R11"},{"id":"P7-112","part":"7","difficulty":"800","category":"備忘錄","prompt":"What should employees do by Friday?","choices":["Discard old return forms","Upload customer receipts","Change the exchange policy","Contact every regional manager"],"answer":0,"explanation":"必須銷毀舊版未使用表格。","translation":"","passage":"To: Regional Store Managers\nFrom: Elaine Ford, Operations Director\nSubject: Revised Return Procedure\n\nEffective immediately, refunds for purchases over $300 require approval from a regional manager. Store employees should continue to process exchanges according to the existing policy. A revised return form has been uploaded to the company intranet. Please destroy any unused copies of the previous form by Friday.","audioText":"","tags":["reading"],"groupId":"P7-R11"},{"id":"P7-121","part":"7","difficulty":"800","category":"文章","prompt":"What happened on Saturday?","choices":["A theater reopened","A director was hired","A renovation began","A ticket counter closed"],"answer":0,"explanation":"第一句說劇院於星期六重新開幕。","translation":"","passage":"After a six-month renovation, the historic Milton Theater reopened on Saturday. Improvements include wider seats, upgraded sound equipment, and a new ticket counter. Theater director Paul Ingram said that most of the building's original interior design was preserved. The theater will present local productions during the week and touring performances on weekends.","audioText":"","tags":["reading"],"groupId":"P7-R12"},{"id":"P7-122","part":"7","difficulty":"800","category":"文章","prompt":"What was mostly preserved?","choices":["The original interior design","The old sound equipment","The previous seating arrangement","The weekend schedule"],"answer":0,"explanation":"館長說大部分原始室內設計獲得保留。","translation":"","passage":"After a six-month renovation, the historic Milton Theater reopened on Saturday. Improvements include wider seats, upgraded sound equipment, and a new ticket counter. Theater director Paul Ingram said that most of the building's original interior design was preserved. The theater will present local productions during the week and touring performances on weekends.","audioText":"","tags":["reading"],"groupId":"P7-R12"},{"id":"P7-131","part":"7","difficulty":"800","category":"雙篇閱讀","prompt":"Why will Route 18 skip Central Market?","choices":["Road construction","A public holiday","A vehicle inspection","A market event"],"answer":0,"explanation":"公告說明原因是道路施工。","translation":"","passage":"ONLINE NOTICE\nDue to road construction, City Bus Route 18 will not stop at Central Market from July 3 through July 7. Passengers should use the temporary stop on Oak Street, one block east of the market.\n\nTEXT MESSAGE\nMia: I was going to take Route 18 to meet you at Central Market tomorrow, but the stop is closed.\nJon: Get off at the temporary Oak Street stop. I'll meet you there at 1:15. It's next to a pharmacy.","audioText":"","tags":["reading"],"groupId":"P7-R13"},{"id":"P7-132","part":"7","difficulty":"800","category":"雙篇閱讀","prompt":"Where will Jon meet Mia?","choices":["At the Oak Street stop","Inside Central Market","At the bus company's office","One block west of the market"],"answer":0,"explanation":"簡訊約在 Oak Street 臨時站牌見面。","translation":"","passage":"ONLINE NOTICE\nDue to road construction, City Bus Route 18 will not stop at Central Market from July 3 through July 7. Passengers should use the temporary stop on Oak Street, one block east of the market.\n\nTEXT MESSAGE\nMia: I was going to take Route 18 to meet you at Central Market tomorrow, but the stop is closed.\nJon: Get off at the temporary Oak Street stop. I'll meet you there at 1:15. It's next to a pharmacy.","audioText":"","tags":["reading"],"groupId":"P7-R13"},{"id":"P2-031","part":"2","difficulty":"400","category":"應答","prompt":"Choose the best response.","choices":["In the tray beside my desk.","They were completed yesterday.","About five pages."],"answer":0,"explanation":"Where 問放置地點。","translation":"我應該把填好的表格放在哪裡？","passage":"","audioText":"Where should I leave the completed forms?","audioTranslation":"我應該把填好的表格放在哪裡？","answerTranslation":"放在我桌邊的文件盤裡。","tags":["listening","response"]},{"id":"P2-032","part":"2","difficulty":"600","category":"應答","prompt":"Choose the best response.","choices":["I can ask the project manager.","The deadline was printed clearly.","We submitted three copies."],"answer":0,"explanation":"對能否延期的詢問，最自然的回應是表示會向負責人確認。","translation":"有可能延長截止期限嗎？","passage":"","audioText":"Would it be possible to extend the deadline?","audioTranslation":"有可能延長截止期限嗎？","answerTranslation":"我可以詢問專案經理。","tags":["listening","response"]},{"id":"P2-033","part":"2","difficulty":"400","category":"應答","prompt":"Choose the best response.","choices":["The finance director did.","It was revised twice.","For the online campaign."],"answer":0,"explanation":"Who 問執行核准的人。","translation":"誰核准了修訂後的廣告預算？","passage":"","audioText":"Who approved the revised advertising budget?","audioTranslation":"誰核准了修訂後的廣告預算？","answerTranslation":"財務主管核准的。","tags":["listening","response"]},{"id":"P2-034","part":"2","difficulty":"600","category":"應答","prompt":"Choose the best response.","choices":["The supplier shipped it to the wrong address.","It fits this machine.","We ordered two parts."],"answer":0,"explanation":"Why 問尚未抵達的原因。","translation":"替換零件為什麼還沒到？","passage":"","audioText":"Why hasn't the replacement part arrived?","audioTranslation":"替換零件為什麼還沒到？","answerTranslation":"供應商把它寄到錯誤地址了。","tags":["listening","response"]},{"id":"P2-035","part":"2","difficulty":"400","category":"應答","prompt":"Choose the best response.","choices":["An additional twelve dollars.","It arrives tomorrow morning.","At the service counter."],"answer":0,"explanation":"How much 問價格。","translation":"快速配送服務要多少錢？","passage":"","audioText":"How much does the express delivery service cost?","audioTranslation":"快速配送服務要多少錢？","answerTranslation":"另外加收十二美元。","tags":["listening","response"]},{"id":"P2-036","part":"2","difficulty":"600","category":"應答","prompt":"Choose the best response.","choices":["Yes, if we start before lunch.","The contract has ten pages.","I reviewed the schedule."],"answer":0,"explanation":"Yes/No 問時間是否足夠，回答條件最自然。","translation":"今天有足夠時間審查合約嗎？","passage":"","audioText":"Is there enough time to review the contract today?","audioTranslation":"今天有足夠時間審查合約嗎？","answerTranslation":"有，只要我們午餐前開始。","tags":["listening","response"]},{"id":"P2-037","part":"2","difficulty":"600","category":"應答","prompt":"Choose the best response.","choices":["I tried, but it was already booked.","The conference lasted two hours.","The room is on the fifth floor."],"answer":0,"explanation":"否定疑問句依事實回答，並說明沒有訂到的原因。","translation":"你不是已經預訂會議室了嗎？","passage":"","audioText":"Didn't you reserve the conference room?","audioTranslation":"你不是已經預訂會議室了嗎？","answerTranslation":"我試過了，但它已經被訂走了。","tags":["listening","response"]},{"id":"P2-038","part":"2","difficulty":"400","category":"應答","prompt":"Choose the best response.","choices":["On the first Monday in June.","In the human resources office.","There are four interns."],"answer":0,"explanation":"When 問開始日期。","translation":"新實習生什麼時候開始上班？","passage":"","audioText":"When are the new interns starting?","audioTranslation":"新實習生什麼時候開始上班？","answerTranslation":"六月的第一個星期一。","tags":["listening","response"]},{"id":"P2-039","part":"2","difficulty":"600","category":"應答","prompt":"Choose the best response.","choices":["Thanks, that would be useful.","Prices rose last month.","The list is alphabetical."],"answer":0,"explanation":"Why don't I...? 在此表示主動提議協助，應接受或婉拒。","translation":"我把更新後的價目表寄給你好嗎？","passage":"","audioText":"Why don't I send you the updated price list?","audioTranslation":"我把更新後的價目表寄給你好嗎？","answerTranslation":"謝謝，那會很有用。","tags":["listening","response"]},{"id":"P2-040","part":"2","difficulty":"400","category":"應答","prompt":"Choose the best response.","choices":["The one on the far left.","At seven o'clock.","The restaurant is crowded."],"answer":0,"explanation":"Which elevator 問特定電梯。","translation":"哪一部電梯會到頂樓餐廳？","passage":"","audioText":"Which elevator goes to the rooftop restaurant?","audioTranslation":"哪一部電梯會到頂樓餐廳？","answerTranslation":"最左邊那一部。","tags":["listening","response"]},{"id":"P2-041","part":"2","difficulty":"600","category":"應答","prompt":"Choose the best response.","choices":["Sure, I'll call this afternoon.","The proposal is well written.","We received two packages."],"answer":0,"explanation":"Could you...? 是請求，應承諾採取行動。","translation":"你可以確認客戶是否收到我們的提案嗎？","passage":"","audioText":"Could you check whether the client received our proposal?","audioTranslation":"你可以確認客戶是否收到我們的提案嗎？","answerTranslation":"可以，我今天下午會打電話。","tags":["listening","response"]},{"id":"P2-042","part":"2","difficulty":"400","category":"應答","prompt":"Choose the best response.","choices":["A former colleague told me.","The interview is on Friday.","It is a full-time position."],"answer":0,"explanation":"How did you hear about...? 問資訊來源。","translation":"你是怎麼得知這個職缺的？","passage":"","audioText":"How did you hear about the job opening?","audioTranslation":"你是怎麼得知這個職缺的？","answerTranslation":"一位以前的同事告訴我的。","tags":["listening","response"]},{"id":"P2-043","part":"2","difficulty":"600","category":"應答","prompt":"Choose the best response.","choices":["Only the charts need to be in color.","The printer uses less paper.","I handed them out yesterday."],"answer":0,"explanation":"選擇如何列印，回應哪部分需要彩色最自然。","translation":"我們應該把講義印成彩色嗎？","passage":"","audioText":"Should we print the handouts in color?","audioTranslation":"我們應該把講義印成彩色嗎？","answerTranslation":"只有圖表需要彩色。","tags":["listening","response"]},{"id":"P2-044","part":"2","difficulty":"400","category":"應答","prompt":"Choose the best response.","choices":["At the reception desk.","The suitcase is very heavy.","They arrived by train."],"answer":0,"explanation":"Where 問寄放行李的地點。","translation":"客人可以把行李寄放在哪裡？","passage":"","audioText":"Where can guests store their luggage?","audioTranslation":"客人可以把行李寄放在哪裡？","answerTranslation":"在接待櫃台。","tags":["listening","response"]},{"id":"P2-045","part":"2","difficulty":"600","category":"應答","prompt":"Choose the best response.","choices":["No, it will continue for another hour.","The inspector signed the form.","Yes, the equipment is new."],"answer":0,"explanation":"尚未完成，並補充還需一小時。","translation":"維護檢查還沒結束嗎？","passage":"","audioText":"Hasn't the maintenance inspection finished yet?","audioTranslation":"維護檢查還沒結束嗎？","answerTranslation":"還沒，還會再持續一小時。","tags":["listening","response"]},{"id":"P2-046","part":"2","difficulty":"400","category":"應答","prompt":"Choose the best response.","choices":["Nearly sixty.","For two days.","In the training center."],"answer":0,"explanation":"How many 問人數。","translation":"有多少人報名工作坊？","passage":"","audioText":"How many people registered for the workshop?","audioTranslation":"有多少人報名工作坊？","answerTranslation":"將近六十人。","tags":["listening","response"]},{"id":"P2-047","part":"2","difficulty":"600","category":"應答","prompt":"Choose the best response.","choices":["An e-mail copy, please.","The payment was approved.","I copied the document."],"answer":0,"explanation":"選擇問句應直接選擇其中一項。","translation":"你想要紙本收據還是電子郵件副本？","passage":"","audioText":"Would you prefer a printed receipt or an e-mail copy?","audioTranslation":"你想要紙本收據還是電子郵件副本？","answerTranslation":"請寄電子郵件副本。","tags":["listening","response"]},{"id":"P2-048","part":"2","difficulty":"400","category":"應答","prompt":"Choose the best response.","choices":["The floor is being repaired.","It closes at six.","Use the front entrance."],"answer":0,"explanation":"Why 問關閉原因。","translation":"正門為什麼關閉？","passage":"","audioText":"Why is the front entrance closed?","audioTranslation":"正門為什麼關閉？","answerTranslation":"地板正在維修。","tags":["listening","response"]},{"id":"P2-049","part":"2","difficulty":"600","category":"應答","prompt":"Choose the best response.","choices":["I'm sorry, cards can't be shared.","The card reader is downstairs.","I borrowed a laptop."],"answer":0,"explanation":"對借用門禁卡的請求，依安全規定婉拒。","translation":"我可以借一下你的門禁卡嗎？","passage":"","audioText":"May I borrow your access card for a moment?","audioTranslation":"我可以借一下你的門禁卡嗎？","answerTranslation":"抱歉，門禁卡不能共用。","tags":["listening","response"]},{"id":"P2-050","part":"2","difficulty":"400","category":"應答","prompt":"Choose the best response.","choices":["At eight thirty.","Near the main lobby.","The representative was helpful."],"answer":0,"explanation":"What time 問營業時間。","translation":"客服櫃台幾點開始服務？","passage":"","audioText":"What time does the customer service desk open?","audioTranslation":"客服櫃台幾點開始服務？","answerTranslation":"八點三十分。","tags":["listening","response"]},{"id":"P3-G09-Q1","part":"3","difficulty":"600","category":"員工訓練","prompt":"What are the speakers discussing?","choices":["Adding another training session","Canceling a customer order","Moving to a new office","Hiring a workshop instructor"],"answer":0,"explanation":"他們討論增加第二場訓練。","translation":"","passage":"","audioText":"W: The customer service workshop is almost full. Should we add a second session next week? M: Yes. Wednesday afternoon is open in the training room. W: Great. I'll ask Human Resources to send another announcement.","audioTranslation":"女：客服工作坊幾乎額滿了。我們是否應在下週增加第二場？男：好。訓練室星期三下午有空。女：很好。我會請人力資源部再發一則公告。","groupId":"P3-G09","tags":["conversation","listening"]},{"id":"P3-G09-Q2","part":"3","difficulty":"600","category":"員工訓練","prompt":"When is the training room available?","choices":["Wednesday afternoon","Monday morning","Friday evening","Saturday afternoon"],"answer":0,"explanation":"男子說星期三下午有空。","translation":"","passage":"","audioText":"W: The customer service workshop is almost full. Should we add a second session next week? M: Yes. Wednesday afternoon is open in the training room. W: Great. I'll ask Human Resources to send another announcement.","audioTranslation":"女：客服工作坊幾乎額滿了。我們是否應在下週增加第二場？男：好。訓練室星期三下午有空。女：很好。我會請人力資源部再發一則公告。","groupId":"P3-G09","tags":["conversation","listening"]},{"id":"P3-G09-Q3","part":"3","difficulty":"600","category":"員工訓練","prompt":"What will the woman ask Human Resources to do?","choices":["Send another announcement","Reserve a restaurant","Interview a candidate","Prepare customer invoices"],"answer":0,"explanation":"女子會請人資再發公告。","translation":"","passage":"","audioText":"W: The customer service workshop is almost full. Should we add a second session next week? M: Yes. Wednesday afternoon is open in the training room. W: Great. I'll ask Human Resources to send another announcement.","audioTranslation":"女：客服工作坊幾乎額滿了。我們是否應在下週增加第二場？男：好。訓練室星期三下午有空。女：很好。我會請人力資源部再發一則公告。","groupId":"P3-G09","tags":["conversation","listening"]},{"id":"P3-G10-Q1","part":"3","difficulty":"800","category":"餐廳設備","prompt":"What problem is mentioned?","choices":["A refrigerator is not cold enough","A bakery order is late","A kitchen employee is absent","A restaurant is overcrowded"],"answer":0,"explanation":"冰箱無法維持正確溫度。","translation":"","passage":"","audioText":"M: The refrigerator in the restaurant kitchen isn't maintaining the correct temperature. W: I called the service company, but their technician cannot come until Friday. M: Then we should move the dairy products to the smaller refrigerator in the bakery.","audioTranslation":"男：餐廳廚房的冰箱無法維持正確溫度。女：我已聯絡維修公司，但技術人員要到星期五才能來。男：那我們應該把乳製品移到烘焙區較小的冰箱。","groupId":"P3-G10","tags":["conversation","listening"]},{"id":"P3-G10-Q2","part":"3","difficulty":"800","category":"餐廳設備","prompt":"When can the technician come?","choices":["On Friday","This afternoon","On Monday","Tomorrow morning"],"answer":0,"explanation":"技術人員星期五才能來。","translation":"","passage":"","audioText":"M: The refrigerator in the restaurant kitchen isn't maintaining the correct temperature. W: I called the service company, but their technician cannot come until Friday. M: Then we should move the dairy products to the smaller refrigerator in the bakery.","audioTranslation":"男：餐廳廚房的冰箱無法維持正確溫度。女：我已聯絡維修公司，但技術人員要到星期五才能來。男：那我們應該把乳製品移到烘焙區較小的冰箱。","groupId":"P3-G10","tags":["conversation","listening"]},{"id":"P3-G10-Q3","part":"3","difficulty":"800","category":"餐廳設備","prompt":"What does the man suggest?","choices":["Moving some food","Buying new equipment immediately","Closing the bakery","Canceling a delivery"],"answer":0,"explanation":"男子建議移動乳製品。","translation":"","passage":"","audioText":"M: The refrigerator in the restaurant kitchen isn't maintaining the correct temperature. W: I called the service company, but their technician cannot come until Friday. M: Then we should move the dairy products to the smaller refrigerator in the bakery.","audioTranslation":"男：餐廳廚房的冰箱無法維持正確溫度。女：我已聯絡維修公司，但技術人員要到星期五才能來。男：那我們應該把乳製品移到烘焙區較小的冰箱。","groupId":"P3-G10","tags":["conversation","listening"]},{"id":"P3-G11-Q1","part":"3","difficulty":"600","category":"差旅安排","prompt":"What are the speakers arranging?","choices":["A flight","A dinner menu","A product delivery","A training schedule"],"answer":0,"explanation":"對話在比較飛往大阪的班機。","translation":"","passage":"","audioText":"W: I found a morning flight to Osaka, but it leaves at six ten. M: That's early. Is there a later flight that arrives before the conference dinner? W: Yes, one leaves at nine and arrives at noon. It costs thirty dollars more.","audioTranslation":"女：我找到一班早上飛往大阪的班機，但它六點十分起飛。男：那很早。有沒有較晚、又能在會議晚宴前抵達的班機？女：有，一班九點起飛、中午抵達，但貴三十美元。","groupId":"P3-G11","tags":["conversation","listening"]},{"id":"P3-G11-Q2","part":"3","difficulty":"600","category":"差旅安排","prompt":"Why does the man prefer a later flight?","choices":["The first flight leaves very early","He needs a cheaper ticket","The conference has been canceled","He wants to arrive after dinner"],"answer":0,"explanation":"六點十分太早。","translation":"","passage":"","audioText":"W: I found a morning flight to Osaka, but it leaves at six ten. M: That's early. Is there a later flight that arrives before the conference dinner? W: Yes, one leaves at nine and arrives at noon. It costs thirty dollars more.","audioTranslation":"女：我找到一班早上飛往大阪的班機，但它六點十分起飛。男：那很早。有沒有較晚、又能在會議晚宴前抵達的班機？女：有，一班九點起飛、中午抵達，但貴三十美元。","groupId":"P3-G11","tags":["conversation","listening"]},{"id":"P3-G11-Q3","part":"3","difficulty":"600","category":"差旅安排","prompt":"What is said about the nine o'clock flight?","choices":["It costs more","It arrives in the evening","It has no available seats","It requires two transfers"],"answer":0,"explanation":"該班機多三十美元。","translation":"","passage":"","audioText":"W: I found a morning flight to Osaka, but it leaves at six ten. M: That's early. Is there a later flight that arrives before the conference dinner? W: Yes, one leaves at nine and arrives at noon. It costs thirty dollars more.","audioTranslation":"女：我找到一班早上飛往大阪的班機，但它六點十分起飛。男：那很早。有沒有較晚、又能在會議晚宴前抵達的班機？女：有，一班九點起飛、中午抵達，但貴三十美元。","groupId":"P3-G11","tags":["conversation","listening"]},{"id":"P3-G12-Q1","part":"3","difficulty":"800","category":"網站更新","prompt":"What issue are the speakers discussing?","choices":["Blurry website images","Incorrect product prices","A delayed shipment","A missing customer review"],"answer":0,"explanation":"產品照片在手機顯示模糊。","translation":"","passage":"","audioText":"M: The product photos on our website look blurry on mobile phones. W: I can resize the image files this afternoon. We should also test the pages on several screen sizes. M: Good. Please finish before the online sale begins tomorrow.","audioTranslation":"男：我們網站上的產品照片在手機上看起來很模糊。女：我今天下午可以重新調整圖片檔案大小。我們也應該在多種螢幕尺寸上測試頁面。男：很好。請在明天網路促銷開始前完成。","groupId":"P3-G12","tags":["conversation","listening"]},{"id":"P3-G12-Q2","part":"3","difficulty":"800","category":"網站更新","prompt":"What does the woman propose doing?","choices":["Testing different screen sizes","Replacing all products","Hiring a photographer today","Closing the website"],"answer":0,"explanation":"她提議測試多種螢幕尺寸。","translation":"","passage":"","audioText":"M: The product photos on our website look blurry on mobile phones. W: I can resize the image files this afternoon. We should also test the pages on several screen sizes. M: Good. Please finish before the online sale begins tomorrow.","audioTranslation":"男：我們網站上的產品照片在手機上看起來很模糊。女：我今天下午可以重新調整圖片檔案大小。我們也應該在多種螢幕尺寸上測試頁面。男：很好。請在明天網路促銷開始前完成。","groupId":"P3-G12","tags":["conversation","listening"]},{"id":"P3-G12-Q3","part":"3","difficulty":"800","category":"網站更新","prompt":"When should the work be completed?","choices":["Before tomorrow's online sale","By the end of next month","After a customer survey","Before today's lunch"],"answer":0,"explanation":"男子要求在明天促銷前完成。","translation":"","passage":"","audioText":"M: The product photos on our website look blurry on mobile phones. W: I can resize the image files this afternoon. We should also test the pages on several screen sizes. M: Good. Please finish before the online sale begins tomorrow.","audioTranslation":"男：我們網站上的產品照片在手機上看起來很模糊。女：我今天下午可以重新調整圖片檔案大小。我們也應該在多種螢幕尺寸上測試頁面。男：很好。請在明天網路促銷開始前完成。","groupId":"P3-G12","tags":["conversation","listening"]},{"id":"P4-G07-Q1","part":"4","difficulty":"600","category":"辦公室公告","prompt":"What will happen tomorrow?","choices":["The water will be turned off temporarily","The fourth floor will close permanently","Employees will move offices","A new restroom will open"],"answer":0,"explanation":"明天會暫時停水。","translation":"","passage":"","audioText":"Employees on the fourth floor should be aware that the water supply will be turned off tomorrow from ten A.M. until noon while a pipe is replaced. Restrooms on the third and fifth floors will remain available. Please direct any questions to the facilities department.","audioTranslation":"四樓員工請注意，因更換水管，明日上午十點至中午將暫停供水。三樓與五樓的洗手間仍可使用。如有任何問題，請洽設施管理部門。","groupId":"P4-G07","tags":["talk","listening"]},{"id":"P4-G07-Q2","part":"4","difficulty":"600","category":"辦公室公告","prompt":"Which restrooms will remain available?","choices":["Those on the third and fifth floors","Only those on the fourth floor","Those near the cafeteria","Only those in the lobby"],"answer":0,"explanation":"三樓與五樓可使用。","translation":"","passage":"","audioText":"Employees on the fourth floor should be aware that the water supply will be turned off tomorrow from ten A.M. until noon while a pipe is replaced. Restrooms on the third and fifth floors will remain available. Please direct any questions to the facilities department.","audioTranslation":"四樓員工請注意，因更換水管，明日上午十點至中午將暫停供水。三樓與五樓的洗手間仍可使用。如有任何問題，請洽設施管理部門。","groupId":"P4-G07","tags":["talk","listening"]},{"id":"P4-G07-Q3","part":"4","difficulty":"600","category":"辦公室公告","prompt":"Whom should employees contact with questions?","choices":["The facilities department","The accounting department","The security office","The cafeteria manager"],"answer":0,"explanation":"問題請洽設施部門。","translation":"","passage":"","audioText":"Employees on the fourth floor should be aware that the water supply will be turned off tomorrow from ten A.M. until noon while a pipe is replaced. Restrooms on the third and fifth floors will remain available. Please direct any questions to the facilities department.","audioTranslation":"四樓員工請注意，因更換水管，明日上午十點至中午將暫停供水。三樓與五樓的洗手間仍可使用。如有任何問題，請洽設施管理部門。","groupId":"P4-G07","tags":["talk","listening"]},{"id":"P4-G08-Q1","part":"4","difficulty":"800","category":"商務活動","prompt":"Where will the keynote speech take place?","choices":["In the Grand Hall","In a hotel restaurant","In the registration office","In a small workshop room"],"answer":0,"explanation":"主題演講在大禮堂。","translation":"","passage":"","audioText":"Thank you for attending the Regional Entrepreneurs Conference. The keynote speech will begin in the Grand Hall at nine thirty. After the speech, participants may choose from three smaller workshops. A schedule and room map are included inside your name badge holder.","audioTranslation":"感謝各位參加區域創業家會議。主題演講將於九點三十分在大禮堂開始。演講結束後，參加者可從三場小型工作坊中選擇。時程表與會議室地圖放在名牌套內。","groupId":"P4-G08","tags":["talk","listening"]},{"id":"P4-G08-Q2","part":"4","difficulty":"800","category":"商務活動","prompt":"What may participants do after the speech?","choices":["Attend one of three workshops","Leave for the airport","Collect a refund","Meet the keynote speaker privately"],"answer":0,"explanation":"之後可選擇三場工作坊之一。","translation":"","passage":"","audioText":"Thank you for attending the Regional Entrepreneurs Conference. The keynote speech will begin in the Grand Hall at nine thirty. After the speech, participants may choose from three smaller workshops. A schedule and room map are included inside your name badge holder.","audioTranslation":"感謝各位參加區域創業家會議。主題演講將於九點三十分在大禮堂開始。演講結束後，參加者可從三場小型工作坊中選擇。時程表與會議室地圖放在名牌套內。","groupId":"P4-G08","tags":["talk","listening"]},{"id":"P4-G08-Q3","part":"4","difficulty":"800","category":"商務活動","prompt":"Where can participants find a room map?","choices":["Inside the name badge holder","At the parking entrance","On the conference website only","Under their seats"],"answer":0,"explanation":"地圖放在名牌套內。","translation":"","passage":"","audioText":"Thank you for attending the Regional Entrepreneurs Conference. The keynote speech will begin in the Grand Hall at nine thirty. After the speech, participants may choose from three smaller workshops. A schedule and room map are included inside your name badge holder.","audioTranslation":"感謝各位參加區域創業家會議。主題演講將於九點三十分在大禮堂開始。演講結束後，參加者可從三場小型工作坊中選擇。時程表與會議室地圖放在名牌套內。","groupId":"P4-G08","tags":["talk","listening"]},{"id":"P4-G09-Q1","part":"4","difficulty":"600","category":"商店語音","prompt":"When is the showroom closed?","choices":["On Sunday","On Saturday","On Monday","Every afternoon"],"answer":0,"explanation":"營業日為週一至週六，因此週日休息。","translation":"","passage":"","audioText":"Thank you for calling Martin's Furniture. Our showroom is open Monday through Saturday from nine to six. For information about an existing delivery, press one. To schedule a design consultation, press two. To speak with a billing representative, remain on the line.","audioTranslation":"感謝致電 Martin's Furniture。我們的展示間週一至週六上午九點到下午六點營業。查詢既有配送請按一；預約設計諮詢請按二；如需帳務人員服務，請不要掛斷。","groupId":"P4-G09","tags":["talk","listening"]},{"id":"P4-G09-Q2","part":"4","difficulty":"600","category":"商店語音","prompt":"What should callers do to arrange a design consultation?","choices":["Press two","Press one","Visit the showroom","Remain on the line"],"answer":0,"explanation":"設計諮詢按二。","translation":"","passage":"","audioText":"Thank you for calling Martin's Furniture. Our showroom is open Monday through Saturday from nine to six. For information about an existing delivery, press one. To schedule a design consultation, press two. To speak with a billing representative, remain on the line.","audioTranslation":"感謝致電 Martin's Furniture。我們的展示間週一至週六上午九點到下午六點營業。查詢既有配送請按一；預約設計諮詢請按二；如需帳務人員服務，請不要掛斷。","groupId":"P4-G09","tags":["talk","listening"]},{"id":"P4-G09-Q3","part":"4","difficulty":"600","category":"商店語音","prompt":"Why should a caller remain on the line?","choices":["To speak with a billing representative","To change a delivery address","To hear store hours again","To order new furniture"],"answer":0,"explanation":"留在線上可與帳務人員通話。","translation":"","passage":"","audioText":"Thank you for calling Martin's Furniture. Our showroom is open Monday through Saturday from nine to six. For information about an existing delivery, press one. To schedule a design consultation, press two. To speak with a billing representative, remain on the line.","audioTranslation":"感謝致電 Martin's Furniture。我們的展示間週一至週六上午九點到下午六點營業。查詢既有配送請按一；預約設計諮詢請按二；如需帳務人員服務，請不要掛斷。","groupId":"P4-G09","tags":["talk","listening"]},{"id":"P4-G10-Q1","part":"4","difficulty":"800","category":"機場公告","prompt":"Where should passengers go?","choices":["Gate 16","Gate 20","The baggage office","The ticket counter"],"answer":0,"explanation":"乘客應前往十六號登機門。","translation":"","passage":"","audioText":"Passengers traveling on Flight 482 to Vancouver should proceed to Gate 16. Boarding will begin at five forty instead of five twenty because the aircraft arrived late. Passengers requiring assistance may speak with an agent at the service desk beside the gate.","audioTranslation":"搭乘 482 班機前往溫哥華的旅客請前往十六號登機門。由於飛機抵達延誤，登機時間將由五點二十分改為五點四十分。需要協助的旅客可洽登機門旁服務櫃台的人員。","groupId":"P4-G10","tags":["talk","listening"]},{"id":"P4-G10-Q2","part":"4","difficulty":"800","category":"機場公告","prompt":"Why will boarding begin late?","choices":["The aircraft arrived late","The weather is severe","The gate is being repaired","The crew is in a meeting"],"answer":0,"explanation":"因為飛機晚到。","translation":"","passage":"","audioText":"Passengers traveling on Flight 482 to Vancouver should proceed to Gate 16. Boarding will begin at five forty instead of five twenty because the aircraft arrived late. Passengers requiring assistance may speak with an agent at the service desk beside the gate.","audioTranslation":"搭乘 482 班機前往溫哥華的旅客請前往十六號登機門。由於飛機抵達延誤，登機時間將由五點二十分改為五點四十分。需要協助的旅客可洽登機門旁服務櫃台的人員。","groupId":"P4-G10","tags":["talk","listening"]},{"id":"P4-G10-Q3","part":"4","difficulty":"800","category":"機場公告","prompt":"Where can passengers request assistance?","choices":["At a service desk beside the gate","At the parking office","Inside the aircraft","At the baggage carousel"],"answer":0,"explanation":"可洽登機門旁服務櫃台。","translation":"","passage":"","audioText":"Passengers traveling on Flight 482 to Vancouver should proceed to Gate 16. Boarding will begin at five forty instead of five twenty because the aircraft arrived late. Passengers requiring assistance may speak with an agent at the service desk beside the gate.","audioTranslation":"搭乘 482 班機前往溫哥華的旅客請前往十六號登機門。由於飛機抵達延誤，登機時間將由五點二十分改為五點四十分。需要協助的旅客可洽登機門旁服務櫃台的人員。","groupId":"P4-G10","tags":["talk","listening"]},{"id":"P5-081","part":"5","difficulty":"600","category":"介系詞","prompt":"The training manual is divided _____ five sections.","choices":["into","among","between","through"],"answer":0,"explanation":"divide A into B 表示把 A 分成 B。","translation":"這本訓練手冊分成五個部分。","passage":"","audioText":"","tags":["reading","grammar"]},{"id":"P5-082","part":"5","difficulty":"600","category":"固定搭配","prompt":"The proposed schedule is acceptable _____ all department managers.","choices":["to","with","for","of"],"answer":0,"explanation":"be acceptable to someone 表示某人可接受。","translation":"所提時程為所有部門經理所接受。","passage":"","audioText":"","tags":["reading","grammar"]},{"id":"P5-083","part":"5","difficulty":"800","category":"分詞","prompt":"All invoices _____ after the deadline will be processed next month.","choices":["receive","received","receiving","to receive"],"answer":1,"explanation":"invoices 與 receive 是被動關係，用過去分詞。","translation":"截止期限後收到的所有發票將於下月處理。","passage":"","audioText":"","tags":["reading","grammar"]},{"id":"P5-084","part":"5","difficulty":"600","category":"副詞子句","prompt":"Please notify the receptionist _____ you expect a visitor.","choices":["if","despite","during","because of"],"answer":0,"explanation":"if + 子句表示條件。","translation":"若你預計有訪客，請通知接待人員。","passage":"","audioText":"","tags":["reading","grammar"]},{"id":"P5-085","part":"5","difficulty":"800","category":"倒裝","prompt":"Only after the software was updated _____ the error disappear.","choices":["did","was","had","has"],"answer":0,"explanation":"Only after 置於句首時主句倒裝，用 did + 原形。","translation":"直到軟體更新後，錯誤才消失。","passage":"","audioText":"","tags":["reading","grammar"]},{"id":"P5-086","part":"5","difficulty":"400","category":"商務字彙","prompt":"The hotel will _____ guests for any charges made in error.","choices":["reimburse","recruit","reserve","relocate"],"answer":0,"explanation":"reimburse someone for charges 表示償還誤收費用。","translation":"飯店將退還顧客任何誤收的費用。","passage":"","audioText":"","tags":["reading","grammar"]},{"id":"P5-087","part":"5","difficulty":"600","category":"詞性","prompt":"The expansion project requires careful financial _____.","choices":["plan","planned","planning","planner"],"answer":2,"explanation":"financial planning 是固定名詞搭配。","translation":"擴建計畫需要審慎的財務規劃。","passage":"","audioText":"","tags":["reading","grammar"]},{"id":"P5-088","part":"5","difficulty":"600","category":"代名詞","prompt":"The two proposals are similar, but the second is less expensive than _____.","choices":["one","ones","the other","another"],"answer":2,"explanation":"兩者中的另一個用 the other。","translation":"兩份提案相似，但第二份比另一份便宜。","passage":"","audioText":"","tags":["reading","grammar"]},{"id":"P6-025","part":"6","difficulty":"600","category":"辦公室通知","prompt":"Choose the best word or phrase for the blank.","choices":["before","among","through","unless"],"answer":0,"explanation":"before + V-ing 表示在抵達前。","translation":"","passage":"The employee cafeteria will introduce a new mobile ordering system on Monday. Staff members can use the application to place orders _____ arriving at the cafeteria.","audioText":"","tags":["text-completion"],"groupId":"P6-G07"},{"id":"P6-026","part":"6","difficulty":"600","category":"辦公室通知","prompt":"Choose the best word or phrase for the blank.","choices":["receive","received","receiving","receipt"],"answer":1,"explanation":"訂單是被收到，用被動 are received。","translation":"","passage":"The employee cafeteria will introduce a new mobile ordering system on Monday. Orders will be prepared in the sequence in which they are _____.","audioText":"","tags":["text-completion"],"groupId":"P6-G07"},{"id":"P6-027","part":"6","difficulty":"800","category":"辦公室通知","prompt":"Choose the best word or phrase for the blank.","choices":["However","Therefore","For example","Likewise"],"answer":0,"explanation":"雖推出行動點餐，但仍收現金，語意轉折。","translation":"","passage":"The employee cafeteria will introduce a new mobile ordering system on Monday. _____, cash payments will still be accepted at the counter.","audioText":"","tags":["text-completion"],"groupId":"P6-G07"},{"id":"P6-028","part":"6","difficulty":"600","category":"辦公室通知","prompt":"Choose the best word or phrase for the blank.","choices":["available","availability","availably","avail"],"answer":0,"explanation":"be available on 是正確結構。","translation":"","passage":"The employee cafeteria will introduce a new mobile ordering system on Monday. Instructions for downloading the application are _____ on the employee portal.","audioText":"","tags":["text-completion"],"groupId":"P6-G07"},{"id":"P7-14-Q1","part":"7","difficulty":"600","category":"活動公告","prompt":"What service is being offered?","choices":["Free technology assistance","Discounted computer sales","Professional photography","A full-day training course"],"answer":0,"explanation":"活動提供免費科技諮詢。","translation":"","passage":"Community Technology Day\n\nThe Westfield Community Center will offer free thirty-minute consultations on Saturday, August 9. Volunteers will help residents set up e-mail accounts, install security updates, and organize digital photographs. Appointments are recommended, but walk-in visitors will be assisted if time permits. Participants should bring their own devices and charging cables.","audioText":"","tags":["reading"],"groupId":"P7-R14"},{"id":"P7-14-Q2","part":"7","difficulty":"600","category":"活動公告","prompt":"What should participants bring?","choices":["Their devices and charging cables","Printed photographs only","A membership payment","Their own desks"],"answer":0,"explanation":"文末要求攜帶裝置與充電線。","translation":"","passage":"Community Technology Day\n\nThe Westfield Community Center will offer free thirty-minute consultations on Saturday, August 9. Volunteers will help residents set up e-mail accounts, install security updates, and organize digital photographs. Appointments are recommended, but walk-in visitors will be assisted if time permits. Participants should bring their own devices and charging cables.","audioText":"","tags":["reading"],"groupId":"P7-R14"},{"id":"P7-15-Q1","part":"7","difficulty":"800","category":"公司電子郵件","prompt":"What has changed about the review?","choices":["Its location","Its starting time","Its client","Its purpose"],"answer":0,"explanation":"時間不變，地點改到製造廠。","translation":"","passage":"From: Victor Chen\nTo: Product Development Team\nSubject: Prototype Review\n\nThe client has asked us to move Friday's prototype review from the downtown office to its manufacturing facility. The meeting will still begin at 10 A.M., but security registration may take up to twenty minutes. Please arrive by 9:30 and bring a government-issued photo ID. I have attached a map showing the visitor entrance and parking area.","audioText":"","tags":["reading"],"groupId":"P7-R15"},{"id":"P7-15-Q2","part":"7","difficulty":"800","category":"公司電子郵件","prompt":"Why should attendees arrive by 9:30?","choices":["Security registration may take time","The meeting begins at 9:30","Parking closes at ten","They must inspect the prototype alone"],"answer":0,"explanation":"安全登記可能需要二十分鐘。","translation":"","passage":"From: Victor Chen\nTo: Product Development Team\nSubject: Prototype Review\n\nThe client has asked us to move Friday's prototype review from the downtown office to its manufacturing facility. The meeting will still begin at 10 A.M., but security registration may take up to twenty minutes. Please arrive by 9:30 and bring a government-issued photo ID. I have attached a map showing the visitor entrance and parking area.","audioText":"","tags":["reading"],"groupId":"P7-R15"},{"id":"P2-051","part":"2","difficulty":"400","category":"應答","prompt":"Choose the best response.","choices":["Behind the main building.","The visitor arrived early.","Parking is free today."],"answer":0,"explanation":"Where 問地點。","translation":"訪客停車區在哪裡？","passage":"","audioText":"Where is the visitor parking area?","audioTranslation":"訪客停車區在哪裡？","answerTranslation":"在主建築後方。","tags":["listening","response"]},{"id":"P2-052","part":"2","difficulty":"600","category":"應答","prompt":"Choose the best response.","choices":["I should have time after lunch.","The estimate was accurate.","It costs about two hundred dollars."],"answer":0,"explanation":"Would you be able to...? 是請求，應說明能否完成。","translation":"你今天可以審查這份估價嗎？","passage":"","audioText":"Would you be able to review this estimate today?","audioTranslation":"你今天可以審查這份估價嗎？","answerTranslation":"午餐後我應該有時間。","tags":["listening","response"]},{"id":"P2-053","part":"2","difficulty":"400","category":"應答","prompt":"Choose the best response.","choices":["The digital marketing team.","It was updated yesterday.","On the company server."],"answer":0,"explanation":"Who 問負責人。","translation":"誰負責更新網站？","passage":"","audioText":"Who is responsible for updating the website?","audioTranslation":"誰負責更新網站？","answerTranslation":"數位行銷團隊。","tags":["listening","response"]},{"id":"P2-054","part":"2","difficulty":"600","category":"應答","prompt":"Choose the best response.","choices":["The payment information was incomplete.","Your membership lasts a year.","The form is at the front desk."],"answer":0,"explanation":"Why 問遭拒原因。","translation":"我的會員續約為什麼被拒絕？","passage":"","audioText":"Why was my membership renewal rejected?","audioTranslation":"我的會員續約為什麼被拒絕？","answerTranslation":"付款資料不完整。","tags":["listening","response"]},{"id":"P2-055","part":"2","difficulty":"400","category":"應答","prompt":"Choose the best response.","choices":["By the end of the day.","The repair shop is nearby.","Two machines were damaged."],"answer":0,"explanation":"How soon 問多久之內能完成。","translation":"修繕最快何時能完成？","passage":"","audioText":"How soon can the repairs be completed?","audioTranslation":"修繕最快何時能完成？","answerTranslation":"今天結束前。","tags":["listening","response"]},{"id":"P2-056","part":"2","difficulty":"600","category":"應答","prompt":"Choose the best response.","choices":["No, the final guest list just arrived.","The badge has a blue border.","They were on the conference table."],"answer":0,"explanation":"否定疑問句依事實回答，並解釋尚未列印的原因。","translation":"會議名牌還沒印好嗎？","passage":"","audioText":"Haven't the conference badges been printed?","audioTranslation":"會議名牌還沒印好嗎？","answerTranslation":"還沒，最終來賓名單才剛送達。","tags":["listening","response"]},{"id":"P2-057","part":"2","difficulty":"400","category":"應答","prompt":"Choose the best response.","choices":["The seventh floor.","The elevator is on the right.","There are twelve departments."],"answer":0,"explanation":"Which floor 問樓層。","translation":"法務部在哪一層？","passage":"","audioText":"Which floor is the legal department on?","audioTranslation":"法務部在哪一層？","answerTranslation":"七樓。","tags":["listening","response"]},{"id":"P2-058","part":"2","difficulty":"600","category":"應答","prompt":"Choose the best response.","choices":["Certainly, if you have the receipt.","The jacket is on sale.","The fitting room is occupied."],"answer":0,"explanation":"退換貨請求最自然的回應是說明可辦理的條件。","translation":"我可以把這件外套換成大一號嗎？","passage":"","audioText":"Could I exchange this jacket for a larger size?","audioTranslation":"我可以把這件外套換成大一號嗎？","answerTranslation":"可以，只要你有收據。","tags":["listening","response"]},{"id":"P3-G13-Q1","part":"3","difficulty":"600","category":"辦公室搬遷","prompt":"What will happen on Monday?","choices":["A team will move to another floor","A directory will be printed for sale","A delivery company will close","The lobby will be renovated"],"answer":0,"explanation":"會計團隊星期一搬到六樓。","translation":"","passage":"","audioText":"W: The accounting team is moving to the sixth floor on Monday. M: Then we need to update the directory in the lobby. W: I'll also send a message to our regular delivery companies.","audioTranslation":"女：會計團隊星期一將搬到六樓。男：那我們需要更新大廳的公司目錄。女：我也會傳訊息給經常合作的送貨公司。","groupId":"P3-G13","tags":["conversation","listening"]},{"id":"P3-G13-Q2","part":"3","difficulty":"600","category":"辦公室搬遷","prompt":"What does the man say needs to be updated?","choices":["The lobby directory","The accounting software","The delivery schedule","The company website"],"answer":0,"explanation":"男子說要更新大廳目錄。","translation":"","passage":"","audioText":"W: The accounting team is moving to the sixth floor on Monday. M: Then we need to update the directory in the lobby. W: I'll also send a message to our regular delivery companies.","audioTranslation":"女：會計團隊星期一將搬到六樓。男：那我們需要更新大廳的公司目錄。女：我也會傳訊息給經常合作的送貨公司。","groupId":"P3-G13","tags":["conversation","listening"]},{"id":"P3-G13-Q3","part":"3","difficulty":"600","category":"辦公室搬遷","prompt":"Whom will the woman contact?","choices":["Regular delivery companies","New accounting applicants","Building inspectors","Conference attendees"],"answer":0,"explanation":"女子會通知固定合作的送貨公司。","translation":"","passage":"","audioText":"W: The accounting team is moving to the sixth floor on Monday. M: Then we need to update the directory in the lobby. W: I'll also send a message to our regular delivery companies.","audioTranslation":"女：會計團隊星期一將搬到六樓。男：那我們需要更新大廳的公司目錄。女：我也會傳訊息給經常合作的送貨公司。","groupId":"P3-G13","tags":["conversation","listening"]},{"id":"P3-G14-Q1","part":"3","difficulty":"800","category":"商品攝影","prompt":"What are the speakers preparing for?","choices":["A catalog photo session","A winter conference","A supplier interview","A clothing sale today"],"answer":0,"explanation":"他們正準備冬季目錄攝影。","translation":"","passage":"","audioText":"M: The photos for the winter catalog are scheduled for Thursday, but the sample coats haven't arrived. W: The supplier says they will be delivered tomorrow morning. M: Good. Please check every item as soon as the boxes arrive.","audioTranslation":"男：冬季目錄的拍攝排在星期四，但樣品外套還沒送到。女：供應商說明天早上會送達。男：很好。箱子一到，請立刻檢查每一件商品。","groupId":"P3-G14","tags":["conversation","listening"]},{"id":"P3-G14-Q2","part":"3","difficulty":"800","category":"商品攝影","prompt":"When should the coats arrive?","choices":["Tomorrow morning","Thursday evening","Next winter","This afternoon"],"answer":0,"explanation":"供應商說明早送達。","translation":"","passage":"","audioText":"M: The photos for the winter catalog are scheduled for Thursday, but the sample coats haven't arrived. W: The supplier says they will be delivered tomorrow morning. M: Good. Please check every item as soon as the boxes arrive.","audioTranslation":"男：冬季目錄的拍攝排在星期四，但樣品外套還沒送到。女：供應商說明天早上會送達。男：很好。箱子一到，請立刻檢查每一件商品。","groupId":"P3-G14","tags":["conversation","listening"]},{"id":"P3-G14-Q3","part":"3","difficulty":"800","category":"商品攝影","prompt":"What does the man ask the woman to do?","choices":["Inspect the delivered items","Cancel the photo session","Return all the coats","Call a different photographer"],"answer":0,"explanation":"箱子送達後要檢查所有商品。","translation":"","passage":"","audioText":"M: The photos for the winter catalog are scheduled for Thursday, but the sample coats haven't arrived. W: The supplier says they will be delivered tomorrow morning. M: Good. Please check every item as soon as the boxes arrive.","audioTranslation":"男：冬季目錄的拍攝排在星期四，但樣品外套還沒送到。女：供應商說明天早上會送達。男：很好。箱子一到，請立刻檢查每一件商品。","groupId":"P3-G14","tags":["conversation","listening"]},{"id":"P4-G11-Q1","part":"4","difficulty":"600","category":"大樓公告","prompt":"Why will the information desk close early?","choices":["Staff members will attend training","The lobby will be painted","Security equipment is being replaced","The building is closing"],"answer":0,"explanation":"提早關閉是因為員工訓練。","translation":"","passage":"","audioText":"The main lobby information desk will close at four o'clock today for staff training. Visitors arriving after four should check in with the security officer at the south entrance. The information desk will reopen at its normal time tomorrow morning.","audioTranslation":"大廳服務台今天因員工訓練將於四點關閉。四點後抵達的訪客應在南側入口向警衛辦理登記。服務台明早將依正常時間重新開放。","groupId":"P4-G11","tags":["talk","listening"]},{"id":"P4-G11-Q2","part":"4","difficulty":"600","category":"大樓公告","prompt":"Where should late visitors check in?","choices":["At the south entrance","At the parking office","On the second floor","At the main information desk"],"answer":0,"explanation":"四點後應到南側入口。","translation":"","passage":"","audioText":"The main lobby information desk will close at four o'clock today for staff training. Visitors arriving after four should check in with the security officer at the south entrance. The information desk will reopen at its normal time tomorrow morning.","audioTranslation":"大廳服務台今天因員工訓練將於四點關閉。四點後抵達的訪客應在南側入口向警衛辦理登記。服務台明早將依正常時間重新開放。","groupId":"P4-G11","tags":["talk","listening"]},{"id":"P4-G11-Q3","part":"4","difficulty":"600","category":"大樓公告","prompt":"When will the desk reopen?","choices":["Tomorrow morning","At four today","Next Monday","After lunch today"],"answer":0,"explanation":"明早恢復正常服務。","translation":"","passage":"","audioText":"The main lobby information desk will close at four o'clock today for staff training. Visitors arriving after four should check in with the security officer at the south entrance. The information desk will reopen at its normal time tomorrow morning.","audioTranslation":"大廳服務台今天因員工訓練將於四點關閉。四點後抵達的訪客應在南側入口向警衛辦理登記。服務台明早將依正常時間重新開放。","groupId":"P4-G11","tags":["talk","listening"]},{"id":"P4-G12-Q1","part":"4","difficulty":"800","category":"產品說明","prompt":"What should users do before first use?","choices":["Remove a covering from the filter","Order a replacement filter","Place the unit against a wall","Turn the indicator light orange"],"answer":0,"explanation":"首次使用前要移除濾網保護膜。","translation":"","passage":"","audioText":"Thank you for purchasing the CleanAir 500 purifier. Before first use, remove the protective covering from the filter and place the unit at least thirty centimeters from a wall. The indicator light will turn orange when the filter needs to be replaced. Replacement filters can be ordered through our website.","audioTranslation":"感謝您購買 CleanAir 500 空氣清淨機。首次使用前，請移除濾網保護膜，並將機器放在離牆至少三十公分處。需要更換濾網時，指示燈會變成橘色。替換濾網可透過本公司網站訂購。","groupId":"P4-G12","tags":["talk","listening"]},{"id":"P4-G12-Q2","part":"4","difficulty":"800","category":"產品說明","prompt":"How far should the unit be from a wall?","choices":["At least thirty centimeters","Exactly five centimeters","More than three meters","It may touch the wall"],"answer":0,"explanation":"至少離牆三十公分。","translation":"","passage":"","audioText":"Thank you for purchasing the CleanAir 500 purifier. Before first use, remove the protective covering from the filter and place the unit at least thirty centimeters from a wall. The indicator light will turn orange when the filter needs to be replaced. Replacement filters can be ordered through our website.","audioTranslation":"感謝您購買 CleanAir 500 空氣清淨機。首次使用前，請移除濾網保護膜，並將機器放在離牆至少三十公分處。需要更換濾網時，指示燈會變成橘色。替換濾網可透過本公司網站訂購。","groupId":"P4-G12","tags":["talk","listening"]},{"id":"P4-G12-Q3","part":"4","difficulty":"800","category":"產品說明","prompt":"What does an orange light indicate?","choices":["The filter needs replacement","The unit is too far from a wall","The website is unavailable","The covering is still attached"],"answer":0,"explanation":"橘色燈表示需要更換濾網。","translation":"","passage":"","audioText":"Thank you for purchasing the CleanAir 500 purifier. Before first use, remove the protective covering from the filter and place the unit at least thirty centimeters from a wall. The indicator light will turn orange when the filter needs to be replaced. Replacement filters can be ordered through our website.","audioTranslation":"感謝您購買 CleanAir 500 空氣清淨機。首次使用前，請移除濾網保護膜，並將機器放在離牆至少三十公分處。需要更換濾網時，指示燈會變成橘色。替換濾網可透過本公司網站訂購。","groupId":"P4-G12","tags":["talk","listening"]},{"id":"P5-089","part":"5","difficulty":"400","category":"介系詞","prompt":"The warranty remains valid _____ three years from the date of purchase.","choices":["for","since","during","until"],"answer":0,"explanation":"for + 一段時間。","translation":"保固自購買日起有效三年。","passage":"","audioText":"","tags":["reading","grammar"]},{"id":"P5-090","part":"5","difficulty":"600","category":"介系詞","prompt":"The final decision rests _____ the executive committee.","choices":["with","to","for","into"],"answer":0,"explanation":"rest with someone 表示由某人負責決定。","translation":"最終決定權在執行委員會。","passage":"","audioText":"","tags":["reading","grammar"]},{"id":"P5-091","part":"5","difficulty":"600","category":"固定搭配","prompt":"The new regulations are applicable _____ all overseas branches.","choices":["to","with","for","at"],"answer":0,"explanation":"be applicable to 是固定搭配。","translation":"新規定適用於所有海外分公司。","passage":"","audioText":"","tags":["reading","grammar"]},{"id":"P5-092","part":"5","difficulty":"600","category":"固定搭配","prompt":"Several employees expressed concern _____ the proposed schedule change.","choices":["about","with","from","into"],"answer":0,"explanation":"express concern about 是固定搭配。","translation":"數名員工對所提議的時程變更表示擔憂。","passage":"","audioText":"","tags":["reading","grammar"]},{"id":"P5-093","part":"5","difficulty":"400","category":"詞性","prompt":"The hotel offers _____ transportation to and from the airport.","choices":["complimentary","compliment","complimented","complimentarily"],"answer":0,"explanation":"修飾 transportation 使用形容詞 complimentary，意為免費的。","translation":"飯店提供免費機場接送。","passage":"","audioText":"","tags":["reading","grammar"]},{"id":"P5-094","part":"5","difficulty":"600","category":"詞性","prompt":"The board requested a more _____ analysis of the proposal.","choices":["detail","detailed","details","detailing"],"answer":1,"explanation":"修飾 analysis 使用形容詞 detailed。","translation":"董事會要求對提案進行更詳細的分析。","passage":"","audioText":"","tags":["reading","grammar"]},{"id":"P5-095","part":"5","difficulty":"600","category":"時態","prompt":"The research team _____ the survey results before publishing its report.","choices":["verifies","will verify","verified","has verifying"],"answer":1,"explanation":"在未來發布報告前將先核實結果，使用未來式。","translation":"研究團隊將在發布報告前核實調查結果。","passage":"","audioText":"","tags":["reading","grammar"]},{"id":"P5-096","part":"5","difficulty":"800","category":"時態","prompt":"This is the first time the company _____ a conference in Bangkok.","choices":["hosts","hosted","has hosted","will host"],"answer":2,"explanation":"This is the first time + 現在完成式。","translation":"這是公司第一次在曼谷舉辦會議。","passage":"","audioText":"","tags":["reading","grammar"]},{"id":"P5-097","part":"5","difficulty":"600","category":"關係代名詞","prompt":"The applicants, several of _____ have worked abroad, will be interviewed today.","choices":["who","whom","whose","which"],"answer":1,"explanation":"介系詞 of 後指人，使用 whom。","translation":"這些申請者中有幾位曾在海外工作，他們今天將接受面試。","passage":"","audioText":"","tags":["reading","grammar"]},{"id":"P5-098","part":"5","difficulty":"800","category":"名詞子句","prompt":"The committee will discuss _____ additional funding is necessary.","choices":["whether","despite","which","during"],"answer":0,"explanation":"whether 引導「是否需要」的名詞子句。","translation":"委員會將討論是否需要額外資金。","passage":"","audioText":"","tags":["reading","grammar"]},{"id":"P5-099","part":"5","difficulty":"600","category":"分詞","prompt":"Customers _____ to the loyalty program receive monthly coupons.","choices":["subscribe","subscribed","subscribing","subscription"],"answer":1,"explanation":"customers subscribed to... 表示已加入方案的顧客。","translation":"加入忠誠方案的顧客每月會收到優惠券。","passage":"","audioText":"","tags":["reading","grammar"]},{"id":"P5-100","part":"5","difficulty":"800","category":"分詞構句","prompt":"_____ all required documents, the applicant proceeded to the interview room.","choices":["Submit","Submitted","Having submitted","To submitting"],"answer":2,"explanation":"先提交文件再前往面試室，用 Having submitted。","translation":"提交所有必要文件後，申請者前往面試室。","passage":"","audioText":"","tags":["reading","grammar"]},{"id":"P5-101","part":"5","difficulty":"400","category":"數量詞","prompt":"Only a _____ employees volunteered for the weekend event.","choices":["few","little","much","less"],"answer":0,"explanation":"employees 為可數複數，a few 表示一些。","translation":"只有少數員工自願參加週末活動。","passage":"","audioText":"","tags":["reading","grammar"]},{"id":"P5-102","part":"5","difficulty":"600","category":"比較級","prompt":"This year's exhibition attracted _____ visitors than last year's event.","choices":["many","more","most","much"],"answer":1,"explanation":"than 搭配比較級 more。","translation":"今年的展覽比去年吸引更多訪客。","passage":"","audioText":"","tags":["reading","grammar"]},{"id":"P5-103","part":"5","difficulty":"600","category":"商務字彙","prompt":"The company will _____ the damaged items at no additional cost.","choices":["replace","release","relieve","represent"],"answer":0,"explanation":"replace damaged items 表示更換受損商品。","translation":"公司將免費更換受損商品。","passage":"","audioText":"","tags":["reading","grammar"]},{"id":"P5-104","part":"5","difficulty":"800","category":"商務字彙","prompt":"Managers are expected to _____ potential risks before approving a project.","choices":["assess","access","assist","assign"],"answer":0,"explanation":"assess risks 表示評估風險。","translation":"經理在核准專案前應評估潛在風險。","passage":"","audioText":"","tags":["reading","grammar"]},{"id":"P6-029","part":"6","difficulty":"600","category":"員工通知","prompt":"The company gym will close at 7 P.M. on Thursday so that new exercise equipment can be _____.","choices":["install","installed","installing","installation"],"answer":1,"explanation":"can be + 過去分詞，表示設備被安裝。","translation":"","passage":"The company gym will close at 7 P.M. on Thursday so that new exercise equipment can be _____. Members should remove all personal belongings from the lockers _____ Wednesday evening. _____ the closure, employees may use the fitness center at the West Avenue branch. Normal operating hours will _____ on Friday morning.","audioText":"","groupId":"P6-G08","tags":["text-completion"]},{"id":"P6-030","part":"6","difficulty":"600","category":"員工通知","prompt":"Members should remove all personal belongings from the lockers _____ Wednesday evening.","choices":["by","among","during","from"],"answer":0,"explanation":"by 表示最晚於星期三晚上。","translation":"","passage":"The company gym will close at 7 P.M. on Thursday so that new exercise equipment can be _____. Members should remove all personal belongings from the lockers _____ Wednesday evening. _____ the closure, employees may use the fitness center at the West Avenue branch. Normal operating hours will _____ on Friday morning.","audioText":"","groupId":"P6-G08","tags":["text-completion"]},{"id":"P6-031","part":"6","difficulty":"600","category":"員工通知","prompt":"_____ the closure, employees may use the fitness center at the West Avenue branch.","choices":["During","Despite","Unless","Therefore"],"answer":0,"explanation":"During + 名詞 the closure。","translation":"","passage":"The company gym will close at 7 P.M. on Thursday so that new exercise equipment can be _____. Members should remove all personal belongings from the lockers _____ Wednesday evening. _____ the closure, employees may use the fitness center at the West Avenue branch. Normal operating hours will _____ on Friday morning.","audioText":"","groupId":"P6-G08","tags":["text-completion"]},{"id":"P6-032","part":"6","difficulty":"600","category":"員工通知","prompt":"Normal operating hours will _____ on Friday morning.","choices":["resume","resumes","resumed","resumption"],"answer":0,"explanation":"will 後接原形 resume。","translation":"","passage":"The company gym will close at 7 P.M. on Thursday so that new exercise equipment can be _____. Members should remove all personal belongings from the lockers _____ Wednesday evening. _____ the closure, employees may use the fitness center at the West Avenue branch. Normal operating hours will _____ on Friday morning.","audioText":"","groupId":"P6-G08","tags":["text-completion"]},{"id":"P6-033","part":"6","difficulty":"800","category":"產品召回","prompt":"Customers who purchased the Model X electric kettle between March 1 and April 15 should stop _____ it immediately.","choices":["use","used","using","to used"],"answer":2,"explanation":"stop using 表示停止使用。","translation":"","passage":"Customers who purchased the Model X electric kettle between March 1 and April 15 should stop _____ it immediately. A small number of units may overheat _____ the water level is too low. Affected customers can return the kettle to any authorized store for a full _____. Additional information, including a list of serial numbers, is _____ on our website.","audioText":"","groupId":"P6-G09","tags":["text-completion"]},{"id":"P6-034","part":"6","difficulty":"800","category":"產品召回","prompt":"A small number of units may overheat _____ the water level is too low.","choices":["if","despite","during","because of"],"answer":0,"explanation":"if + 完整子句，表示條件。","translation":"","passage":"Customers who purchased the Model X electric kettle between March 1 and April 15 should stop _____ it immediately. A small number of units may overheat _____ the water level is too low. Affected customers can return the kettle to any authorized store for a full _____. Additional information, including a list of serial numbers, is _____ on our website.","audioText":"","groupId":"P6-G09","tags":["text-completion"]},{"id":"P6-035","part":"6","difficulty":"800","category":"產品召回","prompt":"Affected customers can return the kettle to any authorized store for a full _____.","choices":["refund","refundable","refunding","refunded"],"answer":0,"explanation":"full refund 是全額退款。","translation":"","passage":"Customers who purchased the Model X electric kettle between March 1 and April 15 should stop _____ it immediately. A small number of units may overheat _____ the water level is too low. Affected customers can return the kettle to any authorized store for a full _____. Additional information, including a list of serial numbers, is _____ on our website.","audioText":"","groupId":"P6-G09","tags":["text-completion"]},{"id":"P6-036","part":"6","difficulty":"800","category":"產品召回","prompt":"Additional information, including a list of serial numbers, is _____ on our website.","choices":["available","availability","availably","avail"],"answer":0,"explanation":"be available on 是正確結構。","translation":"","passage":"Customers who purchased the Model X electric kettle between March 1 and April 15 should stop _____ it immediately. A small number of units may overheat _____ the water level is too low. Affected customers can return the kettle to any authorized store for a full _____. Additional information, including a list of serial numbers, is _____ on our website.","audioText":"","groupId":"P6-G09","tags":["text-completion"]},{"id":"P7-R20-Q1","part":"7","difficulty":"600","category":"電子郵件","prompt":"Why was the demonstration time changed?","choices":["The client wants to tour the warehouse","The conference room is unavailable","The presenter has a flight delay","The handouts are not ready"],"answer":0,"explanation":"客戶希望簡報前先參觀倉庫。","translation":"","passage":"From: Hannah Brooks\nTo: Sales Staff\nSubject: Friday Product Demonstration\n\nThe product demonstration scheduled for Friday will now begin at 1:30 P.M., thirty minutes later than originally planned. The client requested extra time to tour our warehouse before the presentation. Please update your calendars and arrive in Conference Room 2 by 1:15. Printed handouts will be available at the entrance.","audioText":"","groupId":"P7-R20","tags":["reading"]},{"id":"P7-R20-Q2","part":"7","difficulty":"600","category":"電子郵件","prompt":"When should staff arrive?","choices":["By 1:15 P.M.","At 1:30 P.M.","Thirty minutes after the presentation","Before the warehouse opens"],"answer":0,"explanation":"信中要求一點十五分前抵達。","translation":"","passage":"From: Hannah Brooks\nTo: Sales Staff\nSubject: Friday Product Demonstration\n\nThe product demonstration scheduled for Friday will now begin at 1:30 P.M., thirty minutes later than originally planned. The client requested extra time to tour our warehouse before the presentation. Please update your calendars and arrive in Conference Room 2 by 1:15. Printed handouts will be available at the entrance.","audioText":"","groupId":"P7-R20","tags":["reading"]},{"id":"P7-R21-Q1","part":"7","difficulty":"600","category":"廣告","prompt":"What is included in the special?","choices":["A safety check","New replacement parts","A bicycle rental","Home delivery"],"answer":0,"explanation":"服務內容包含安全檢查。","translation":"","passage":"Oak Street Bicycle Repair\n\nSpring Tune-Up Special — $39\nService includes brake adjustment, tire inspection, chain cleaning, and a safety check. Bicycles dropped off before noon are usually ready by 5 P.M. the same day. The offer is valid through April 30 and does not include replacement parts. Appointments are recommended on Saturdays.","audioText":"","groupId":"P7-R21","tags":["reading"]},{"id":"P7-R21-Q2","part":"7","difficulty":"600","category":"廣告","prompt":"What is recommended on Saturdays?","choices":["Making an appointment","Arriving after five","Purchasing replacement parts","Using a rental bicycle"],"answer":0,"explanation":"星期六建議先預約。","translation":"","passage":"Oak Street Bicycle Repair\n\nSpring Tune-Up Special — $39\nService includes brake adjustment, tire inspection, chain cleaning, and a safety check. Bicycles dropped off before noon are usually ready by 5 P.M. the same day. The offer is valid through April 30 and does not include replacement parts. Appointments are recommended on Saturdays.","audioText":"","groupId":"P7-R21","tags":["reading"]},{"id":"P7-R22-Q1","part":"7","difficulty":"800","category":"公司文章","prompt":"What has Meridian Foods completed?","choices":["A solar panel installation","The construction of a new factory","A product distribution contract","An employee transportation program"],"answer":0,"explanation":"公司完成太陽能板安裝。","translation":"","passage":"Meridian Foods has completed the installation of solar panels at its largest distribution center. The system is expected to supply nearly forty percent of the facility's annual electricity needs. The company began the project last year as part of a broader plan to reduce operating costs and greenhouse-gas emissions. Additional installations are being considered for two other locations.","audioText":"","groupId":"P7-R22","tags":["reading"]},{"id":"P7-R22-Q2","part":"7","difficulty":"800","category":"公司文章","prompt":"Why did the company begin the project?","choices":["To reduce costs and emissions","To hire additional workers","To increase product prices","To replace two facilities"],"answer":0,"explanation":"目的在降低營運成本與溫室氣體排放。","translation":"","passage":"Meridian Foods has completed the installation of solar panels at its largest distribution center. The system is expected to supply nearly forty percent of the facility's annual electricity needs. The company began the project last year as part of a broader plan to reduce operating costs and greenhouse-gas emissions. Additional installations are being considered for two other locations.","audioText":"","groupId":"P7-R22","tags":["reading"]},{"id":"P7-R23-Q1","part":"7","difficulty":"600","category":"活動通知","prompt":"What transportation will be provided?","choices":["A free shuttle","Discounted train tickets","Bicycle rentals","Airport buses"],"answer":0,"explanation":"活動提供免費接駁車。","translation":"","passage":"The Downtown Art Walk will take place on the evening of May 18. More than twenty galleries will remain open until 10 P.M., and a free shuttle will operate between participating locations. Printed maps can be collected at the visitor center beginning at 4 P.M. Some workshops require advance registration, although admission to the galleries is free.","audioText":"","groupId":"P7-R23","tags":["reading"]},{"id":"P7-R23-Q2","part":"7","difficulty":"600","category":"活動通知","prompt":"What may require advance registration?","choices":["Some workshops","Gallery admission","The visitor center","The printed maps"],"answer":0,"explanation":"部分工作坊需要事先報名。","translation":"","passage":"The Downtown Art Walk will take place on the evening of May 18. More than twenty galleries will remain open until 10 P.M., and a free shuttle will operate between participating locations. Printed maps can be collected at the visitor center beginning at 4 P.M. Some workshops require advance registration, although admission to the galleries is free.","audioText":"","groupId":"P7-R23","tags":["reading"]},{"id":"P7-R24-Q1","part":"7","difficulty":"800","category":"備忘錄","prompt":"What should personnel do with expired materials?","choices":["Remove them","Relabel them","Place them outside Room 214","Send them to the auditor"],"answer":0,"explanation":"過期材料應移除。","translation":"","passage":"To: Laboratory Personnel\nFrom: Safety Office\nSubject: Chemical Storage Audit\n\nA safety auditor will inspect all chemical storage cabinets on June 11. Before the inspection, please verify that containers are clearly labeled and that expired materials have been removed. A checklist is attached to this message. Completed checklists should be placed in the blue folder outside Room 214 by June 9.","audioText":"","groupId":"P7-R24","tags":["reading"]},{"id":"P7-R24-Q2","part":"7","difficulty":"800","category":"備忘錄","prompt":"Where should completed checklists be placed?","choices":["In a blue folder","Inside each cabinet","At the building entrance","On the auditor's desk"],"answer":0,"explanation":"應放在 214 室外的藍色資料夾。","translation":"","passage":"To: Laboratory Personnel\nFrom: Safety Office\nSubject: Chemical Storage Audit\n\nA safety auditor will inspect all chemical storage cabinets on June 11. Before the inspection, please verify that containers are clearly labeled and that expired materials have been removed. A checklist is attached to this message. Completed checklists should be placed in the blue folder outside Room 214 by June 9.","audioText":"","groupId":"P7-R24","tags":["reading"]},{"id":"P7-R25-Q1","part":"7","difficulty":"600","category":"訂單通知","prompt":"Why is a signature required?","choices":["The package contains valuable electronics","The order was placed on Tuesday","The delivery address is incomplete","The customer requested a refund"],"answer":0,"explanation":"包裹內有價值超過五百美元的電子設備。","translation":"","passage":"Shipping Update — Order 90417\n\nYour order left our distribution center on Tuesday and is expected to arrive on Friday. A signature will be required at delivery because the package contains electronic equipment valued at more than $500. To authorize delivery to a neighbor or change the delivery date, visit the carrier's website before 8 P.M. on Thursday.","audioText":"","groupId":"P7-R25","tags":["reading"]},{"id":"P7-R25-Q2","part":"7","difficulty":"600","category":"訂單通知","prompt":"By when must a delivery change be made?","choices":["Before 8 P.M. Thursday","Before Tuesday morning","After the package arrives","By Friday evening"],"answer":0,"explanation":"需在星期四晚上八點前變更。","translation":"","passage":"Shipping Update — Order 90417\n\nYour order left our distribution center on Tuesday and is expected to arrive on Friday. A signature will be required at delivery because the package contains electronic equipment valued at more than $500. To authorize delivery to a neighbor or change the delivery date, visit the carrier's website before 8 P.M. on Thursday.","audioText":"","groupId":"P7-R25","tags":["reading"]},{"id":"P7-R26-Q1","part":"7","difficulty":"800","category":"職缺","prompt":"What is one responsibility of the position?","choices":["Coordinating room reservations","Teaching spreadsheet courses","Repairing classroom equipment","Hiring university professors"],"answer":0,"explanation":"工作包含安排教室預約。","translation":"","passage":"Facilities Scheduling Assistant\n\nRiverton University seeks an assistant to coordinate classroom reservations and maintain event calendars. The position requires excellent organizational skills and familiarity with spreadsheet software. Previous experience in an educational institution is preferred. The selected candidate will work from 8 A.M. to 4 P.M., Monday through Friday. Applications must include a résumé and a cover letter.","audioText":"","groupId":"P7-R26","tags":["reading"]},{"id":"P7-R26-Q2","part":"7","difficulty":"800","category":"職缺","prompt":"What experience is preferred?","choices":["Work at an educational institution","Professional teaching certification","Building maintenance experience","Weekend customer service"],"answer":0,"explanation":"偏好具教育機構工作經驗。","translation":"","passage":"Facilities Scheduling Assistant\n\nRiverton University seeks an assistant to coordinate classroom reservations and maintain event calendars. The position requires excellent organizational skills and familiarity with spreadsheet software. Previous experience in an educational institution is preferred. The selected candidate will work from 8 A.M. to 4 P.M., Monday through Friday. Applications must include a résumé and a cover letter.","audioText":"","groupId":"P7-R26","tags":["reading"]},{"id":"P7-R27-Q1","part":"7","difficulty":"800","category":"雙篇閱讀","prompt":"What change is announced?","choices":["The café will open earlier on weekdays","The café will stop accepting online orders","Breakfast will be served only on weekends","The mobile application will be replaced"],"answer":0,"explanation":"平日早餐開始時間由八點提前到七點。","translation":"","passage":"RESTAURANT NOTICE\nBeginning September 1, Harbor Café will serve breakfast from 7 to 10 A.M. on weekdays. The café previously opened at 8 A.M. Online orders may be placed through the café's mobile application.\n\nMESSAGE\nLeah: Our client meeting starts at 8:30 on Tuesday. Harbor Café now opens at seven, so I'll order breakfast for the group.\nOwen: Great. Please include two vegetarian meals and have everything delivered to Meeting Room 5 by 8:15.","audioText":"","groupId":"P7-R27","tags":["reading"]},{"id":"P7-R27-Q2","part":"7","difficulty":"800","category":"雙篇閱讀","prompt":"What does Owen request?","choices":["Two vegetarian meals","A table at the café","A meeting at seven","Five mobile applications"],"answer":0,"explanation":"Owen 要求兩份素食餐點。","translation":"","passage":"RESTAURANT NOTICE\nBeginning September 1, Harbor Café will serve breakfast from 7 to 10 A.M. on weekdays. The café previously opened at 8 A.M. Online orders may be placed through the café's mobile application.\n\nMESSAGE\nLeah: Our client meeting starts at 8:30 on Tuesday. Harbor Café now opens at seven, so I'll order breakfast for the group.\nOwen: Great. Please include two vegetarian meals and have everything delivered to Meeting Room 5 by 8:15.","audioText":"","groupId":"P7-R27","tags":["reading"]},{"id":"P2-059","part":"2","difficulty":"400","category":"應答","prompt":"Choose the best response.","choices":["On Thursday afternoon.","Near the loading dock.","They are more comfortable."],"answer":0,"explanation":"When 問時間。","translation":"替換椅子何時送達？","passage":"","audioText":"When will the replacement chairs be delivered?","audioTranslation":"替換椅子何時送達？","answerTranslation":"星期四下午。","tags":["listening","response"]},{"id":"P2-060","part":"2","difficulty":"600","category":"應答","prompt":"Choose the best response.","choices":["Not at all. I'll review them now.","The figures increased last year.","There are twelve figures."],"answer":0,"explanation":"Would you mind...? 接受請求可回答 Not at all。","translation":"可以麻煩你再確認一次這些數字嗎？","passage":"","audioText":"Would you mind checking these figures once more?","audioTranslation":"可以麻煩你再確認一次這些數字嗎？","answerTranslation":"當然可以，我現在就檢查。","tags":["listening","response"]},{"id":"P2-061","part":"2","difficulty":"400","category":"應答","prompt":"Choose the best response.","choices":["At the reception counter.","She left at five.","The visitors signed in."],"answer":0,"explanation":"Where 問放置地點。","translation":"Ito 女士把訪客證放在哪裡？","passage":"","audioText":"Where did Ms. Ito leave the visitor passes?","audioTranslation":"Ito 女士把訪客證放在哪裡？","answerTranslation":"在接待櫃台。","tags":["listening","response"]},{"id":"P2-062","part":"2","difficulty":"600","category":"應答","prompt":"Choose the best response.","choices":["The legal team requested a revision.","It was copied in color.","The advertisement starts tomorrow."],"answer":0,"explanation":"Why 問尚未核准的原因。","translation":"廣告文案為什麼還沒核准？","passage":"","audioText":"Why hasn't the advertising copy been approved?","audioTranslation":"廣告文案為什麼還沒核准？","answerTranslation":"法務團隊要求修改。","tags":["listening","response"]},{"id":"P2-063","part":"2","difficulty":"400","category":"應答","prompt":"Choose the best response.","choices":["Twice a year.","By the safety officer.","On every floor."],"answer":0,"explanation":"How often 問頻率。","translation":"火災警報器多久測試一次？","passage":"","audioText":"How often are the fire alarms tested?","audioTranslation":"火災警報器多久測試一次？","answerTranslation":"一年兩次。","tags":["listening","response"]},{"id":"P2-064","part":"2","difficulty":"600","category":"應答","prompt":"Choose the best response.","choices":["Yes, we expect about forty guests.","The room is on the right.","I attended the meeting."],"answer":0,"explanation":"Should I...? 是詢問是否採取行動。","translation":"我應該預訂較大的會議室嗎？","passage":"","audioText":"Should I reserve the larger meeting room?","audioTranslation":"我應該預訂較大的會議室嗎？","answerTranslation":"是的，我們預計約四十位來賓。","tags":["listening","response"]},{"id":"P2-065","part":"2","difficulty":"400","category":"應答","prompt":"Choose the best response.","choices":["The finance manager.","It takes three business days.","At the downtown bank."],"answer":0,"explanation":"Who 問具有授權權限的人。","translation":"誰可以核准國際匯款？","passage":"","audioText":"Who can authorize an international transfer?","audioTranslation":"誰可以核准國際匯款？","answerTranslation":"財務經理。","tags":["listening","response"]},{"id":"P2-066","part":"2","difficulty":"600","category":"應答","prompt":"Choose the best response.","choices":["No, the pickup was rescheduled.","The package is lightweight.","This morning was busy."],"answer":0,"explanation":"否定疑問句依事實回答，並說明重新排程。","translation":"快遞今天早上不是已取走包裹了嗎？","passage":"","audioText":"Didn't the courier pick up the package this morning?","audioTranslation":"快遞今天早上不是已取走包裹了嗎？","answerTranslation":"沒有，取件時間重新安排了。","tags":["listening","response"]},{"id":"P2-067","part":"2","difficulty":"400","category":"應答","prompt":"Choose the best response.","choices":["The one marked final.","At the copy center.","About thirty pages."],"answer":0,"explanation":"Which version 問特定版本。","translation":"我應該列印哪個版本的報告？","passage":"","audioText":"Which version of the report should I print?","audioTranslation":"我應該列印哪個版本的報告？","answerTranslation":"標示為 final 的那一份。","tags":["listening","response"]},{"id":"P2-068","part":"2","difficulty":"600","category":"應答","prompt":"Choose the best response.","choices":["Let me check the consultant's schedule.","Friday is the fifth day.","The appointment lasted an hour."],"answer":0,"explanation":"對更改預約時間的請求，先確認行程最自然。","translation":"我們可以把預約改到星期五早上嗎？","passage":"","audioText":"Could we move the appointment to Friday morning?","audioTranslation":"我們可以把預約改到星期五早上嗎？","answerTranslation":"我確認一下顧問的行程。","tags":["listening","response"]},{"id":"P3-G15-Q1","part":"3","difficulty":"600","category":"印刷訂單","prompt":"What problem is mentioned?","choices":["A logo is missing from the brochures","The event date is incorrect","The printer is out of paper","The company address changed"],"answer":0,"explanation":"宣傳冊背頁少了公司標誌。","translation":"","passage":"","audioText":"W: The brochures for Monday's event arrived, but the company logo is missing from the back page. M: I'll contact the printer immediately. Do we have time for a corrected delivery? W: Yes, as long as it arrives by Friday afternoon.","audioTranslation":"女：星期一活動用的宣傳冊已送達，但背頁少了公司標誌。男：我會立刻聯絡印刷廠。我們還有時間重新送一批修正版嗎？女：有，只要星期五下午前送達。","groupId":"P3-G15","tags":["conversation","listening"]},{"id":"P3-G15-Q2","part":"3","difficulty":"600","category":"印刷訂單","prompt":"Whom will the man contact?","choices":["The printer","The event speaker","A delivery customer","The design applicant"],"answer":0,"explanation":"男子會聯絡印刷廠。","translation":"","passage":"","audioText":"W: The brochures for Monday's event arrived, but the company logo is missing from the back page. M: I'll contact the printer immediately. Do we have time for a corrected delivery? W: Yes, as long as it arrives by Friday afternoon.","audioTranslation":"女：星期一活動用的宣傳冊已送達，但背頁少了公司標誌。男：我會立刻聯絡印刷廠。我們還有時間重新送一批修正版嗎？女：有，只要星期五下午前送達。","groupId":"P3-G15","tags":["conversation","listening"]},{"id":"P3-G15-Q3","part":"3","difficulty":"600","category":"印刷訂單","prompt":"When must the corrected brochures arrive?","choices":["By Friday afternoon","Before Monday morning","This afternoon","After the event"],"answer":0,"explanation":"修正版須在星期五下午前抵達。","translation":"","passage":"","audioText":"W: The brochures for Monday's event arrived, but the company logo is missing from the back page. M: I'll contact the printer immediately. Do we have time for a corrected delivery? W: Yes, as long as it arrives by Friday afternoon.","audioTranslation":"女：星期一活動用的宣傳冊已送達，但背頁少了公司標誌。男：我會立刻聯絡印刷廠。我們還有時間重新送一批修正版嗎？女：有，只要星期五下午前送達。","groupId":"P3-G15","tags":["conversation","listening"]},{"id":"P3-G16-Q1","part":"3","difficulty":"800","category":"客戶軟體展示","prompt":"What does the client want to see?","choices":["A reporting feature","A hiring plan","A delivery schedule","A new office location"],"answer":0,"explanation":"客戶想看報表功能。","translation":"","passage":"","audioText":"M: The client wants us to demonstrate the reporting feature during tomorrow's video call. W: Then we should use the test account rather than real customer data. M: Agreed. I'll prepare a sample report and send you the login information.","audioTranslation":"男：客戶希望我們在明天的視訊通話中展示報表功能。女：那我們應該使用測試帳號，而不是真實顧客資料。男：同意。我會準備一份範例報告，並把登入資訊寄給你。","groupId":"P3-G16","tags":["conversation","listening"]},{"id":"P3-G16-Q2","part":"3","difficulty":"800","category":"客戶軟體展示","prompt":"Why does the woman suggest using a test account?","choices":["To avoid using real customer data","To lower the software price","To shorten the video call","To train a new employee"],"answer":0,"explanation":"避免使用真實顧客資料。","translation":"","passage":"","audioText":"M: The client wants us to demonstrate the reporting feature during tomorrow's video call. W: Then we should use the test account rather than real customer data. M: Agreed. I'll prepare a sample report and send you the login information.","audioTranslation":"男：客戶希望我們在明天的視訊通話中展示報表功能。女：那我們應該使用測試帳號，而不是真實顧客資料。男：同意。我會準備一份範例報告，並把登入資訊寄給你。","groupId":"P3-G16","tags":["conversation","listening"]},{"id":"P3-G16-Q3","part":"3","difficulty":"800","category":"客戶軟體展示","prompt":"What will the man send to the woman?","choices":["Login information","A printed contract","Customer invoices","A meeting recording"],"answer":0,"explanation":"男子會寄登入資訊。","translation":"","passage":"","audioText":"M: The client wants us to demonstrate the reporting feature during tomorrow's video call. W: Then we should use the test account rather than real customer data. M: Agreed. I'll prepare a sample report and send you the login information.","audioTranslation":"男：客戶希望我們在明天的視訊通話中展示報表功能。女：那我們應該使用測試帳號，而不是真實顧客資料。男：同意。我會準備一份範例報告，並把登入資訊寄給你。","groupId":"P3-G16","tags":["conversation","listening"]},{"id":"P3-G17-Q1","part":"3","difficulty":"600","category":"商店陳列","prompt":"What problem does the woman identify?","choices":["A display blocks another area","An escalator is not working","New products arrived late","The store entrance is locked"],"answer":0,"explanation":"展示架擋住新品區。","translation":"","passage":"","audioText":"W: The summer display near the entrance is blocking the view of the new arrivals. M: We could move it beside the escalator. There's more space there. W: Good. I'll ask the evening staff to relocate it after closing.","audioTranslation":"女：入口附近的夏季展示擋住了新品區。男：我們可以把它移到手扶梯旁邊，那裡空間比較大。女：好。我會請晚班員工在打烊後搬動。","groupId":"P3-G17","tags":["conversation","listening"]},{"id":"P3-G17-Q2","part":"3","difficulty":"600","category":"商店陳列","prompt":"Where does the man suggest moving the display?","choices":["Beside the escalator","Into the storage room","Outside the entrance","Near the cash registers"],"answer":0,"explanation":"男子建議移到手扶梯旁。","translation":"","passage":"","audioText":"W: The summer display near the entrance is blocking the view of the new arrivals. M: We could move it beside the escalator. There's more space there. W: Good. I'll ask the evening staff to relocate it after closing.","audioTranslation":"女：入口附近的夏季展示擋住了新品區。男：我們可以把它移到手扶梯旁邊，那裡空間比較大。女：好。我會請晚班員工在打烊後搬動。","groupId":"P3-G17","tags":["conversation","listening"]},{"id":"P3-G17-Q3","part":"3","difficulty":"600","category":"商店陳列","prompt":"When will the display be moved?","choices":["After the store closes","Before the evening shift","During lunch","Next summer"],"answer":0,"explanation":"晚班員工打烊後搬動。","translation":"","passage":"","audioText":"W: The summer display near the entrance is blocking the view of the new arrivals. M: We could move it beside the escalator. There's more space there. W: Good. I'll ask the evening staff to relocate it after closing.","audioTranslation":"女：入口附近的夏季展示擋住了新品區。男：我們可以把它移到手扶梯旁邊，那裡空間比較大。女：好。我會請晚班員工在打烊後搬動。","groupId":"P3-G17","tags":["conversation","listening"]},{"id":"P4-G13-Q1","part":"4","difficulty":"600","category":"圖書館公告","prompt":"Why will the study area be unavailable?","choices":["New lighting is being installed","A private event is being held","The library is closing early","Books are being moved"],"answer":0,"explanation":"二樓要安裝新照明。","translation":"","passage":"","audioText":"The second-floor study area will be unavailable from one to three this afternoon while new lighting is installed. Visitors may use the quiet room on the first floor during that period. Group study rooms are not affected and will remain open.","audioTranslation":"二樓自習區今天下午一點到三點因安裝新照明設備而暫停使用。期間訪客可使用一樓安靜閱覽室。團體自習室不受影響，仍照常開放。","groupId":"P4-G13","tags":["talk","listening"]},{"id":"P4-G13-Q2","part":"4","difficulty":"600","category":"圖書館公告","prompt":"What may visitors use instead?","choices":["The first-floor quiet room","The employee cafeteria","The outdoor reading garden only","The second-floor hallway"],"answer":0,"explanation":"可改用一樓安靜閱覽室。","translation":"","passage":"","audioText":"The second-floor study area will be unavailable from one to three this afternoon while new lighting is installed. Visitors may use the quiet room on the first floor during that period. Group study rooms are not affected and will remain open.","audioTranslation":"二樓自習區今天下午一點到三點因安裝新照明設備而暫停使用。期間訪客可使用一樓安靜閱覽室。團體自習室不受影響，仍照常開放。","groupId":"P4-G13","tags":["talk","listening"]},{"id":"P4-G13-Q3","part":"4","difficulty":"600","category":"圖書館公告","prompt":"What will remain open?","choices":["Group study rooms","The entire second floor","The lighting store","The information desk only"],"answer":0,"explanation":"團體自習室照常開放。","translation":"","passage":"","audioText":"The second-floor study area will be unavailable from one to three this afternoon while new lighting is installed. Visitors may use the quiet room on the first floor during that period. Group study rooms are not affected and will remain open.","audioTranslation":"二樓自習區今天下午一點到三點因安裝新照明設備而暫停使用。期間訪客可使用一樓安靜閱覽室。團體自習室不受影響，仍照常開放。","groupId":"P4-G13","tags":["talk","listening"]},{"id":"P4-G14-Q1","part":"4","difficulty":"800","category":"飯店語音","prompt":"Where is breakfast served?","choices":["In the Garden Restaurant","In the east lobby","At the front desk","On the airport shuttle"],"answer":0,"explanation":"早餐在 Garden Restaurant。","translation":"","passage":"","audioText":"Welcome to the Grand Meridian Hotel. Breakfast is served in the Garden Restaurant from six thirty to ten. Guests who have booked an airport shuttle should meet the driver in the east lobby ten minutes before departure. For late checkout requests, please contact the front desk before eleven A.M.","audioTranslation":"歡迎入住 Grand Meridian Hotel。早餐於六點半至十點在 Garden Restaurant 供應。已預約機場接駁的旅客應在出發前十分鐘到東側大廳與司機會合。若需延後退房，請於上午十一點前聯絡櫃台。","groupId":"P4-G14","tags":["talk","listening"]},{"id":"P4-G14-Q2","part":"4","difficulty":"800","category":"飯店語音","prompt":"When should shuttle passengers meet the driver?","choices":["Ten minutes before departure","At six thirty","After checkout","At eleven A.M."],"answer":0,"explanation":"出發前十分鐘會合。","translation":"","passage":"","audioText":"Welcome to the Grand Meridian Hotel. Breakfast is served in the Garden Restaurant from six thirty to ten. Guests who have booked an airport shuttle should meet the driver in the east lobby ten minutes before departure. For late checkout requests, please contact the front desk before eleven A.M.","audioTranslation":"歡迎入住 Grand Meridian Hotel。早餐於六點半至十點在 Garden Restaurant 供應。已預約機場接駁的旅客應在出發前十分鐘到東側大廳與司機會合。若需延後退房，請於上午十一點前聯絡櫃台。","groupId":"P4-G14","tags":["talk","listening"]},{"id":"P4-G14-Q3","part":"4","difficulty":"800","category":"飯店語音","prompt":"What should guests do to request late checkout?","choices":["Contact the front desk before eleven","Meet the shuttle driver","Visit the restaurant","Call the airport"],"answer":0,"explanation":"十一點前聯絡櫃台。","translation":"","passage":"","audioText":"Welcome to the Grand Meridian Hotel. Breakfast is served in the Garden Restaurant from six thirty to ten. Guests who have booked an airport shuttle should meet the driver in the east lobby ten minutes before departure. For late checkout requests, please contact the front desk before eleven A.M.","audioTranslation":"歡迎入住 Grand Meridian Hotel。早餐於六點半至十點在 Garden Restaurant 供應。已預約機場接駁的旅客應在出發前十分鐘到東側大廳與司機會合。若需延後退房，請於上午十一點前聯絡櫃台。","groupId":"P4-G14","tags":["talk","listening"]},{"id":"P4-G15-Q1","part":"4","difficulty":"600","category":"公司活動","prompt":"Where should participants meet?","choices":["In the north parking lot","At Riverside Park directly","Inside the cafeteria","At the train station"],"answer":0,"explanation":"集合地點是北側停車場。","translation":"","passage":"","audioText":"This Friday's employee volunteer event will begin at eight thirty in the north parking lot. Buses will transport participants to the Riverside Park cleanup site. Gloves and trash bags will be provided, but volunteers should bring drinking water and wear comfortable shoes.","audioTranslation":"本週五員工志工活動將於八點半在北側停車場集合。巴士會載參加者前往 Riverside Park 清理地點。現場提供手套與垃圾袋，但志工應自備飲用水並穿著舒適鞋子。","groupId":"P4-G15","tags":["talk","listening"]},{"id":"P4-G15-Q2","part":"4","difficulty":"600","category":"公司活動","prompt":"What will be provided?","choices":["Gloves and trash bags","Drinking water","Comfortable shoes","Breakfast"],"answer":0,"explanation":"提供手套與垃圾袋。","translation":"","passage":"","audioText":"This Friday's employee volunteer event will begin at eight thirty in the north parking lot. Buses will transport participants to the Riverside Park cleanup site. Gloves and trash bags will be provided, but volunteers should bring drinking water and wear comfortable shoes.","audioTranslation":"本週五員工志工活動將於八點半在北側停車場集合。巴士會載參加者前往 Riverside Park 清理地點。現場提供手套與垃圾袋，但志工應自備飲用水並穿著舒適鞋子。","groupId":"P4-G15","tags":["talk","listening"]},{"id":"P4-G15-Q3","part":"4","difficulty":"600","category":"公司活動","prompt":"What should volunteers bring?","choices":["Drinking water","A bus ticket","Cleaning gloves","A printed map"],"answer":0,"explanation":"需自備飲用水。","translation":"","passage":"","audioText":"This Friday's employee volunteer event will begin at eight thirty in the north parking lot. Buses will transport participants to the Riverside Park cleanup site. Gloves and trash bags will be provided, but volunteers should bring drinking water and wear comfortable shoes.","audioTranslation":"本週五員工志工活動將於八點半在北側停車場集合。巴士會載參加者前往 Riverside Park 清理地點。現場提供手套與垃圾袋，但志工應自備飲用水並穿著舒適鞋子。","groupId":"P4-G15","tags":["talk","listening"]},{"id":"P5-105","part":"5","difficulty":"400","category":"介系詞","prompt":"The conference registration fee must be paid _____ advance.","choices":["in","on","at","by"],"answer":0,"explanation":"in advance 是固定片語。","translation":"會議報名費必須預先支付。","passage":"","audioText":"","tags":["reading","grammar"]},{"id":"P5-106","part":"5","difficulty":"600","category":"介系詞","prompt":"The renovation was completed _____ accordance with local safety regulations.","choices":["in","on","for","to"],"answer":0,"explanation":"in accordance with 表示依照。","translation":"整修工程依照當地安全法規完成。","passage":"","audioText":"","tags":["reading","grammar"]},{"id":"P5-107","part":"5","difficulty":"600","category":"固定搭配","prompt":"The committee is composed _____ representatives from six departments.","choices":["of","to","with","for"],"answer":0,"explanation":"be composed of 表示由……組成。","translation":"委員會由六個部門的代表組成。","passage":"","audioText":"","tags":["reading","grammar"]},{"id":"P5-108","part":"5","difficulty":"600","category":"固定搭配","prompt":"Employees should be mindful _____ confidential information when working remotely.","choices":["of","at","from","into"],"answer":0,"explanation":"be mindful of 是固定搭配。","translation":"員工遠端工作時應留意機密資訊。","passage":"","audioText":"","tags":["reading","grammar"]},{"id":"P5-109","part":"5","difficulty":"400","category":"詞性","prompt":"The company announced the _____ opening of its new distribution center.","choices":["official","officially","office","officials"],"answer":0,"explanation":"修飾 opening 用形容詞 official。","translation":"公司宣布新配送中心正式啟用。","passage":"","audioText":"","tags":["reading","grammar"]},{"id":"P5-110","part":"5","difficulty":"600","category":"詞性","prompt":"The survey results were presented in a clear and _____ manner.","choices":["organize","organized","organization","organizing"],"answer":1,"explanation":"修飾 manner 使用形容詞 organized。","translation":"調查結果以清楚有條理的方式呈現。","passage":"","audioText":"","tags":["reading","grammar"]},{"id":"P5-111","part":"5","difficulty":"600","category":"時態","prompt":"The manager will call you as soon as she _____ from the meeting.","choices":["returns","will return","returned","returning"],"answer":0,"explanation":"時間副詞子句表示未來時，用現在簡單式。","translation":"經理一結束會議回來就會打給你。","passage":"","audioText":"","tags":["reading","grammar"]},{"id":"P5-112","part":"5","difficulty":"800","category":"時態","prompt":"By next January, Mr. Singh _____ at the company for ten years.","choices":["works","worked","will have worked","has worked"],"answer":2,"explanation":"by + 未來時間點搭配未來完成式。","translation":"到明年一月，Singh 先生將在公司任職滿十年。","passage":"","audioText":"","tags":["reading","grammar"]},{"id":"P5-113","part":"5","difficulty":"600","category":"關係子句","prompt":"The warehouse has a loading area _____ trucks can park safely.","choices":["where","which","who","when"],"answer":0,"explanation":"先行詞 loading area 為地點，用 where。","translation":"倉庫設有卡車可安全停放的裝卸區。","passage":"","audioText":"","tags":["reading","grammar"]},{"id":"P5-114","part":"5","difficulty":"800","category":"關係子句","prompt":"The proposal, the details of _____ remain confidential, will be discussed tomorrow.","choices":["which","that","whom","what"],"answer":0,"explanation":"the details of which 是正式所有關係。","translation":"該提案細節仍屬機密，將於明天討論。","passage":"","audioText":"","tags":["reading","grammar"]},{"id":"P5-115","part":"5","difficulty":"600","category":"分詞","prompt":"Products _____ online can be returned to any branch location.","choices":["purchase","purchased","purchasing","to purchase"],"answer":1,"explanation":"產品是被購買，用過去分詞 purchased。","translation":"網路購買的產品可退至任何分店。","passage":"","audioText":"","tags":["reading","grammar"]},{"id":"P5-116","part":"5","difficulty":"800","category":"分詞構句","prompt":"_____ the updated figures, the analyst revised the forecast.","choices":["Review","Reviewed","Having reviewed","To reviewing"],"answer":2,"explanation":"先檢視數據，再修正預測。","translation":"檢視更新後的數據後，分析師修正預測。","passage":"","audioText":"","tags":["reading","grammar"]},{"id":"P5-117","part":"5","difficulty":"400","category":"連接詞","prompt":"Please keep the receipt _____ you need to request a refund.","choices":["in case","although","despite","whereas"],"answer":0,"explanation":"in case + 子句表示以防。","translation":"請保留收據，以防需要申請退款。","passage":"","audioText":"","tags":["reading","grammar"]},{"id":"P5-118","part":"5","difficulty":"600","category":"連接詞","prompt":"The store extended its hours _____ accommodate holiday shoppers.","choices":["in order to","because","despite","whereas"],"answer":0,"explanation":"in order to + V 表示目的。","translation":"商店延長營業時間以服務假期購物者。","passage":"","audioText":"","tags":["reading","grammar"]},{"id":"P5-119","part":"5","difficulty":"400","category":"代名詞","prompt":"Neither of the two conference rooms has _____ own projector.","choices":["its","their","it","theirs"],"answer":0,"explanation":"Neither 視為單數，使用 its。","translation":"兩間會議室都沒有自己的投影機。","passage":"","audioText":"","tags":["reading","grammar"]},{"id":"P5-120","part":"5","difficulty":"600","category":"代名詞","prompt":"Some employees prefer morning sessions, while _____ choose afternoon sessions.","choices":["others","another","the other","other"],"answer":0,"explanation":"some...others... 表示一些……另一些……。","translation":"有些員工偏好上午課程，另一些選擇下午。","passage":"","audioText":"","tags":["reading","grammar"]},{"id":"P5-121","part":"5","difficulty":"600","category":"比較級","prompt":"The updated application runs _____ than the previous version.","choices":["smooth","more smoothly","smoothest","smoothing"],"answer":1,"explanation":"修飾 runs 並作比較，用 more smoothly。","translation":"更新後的應用程式比前一版運作更順暢。","passage":"","audioText":"","tags":["reading","grammar"]},{"id":"P5-122","part":"5","difficulty":"800","category":"倒裝","prompt":"Rarely _____ such a large number of applicants for one position.","choices":["we receive","do we receive","we received","have received we"],"answer":1,"explanation":"Rarely 置句首時助動詞倒裝。","translation":"我們很少收到這麼多人申請同一職缺。","passage":"","audioText":"","tags":["reading","grammar"]},{"id":"P5-123","part":"5","difficulty":"600","category":"商務字彙","prompt":"The company hired an outside firm to _____ the security audit.","choices":["conduct","construct","contact","contain"],"answer":0,"explanation":"conduct an audit 表示執行稽核。","translation":"公司聘請外部公司執行安全稽核。","passage":"","audioText":"","tags":["reading","grammar"]},{"id":"P5-124","part":"5","difficulty":"800","category":"商務字彙","prompt":"The manufacturer agreed to _____ the cost of shipping the replacement unit.","choices":["absorb","observe","reserve","preserve"],"answer":0,"explanation":"absorb the cost 表示承擔費用。","translation":"製造商同意承擔替換設備的運費。","passage":"","audioText":"","tags":["reading","grammar"]},{"id":"P6-037","part":"6","difficulty":"600","category":"活動通知","prompt":"The annual staff picnic will be held at Lakeview Park on Saturday, June 21. Employees may bring immediate family members at no additional _____.","choices":["charge","charged","charging","charges"],"answer":0,"explanation":"at no additional charge 是固定搭配。","translation":"","passage":"The annual staff picnic will be held at Lakeview Park on Saturday, June 21. Employees may bring immediate family members at no additional _____. Lunch and beverages will be provided, _____ participants are encouraged to bring sunscreen. Anyone planning to attend should complete the online form _____ June 13. In the event of heavy rain, the picnic will be _____ to the following Saturday.","audioText":"","groupId":"P6-G10","tags":["text-completion"]},{"id":"P6-038","part":"6","difficulty":"600","category":"活動通知","prompt":"Lunch and beverages will be provided, _____ participants are encouraged to bring sunscreen.","choices":["but","because of","unless","therefore"],"answer":0,"explanation":"前後為轉折，用 but。","translation":"","passage":"The annual staff picnic will be held at Lakeview Park on Saturday, June 21. Employees may bring immediate family members at no additional _____. Lunch and beverages will be provided, _____ participants are encouraged to bring sunscreen. Anyone planning to attend should complete the online form _____ June 13. In the event of heavy rain, the picnic will be _____ to the following Saturday.","audioText":"","groupId":"P6-G10","tags":["text-completion"]},{"id":"P6-039","part":"6","difficulty":"600","category":"活動通知","prompt":"Anyone planning to attend should complete the online form _____ June 13.","choices":["by","among","through","during"],"answer":0,"explanation":"截止日期使用 by。","translation":"","passage":"The annual staff picnic will be held at Lakeview Park on Saturday, June 21. Employees may bring immediate family members at no additional _____. Lunch and beverages will be provided, _____ participants are encouraged to bring sunscreen. Anyone planning to attend should complete the online form _____ June 13. In the event of heavy rain, the picnic will be _____ to the following Saturday.","audioText":"","groupId":"P6-G10","tags":["text-completion"]},{"id":"P6-040","part":"6","difficulty":"600","category":"活動通知","prompt":"In the event of heavy rain, the picnic will be _____ to the following Saturday.","choices":["postponed","postpone","postponing","postponement"],"answer":0,"explanation":"活動被延期，用被動 be postponed。","translation":"","passage":"The annual staff picnic will be held at Lakeview Park on Saturday, June 21. Employees may bring immediate family members at no additional _____. Lunch and beverages will be provided, _____ participants are encouraged to bring sunscreen. Anyone planning to attend should complete the online form _____ June 13. In the event of heavy rain, the picnic will be _____ to the following Saturday.","audioText":"","groupId":"P6-G10","tags":["text-completion"]},{"id":"P6-041","part":"6","difficulty":"800","category":"系統通知","prompt":"The customer portal has been redesigned to make account information easier to _____.","choices":["locate","located","locating","location"],"answer":0,"explanation":"make + O + adj + to V。","translation":"","passage":"The customer portal has been redesigned to make account information easier to _____. Users can now download invoices, update contact details, and _____ service appointments online. Customers who experience difficulty signing in should first _____ their browser cache. If the problem continues, technical support can be reached _____ phone or e-mail.","audioText":"","groupId":"P6-G11","tags":["text-completion"]},{"id":"P6-042","part":"6","difficulty":"800","category":"系統通知","prompt":"Users can now download invoices, update contact details, and _____ service appointments online.","choices":["schedule","scheduled","scheduling","scheduler"],"answer":0,"explanation":"與 download、update 平行，用原形。","translation":"","passage":"The customer portal has been redesigned to make account information easier to _____. Users can now download invoices, update contact details, and _____ service appointments online. Customers who experience difficulty signing in should first _____ their browser cache. If the problem continues, technical support can be reached _____ phone or e-mail.","audioText":"","groupId":"P6-G11","tags":["text-completion"]},{"id":"P6-043","part":"6","difficulty":"800","category":"系統通知","prompt":"Customers who experience difficulty signing in should first _____ their browser cache.","choices":["clear","cleared","clearing","clarity"],"answer":0,"explanation":"should 後接原形 clear。","translation":"","passage":"The customer portal has been redesigned to make account information easier to _____. Users can now download invoices, update contact details, and _____ service appointments online. Customers who experience difficulty signing in should first _____ their browser cache. If the problem continues, technical support can be reached _____ phone or e-mail.","audioText":"","groupId":"P6-G11","tags":["text-completion"]},{"id":"P6-044","part":"6","difficulty":"800","category":"系統通知","prompt":"If the problem continues, technical support can be reached _____ phone or e-mail.","choices":["by","on","from","between"],"answer":0,"explanation":"by phone / by e-mail。","translation":"","passage":"The customer portal has been redesigned to make account information easier to _____. Users can now download invoices, update contact details, and _____ service appointments online. Customers who experience difficulty signing in should first _____ their browser cache. If the problem continues, technical support can be reached _____ phone or e-mail.","audioText":"","groupId":"P6-G11","tags":["text-completion"]},{"id":"P7-R28-Q1","part":"7","difficulty":"600","category":"電子郵件","prompt":"What will happen on Wednesday morning?","choices":["A printer will be replaced","A copy center will close","A meeting room will be painted","A portal will be redesigned"],"answer":0,"explanation":"會更換彩色印表機。","translation":"","passage":"From: Daniel Reed\nTo: Office Staff\nSubject: Printer Replacement\n\nThe color printer beside Meeting Room A will be replaced on Wednesday morning. Please send any urgent color print jobs to the second-floor copy center before Tuesday at 5 P.M. The new printer should be ready for use by Wednesday afternoon. Instructions for connecting to it will be posted on the employee portal.","audioText":"","groupId":"P7-R28","tags":["reading"]},{"id":"P7-R28-Q2","part":"7","difficulty":"600","category":"電子郵件","prompt":"Where should urgent jobs be sent?","choices":["To the second-floor copy center","To Meeting Room A","To an outside printing company","To the employee portal"],"answer":0,"explanation":"緊急彩色列印要送二樓影印中心。","translation":"","passage":"From: Daniel Reed\nTo: Office Staff\nSubject: Printer Replacement\n\nThe color printer beside Meeting Room A will be replaced on Wednesday morning. Please send any urgent color print jobs to the second-floor copy center before Tuesday at 5 P.M. The new printer should be ready for use by Wednesday afternoon. Instructions for connecting to it will be posted on the employee portal.","audioText":"","groupId":"P7-R28","tags":["reading"]},{"id":"P7-R29-Q1","part":"7","difficulty":"600","category":"廣告","prompt":"What is included in the fee?","choices":["Ingredients and equipment","Transportation to the studio","A restaurant meal","Closed-toe shoes"],"answer":0,"explanation":"費用包含材料與設備。","translation":"","passage":"Seaside Cooking Studio\n\nWeekend Pasta Workshop\nSaturday, 2–5 P.M.\n\nLearn to prepare fresh pasta dough, three sauces, and a seasonal salad. All ingredients and equipment are included in the $75 fee. Participants should wear closed-toe shoes and arrive fifteen minutes early. Register with a friend and each person receives a $10 discount.","audioText":"","groupId":"P7-R29","tags":["reading"]},{"id":"P7-R29-Q2","part":"7","difficulty":"600","category":"廣告","prompt":"How can participants receive a discount?","choices":["Register with a friend","Arrive after two o'clock","Bring their own equipment","Attend on Sunday"],"answer":0,"explanation":"和朋友一起報名可折十美元。","translation":"","passage":"Seaside Cooking Studio\n\nWeekend Pasta Workshop\nSaturday, 2–5 P.M.\n\nLearn to prepare fresh pasta dough, three sauces, and a seasonal salad. All ingredients and equipment are included in the $75 fee. Participants should wear closed-toe shoes and arrive fifteen minutes early. Register with a friend and each person receives a $10 discount.","audioText":"","groupId":"P7-R29","tags":["reading"]},{"id":"P7-R30-Q1","part":"7","difficulty":"800","category":"公司新聞","prompt":"What type of products is the warehouse designed for?","choices":["Products requiring stable temperatures","Large construction equipment","Printed office supplies","Used automobiles"],"answer":0,"explanation":"供食品與醫療產品等需穩定溫度者使用。","translation":"","passage":"Westbridge Logistics has opened a temperature-controlled warehouse near the Port of Kaohsiung. The facility is designed for food and medical products that require stable storage conditions. It includes real-time monitoring systems and backup power generators. According to the company, the warehouse will reduce delivery time for customers in southern Taiwan.","audioText":"","groupId":"P7-R30","tags":["reading"]},{"id":"P7-R30-Q2","part":"7","difficulty":"800","category":"公司新聞","prompt":"What benefit does the company expect?","choices":["Shorter delivery times","Lower employee salaries","Fewer monitoring systems","Longer port inspections"],"answer":0,"explanation":"預期縮短南部客戶配送時間。","translation":"","passage":"Westbridge Logistics has opened a temperature-controlled warehouse near the Port of Kaohsiung. The facility is designed for food and medical products that require stable storage conditions. It includes real-time monitoring systems and backup power generators. According to the company, the warehouse will reduce delivery time for customers in southern Taiwan.","audioText":"","groupId":"P7-R30","tags":["reading"]},{"id":"P7-R31-Q1","part":"7","difficulty":"600","category":"備忘錄","prompt":"What is new about the form?","choices":["It has a section for follow-up actions","It can be used only on Friday","It no longer records service complaints","It must be mailed to customers"],"answer":0,"explanation":"新增後續行動紀錄欄位。","translation":"","passage":"To: All Branch Managers\nFrom: Customer Relations\nSubject: Updated Complaint Form\n\nAn updated customer complaint form is now available on the company intranet. Beginning Monday, please use the new form for all service-related complaints. The form includes an additional section for recording follow-up actions. Existing paper copies should be recycled by the end of this week.","audioText":"","groupId":"P7-R31","tags":["reading"]},{"id":"P7-R31-Q2","part":"7","difficulty":"600","category":"備忘錄","prompt":"What should happen to old paper copies?","choices":["They should be recycled","They should be sent to customers","They should be stored for one year","They should be signed by managers"],"answer":0,"explanation":"舊紙本本週底前回收。","translation":"","passage":"To: All Branch Managers\nFrom: Customer Relations\nSubject: Updated Complaint Form\n\nAn updated customer complaint form is now available on the company intranet. Beginning Monday, please use the new form for all service-related complaints. The form includes an additional section for recording follow-up actions. Existing paper copies should be recycled by the end of this week.","audioText":"","groupId":"P7-R31","tags":["reading"]},{"id":"P7-R32-Q1","part":"7","difficulty":"800","category":"活動網頁","prompt":"Which topic will be covered on July 15?","choices":["Video interview preparation","Résumé writing","Job offer negotiation","Workplace safety"],"answer":0,"explanation":"七月十五日是視訊面試準備。","translation":"","passage":"Career Skills Webinar Series\n\nJuly 8 — Writing Effective Résumés\nJuly 15 — Preparing for Video Interviews\nJuly 22 — Negotiating a Job Offer\n\nEach live webinar begins at 7 P.M. and lasts approximately seventy-five minutes. Registration is free, but participants must sign up separately for each session. Recordings will be available to registered participants for seven days after each webinar.","audioText":"","groupId":"P7-R32","tags":["reading"]},{"id":"P7-R32-Q2","part":"7","difficulty":"800","category":"活動網頁","prompt":"Who can view a recording?","choices":["Registered participants","Anyone visiting the website","Only the webinar presenter","Employees of one company"],"answer":0,"explanation":"只有已報名參加者可看錄影。","translation":"","passage":"Career Skills Webinar Series\n\nJuly 8 — Writing Effective Résumés\nJuly 15 — Preparing for Video Interviews\nJuly 22 — Negotiating a Job Offer\n\nEach live webinar begins at 7 P.M. and lasts approximately seventy-five minutes. Registration is free, but participants must sign up separately for each session. Recordings will be available to registered participants for seven days after each webinar.","audioText":"","groupId":"P7-R32","tags":["reading"]},{"id":"P7-R33-Q1","part":"7","difficulty":"600","category":"訂位確認","prompt":"How long will the table be held?","choices":["Fifteen minutes","Until noon","Six hours","All evening"],"answer":0,"explanation":"保留十五分鐘。","translation":"","passage":"Reservation Confirmation\n\nRestaurant: Maple & Stone\nDate: Friday, October 10\nTime: 7:30 P.M.\nParty size: 6\nReservation name: C. Wang\n\nYour table will be held for fifteen minutes after the reservation time. To change the number of guests, please call no later than noon on the day of the reservation. A private parking lot is available behind the restaurant.","audioText":"","groupId":"P7-R33","tags":["reading"]},{"id":"P7-R33-Q2","part":"7","difficulty":"600","category":"訂位確認","prompt":"By when should a guest-count change be requested?","choices":["By noon that day","After 7:30 P.M.","Fifteen minutes after arrival","The previous week"],"answer":0,"explanation":"當天中午前致電。","translation":"","passage":"Reservation Confirmation\n\nRestaurant: Maple & Stone\nDate: Friday, October 10\nTime: 7:30 P.M.\nParty size: 6\nReservation name: C. Wang\n\nYour table will be held for fifteen minutes after the reservation time. To change the number of guests, please call no later than noon on the day of the reservation. A private parking lot is available behind the restaurant.","audioText":"","groupId":"P7-R33","tags":["reading"]},{"id":"P7-R34-Q1","part":"7","difficulty":"800","category":"雙篇閱讀","prompt":"Why will the Eastside pool close?","choices":["For tile repairs","For a swimming competition","For employee training","For water testing only"],"answer":0,"explanation":"因磁磚維修。","translation":"","passage":"NOTICE\nThe Eastside Fitness Center swimming pool will close from August 4 through August 8 for tile repairs. Members may use the pool at the Northside branch during this period by showing their membership card.\n\nE-MAIL\nFrom: Nora\nTo: Fitness Group\nSince the Eastside pool is closed next week, let's meet at the Northside branch on Wednesday. The evening lap-swim session starts at 6:30. I'll arrive early and reserve lockers for us.","audioText":"","groupId":"P7-R34","tags":["reading"]},{"id":"P7-R34-Q2","part":"7","difficulty":"800","category":"雙篇閱讀","prompt":"What will Nora do?","choices":["Reserve lockers","Repair the pool","Issue membership cards","Cancel the swim session"],"answer":0,"explanation":"Nora 會提早到並保留置物櫃。","translation":"","passage":"NOTICE\nThe Eastside Fitness Center swimming pool will close from August 4 through August 8 for tile repairs. Members may use the pool at the Northside branch during this period by showing their membership card.\n\nE-MAIL\nFrom: Nora\nTo: Fitness Group\nSince the Eastside pool is closed next week, let's meet at the Northside branch on Wednesday. The evening lap-swim session starts at 6:30. I'll arrive early and reserve lockers for us.","audioText":"","groupId":"P7-R34","tags":["reading"]}];
